var ayetHadisData = {"ayetler": [{"kisim": 1, "madde": 1, "metin": "lahü teâlâ Onu, dünyâdaki bütün insanları se’âdete da’vet için gönderdi ve Sebe’ sûresi, yirmisekizinci âyetinde meâlen, (Ey sevgili Peygamberim “sallallahü aleyhi ve sellem”! Seni, dünyâdaki bütün insanlara ebedî se’âdeti müjdelemek ve bu se’âdet yolunu göstermek için, beşeriyyete gönderiyorum)", "arama": "Ey sevgili Peygamberim “sallallahü aleyhi ve sellem”! Seni, "}, {"kisim": 1, "madde": 2, "metin": "Bunun pek kat’î ve kuvvetli olduğunu bildirmek için, âyet-i kerîmede (Elbette muhakkak böyledir)", "arama": "Elbette muhakkak böyledir"}, {"kisim": 1, "madde": 2, "metin": "Allahü teâlâ, yine Nisâ sûresinin yüzellinci ve yüzellibirinci âyet-i kerîmelerinde meâlen, (Kâfirler, Allahü teâlânın emrleri ile Peygamberlerinin emrlerini birbirinden ayırmak istiyorlar. Yehûdîler diyor ki, biz Mûsâ aleyhisselâma inanırız. Îsâ ile Muhammed aleyhimesselâma inanmayız. Hıristiyanlar ise, yalnız Îsâ aleyhisselâma inanıp, Ona, hâşâ, Allahü teâlânın oğlu diyor. Bu inanışları ve dinleri kıymetsizdir. Onların hepsi kâfirdir. Kâfirleri", "arama": "Kâfirler, Allahü teâlânın emrleri ile Peygamberlerinin emrle"}, {"kisim": 1, "madde": 8, "metin": "Dinlerini dünyâya satanlar hakkında, Bekara sûresinde meâli, (Câhiller, ahmaklar, dünyâdaki zevk ve lezzetlere kavuşmak için, dinlerini, îmânlarını verdi. Âhıretlerini satıp, dünyâyı, şehvetlerinin istediklerini aldılar. Kurtuluş yolunu bırakıp, helâke koşdular. Bu alış-verişlerinde birşey kazanmadılar. Bunlar, ticâret ve kazanç yolunu bilmedi. Çok ziyân etdi)", "arama": "Câhiller, ahmaklar, dünyâdaki zevk ve lezzetlere kavuşmak iç"}, {"kisim": 1, "madde": 11, "metin": "esinde kâfirlere kıymet verenlerin ve küfre tâbi’ olanların aldandıklarını ve pişmân olacaklarını beyân buyurarak meâli, (Ey benim sevgili Peygamberime “sallallahü aleyhi ve sellem” inananlar! Eğer, kâfirlerin sözlerine aldanıp da, Resûlümün “sallallahü aleyhi ve sellem” yolundan ayrılırsanız, kendilerine müslimân süsü veren din düşmanlarının, ya’nî zındıkların uydurma ve yaldızlı sözlerine kapılarak, îmânınızı çaldırırsanız, dünyâda ve âhıretde ", "arama": "Ey benim sevgili Peygamberime “sallallahü aleyhi ve sellem” "}, {"kisim": 1, "madde": 11, "metin": "Ra’d sûresinin ondördüncü ve Mü’min sûresinin ellinci âyetlerinde meâlen, (Bu düşmanların düâları netîcesizdir. Kabûl olmak ihtimâli yokdur)", "arama": "Bu düşmanların düâları netîcesizdir. Kabûl olmak ihtimâli yo"}, {"kisim": 1, "madde": 12, "metin": "Nahl sûresinin otuzüçüncü âyetinde meâlen, (Allahü teâlâ, kullarına zulm etmez, haksızlık etmez. Onlar, kendilerini azâba, acılara sürükleyen bozuk düşünceleri, çirkin işleri ile kendilerine zulm ve işkence ediyorlar)", "arama": "Allahü teâlâ, kullarına zulm etmez, haksızlık etmez. Onlar, "}, {"kisim": 1, "madde": 13, "metin": "Nitekim, Mü’minûn sûresi, ellialtıncı âyetinde meâlen, (Kâfirler, mal ve çok evlâd gibi dünyâlıkları verdiğimiz için, kendilerine iyilik mi ediyoruz, yardım mı ediyoruz sanıyor. Peygamberime “sallallahü aleyhi ve sellem” inanmadıkları ve dîn-i islâmı beğenmedikleri için, onlara mükâfât mı ediyoruz, diyorlar? Hayır öyle değildir. Aldanıyorlar. Bunların ni’met olmayıp, musîbet olduğunu anlamıyorlar)", "arama": "Kâfirler, mal ve çok evlâd gibi dünyâlıkları verdiğimiz için"}, {"kisim": 1, "madde": 18, "metin": "Tahrîm sûresinde altıncı âyet-i kerîmenin meâl-i şerîfi, (Kendinizi ve evlerinizde ve emrlerinizde olanları ateşden koruyunuz!)", "arama": "Kendinizi ve evlerinizde ve emrlerinizde olanları ateşden ko"}, {"kisim": 1, "madde": 19, "metin": "Cenâb-ı Hakkın Îsâ aleyhisselâma emr-i ilâhîsinin meâl-i şerîfi, (Eğer yerlerde ve göklerde bulunan bütün mahlûkların ibâdetlerini yapsan, dostlarımı sevmedikce ve düşmanlarıma düşmanlık etmedikce, hiç fâidesi olmaz)", "arama": "Eğer yerlerde ve göklerde bulunan bütün mahlûkların ibâdetle"}, {"kisim": 1, "madde": 19, "metin": "Mücâdele sûresinin son âyetinde meâlen, (Allahü teâlâya ve kıyâmet gününe îmân edenler, Allahü teâlânın ve resûlünün düşmanlarını sevmezler. O kâfirler ve münâfıklar, mü’minlerin anaları, babaları, oğulları, kardeşleri ve başka yakınları olsa da, bunları sevmezler. Böyle olan mü’minleri Cennete koyacağım)", "arama": "Allahü teâlâya ve kıyâmet gününe îmân edenler, Allahü teâlân"}, {"kisim": 1, "madde": 20, "metin": "Enfâl sûresi, altmışıncı âyetinde meâlen, (Kâfirlerin hücûm ve işkencelerine uğramamak, onları da, se’âdet-i ebediyyeye kavuşdurmak için, insan gücünün yetdiği kadar durmadan çalışınız. En mükemmel harb vâsıtalarını yapınız!)", "arama": "Kâfirlerin hücûm ve işkencelerine uğramamak, onları da, se’â"}, {"kisim": 1, "madde": 21, "metin": "Böyle olmakla berâber, Tevbe sûresi, onsekizinci âyetinde meâlen, (Kâfirlerin câmi’ yapmaları câiz değildir. Yerinde ve yarar bir iş değildir. Onların câmi’ yapmaları ve diğer bütün beğendikleri işleri, kıyâmetde kendilerine yaramıyacak ve Muhammed aleyhisselâma tâbi’ olmadıkları için, Cehenneme girip, çok acı azâblarda sonsuz olarak cezâlandırılacaklardır)", "arama": "Kâfirlerin câmi’ yapmaları câiz değildir. Yerinde ve yarar b"}, {"kisim": 1, "madde": 21, "metin": "Âl-i İmrân sûresi, seksenbeşinci âyetinde meâlen, (Muhammed aleyhisselâmın getirdiği İslâm dîninden başka din istiyenlerin, dinlerini Allahü teâlâ sevmez ve kabûl etmez. Dîn-i islâma arka çeviren, âhıretde ziyân edecek, Cehenneme girecekdir)", "arama": "Muhammed aleyhisselâmın getirdiği İslâm dîninden başka din i"}, {"kisim": 1, "madde": 21, "metin": "Nisâ sûresi, onüçüncü âyet-i kerîmesinde meâlen, (Allahü teâlânın ve Peygamberi Muhammed aleyhisselâmın emrlerine aldırış etmiyenler, beğenmiyenler, asra, fenne uygun değildir, modern ihtiyâclara kâfi değildir diyenler, kıyâmetde Cehennem ateşinden kurtulamıyacaklardır. Bunlara, Cehennemde, çok acı azâb vardır)", "arama": "Allahü teâlânın ve Peygamberi Muhammed aleyhisselâmın emrler"}, {"kisim": 1, "madde": 21, "metin": "[Nitekim, Nisâ sûresi yüzyetmişikinci âyet-i kerîmesinde meâlen, (Muhammed aleyhisselâma inanıp, âhırete yarayan işleri yapanlara [ya’nî ahkâm-ı islâmiyyeye uyanlara], Allahü teâlâ, va’d etdiklerini verecek ve ayrıca çok ihsân yapacakdır. Allahü teâlâya ibâdet etmeği, ya’nî Muhammed aleyhisselâma itâ’at etmeği, aşağılık, gericilik sanıp, kendilerine asrî ve münevver diyerek, büyüklük taslıyanlara, çok azâb edecekdir. Kendilerini herkesin üstünde ", "arama": "Muhammed aleyhisselâma inanıp, âhırete yarayan işleri yapanl"}, {"kisim": 1, "madde": 25, "metin": "Sıra, âyet-i kerîmeye gelince, şaşkın bir hâlde (Burası hiçbir söze benzemiyor. Ma’nâ içinde, ma’nâ çıkıyor. Hepsini anlamağa imkân yok)", "arama": "Burası hiçbir söze benzemiyor. Ma’nâ içinde, ma’nâ çıkıyor. "}, {"kisim": 1, "madde": 31, "metin": "Birçok âyet-i kerîmede (Beni çok zikr edin) ve (İzâ câe) sûresinde (Bana istigfâr edin. Düâlarınızı kabûl ederim, günâhlarınızı afv ederim)", "arama": "Bana istigfâr edin. Düâlarınızı kabûl ederim, günâhlarınızı "}, {"kisim": 1, "madde": 31, "metin": "Yatarken, sağ tarafa yatıp, bir E’ûzü ve Besmele, bir Âyet-el-kürsî, üç İhlâs, bir Fâtiha, bir Kul-e’ûzüler, bir (tevekkeltü alellah lâ havle velâ kuvvete illâ billah)", "arama": "tevekkeltü alellah lâ havle velâ kuvvete illâ billah"}, {"kisim": 1, "madde": 35, "metin": "Bu tefsîrde, Tevbe sûresi, yirmidokuzuncu âyetini tefsîr ederken (Müşriklerin içleri, inanışları pis olduğu için, onlar elbette pisdir)", "arama": "Müşriklerin içleri, inanışları pis olduğu için, onlar elbett"}, {"kisim": 1, "madde": 35, "metin": "ü teâlâ, size kolay olan şeyleri yapdırmak istiyor, güç olanı istemiyor) ve Nisâ sûresi, yirmisekizinci âyetinde meâlen, (Allahü teâlâ, ibâdetlerinizin hafîf, kolay olmasını istiyor. İnsan za’îf, dayanıksız yaratıldı)", "arama": "Allahü teâlâ, ibâdetlerinizin hafîf, kolay olmasını istiyor."}, {"kisim": 1, "madde": 35, "metin": "Birgün, bunları anlatırken, meâl-i şerîfi, (Ehl-i kitâbın, ya’nî yehûdî ve nasârânın pişirdiklerini, kesdiklerini yimeniz halâldir)", "arama": "Ehl-i kitâbın, ya’nî yehûdî ve nasârânın pişirdiklerini, kes"}, {"kisim": 1, "madde": 37, "metin": "adakilere emr-i ma’rûf ve nehy-i münker yaparak, doğru yolu gösteriniz! Müzzemmil sûresinin ondokuzuncu âyetinde meâlen, (Rabbinin rızâsına kavuşmak istiyen için, bu elbette bir nasîhatdir)", "arama": "Rabbinin rızâsına kavuşmak istiyen için, bu elbette bir nasî"}, {"kisim": 1, "madde": 39, "metin": "Bir âyet-i kerîmenin meâl-i şerîfi, (Herşeyi nasıl yaratdığımı arayın, işlerimdeki intizâmı, incelikleri görün! Böylece varlığıma, kudretimin, bilgimin sonsuzluğuna inanın!)", "arama": "Herşeyi nasıl yaratdığımı arayın, işlerimdeki intizâmı, ince"}, {"kisim": 1, "madde": 39, "metin": "ci âyetinde meâlen, (Rabbiniz Erdı sizin için, yatak gibi döşedi)", "arama": "Rabbiniz Erdı sizin için, yatak gibi döşedi"}, {"kisim": 1, "madde": 39, "metin": "Nahl sûresinin onbeşinci âyetinde meâlen, (Erdın sizi sarsmaması için, üzerinde dağlar döşedim)", "arama": "Erdın sizi sarsmaması için, üzerinde dağlar döşedim"}, {"kisim": 1, "madde": 39, "metin": "cü âyetinde meâlen, (Allah, Erdı size karâr yapdı)", "arama": "Allah, Erdı size karâr yapdı"}, {"kisim": 1, "madde": 39, "metin": "Nahl sûresinde, (Allahü teâlâ için misâller getirmeyin)", "arama": "Allahü teâlâ için misâller getirmeyin"}, {"kisim": 1, "madde": 40, "metin": "Süâl: Zümer sûresinin kırkikinci âyetinin meâli, (Allahü teâlâ, insan ölürken rûhunu bedeninden ayırır. Ölmediği zemân, uykuda da, rûhunu ayırır)", "arama": "Allahü teâlâ, insan ölürken rûhunu bedeninden ayırır. Ölmedi"}, {"kisim": 1, "madde": 41, "metin": "Enfâl sûresinin yirmibeşinci âyet-i kerîmesinde meâlen, (Zulm edenlere ve etmiyenlere birlikde gelen fitne ve belâdan korkunuz, sakınınız)", "arama": "Zulm edenlere ve etmiyenlere birlikde gelen fitne ve belâdan"}, {"kisim": 1, "madde": 41, "metin": "m ve üstâdım, sebeb-i hayâtım ve se’âdetim abdestde, tahâretde ve nemâzda pek ziyâde dikkat ve edeblere riâyet ederdi ve (Bunları, babamdan görerek öğrendim. Herbir edebe, bütün incelikleri ile riâyeti, kitâblardan öğrenmek kolay değildir)", "arama": "Bunları, babamdan görerek öğrendim. Herbir edebe, bütün ince"}, {"kisim": 1, "madde": 41, "metin": "Süâl: Mâide sûresi, yüzsekizinci âyet-i kerîmesinde meâlen; (Ey îmân eden kullarım! Kendinize dikkat ediniz! Doğru yolu bulursanız, başkasının sapıtması size zarar vermez)", "arama": "Ey îmân eden kullarım! Kendinize dikkat ediniz! Doğru yolu b"}, {"kisim": 1, "madde": 41, "metin": "Ya’nî âyet-i kerîmede meâlen; (Ey mü’min kullarım! Emr etdiğim işleri, ibâdetleri yapar ve emr-i ma’rûf ve nehy-i münker eder iseniz, başkalarının yoldan çıkması, size zarar vermez)", "arama": "Ey mü’min kullarım! Emr etdiğim işleri, ibâdetleri yapar ve "}, {"kisim": 1, "madde": 43, "metin": "Nûr sûresi, otuzbirinci âyet-i kerîmesinde meâlen, (Ey mü’minler! Hepiniz, Allahü teâlâya tevbe ediniz! Tevbe etmekle kurtulabilirsiniz)", "arama": "Ey mü’minler! Hepiniz, Allahü teâlâya tevbe ediniz! Tevbe et"}, {"kisim": 1, "madde": 43, "metin": "Yirmisekizinci cüz’ sonundaki, Tahrîm sûresi, sekizinci âyet-i kerîmesinde meâlen, (Ey îmân eden seçilmişler! Allahü teâlâya dönünüz! Hâlis tevbe edin! Ya’nî tevbenizi bozmayın! Böyle tevbe edince, Rabbiniz, sizi belki afv eder ve ağaçlarının, köşklerinin altından [önünden] sular akan Cennetlere sokar)", "arama": "Ey îmân eden seçilmişler! Allahü teâlâya dönünüz! Hâlis tevb"}, {"kisim": 1, "madde": 43, "metin": "En’âm sûresi, yüzyirminci âyet-i kerîmesinde meâlen, (Açık olsun, gizli olsun günâhlardan sakınınız!)", "arama": "Açık olsun, gizli olsun günâhlardan sakınınız!"}, {"kisim": 1, "madde": 46, "metin": "âyetlerinde meâlen buyuruyor ki: (Fir’avn dedi ki: Bizden evvel gelip geçenlerin hâlleri ne oldu?)", "arama": "Fir’avn dedi ki: Bizden evvel gelip geçenlerin hâlleri ne ol"}, {"kisim": 1, "madde": 46, "metin": "Nisâ sûresi, doksandördüncü âyetinde meâlen, (Mallarını, canlarını fedâ ederek din düşmanları ile, Allah rızâsı için cihâd eden müslimânlar, oturup, ibâdet edenlerden dahâ üstündür. Hepsine de, Cenneti söz veriyorum)", "arama": "Mallarını, canlarını fedâ ederek din düşmanları ile, Allah r"}, {"kisim": 1, "madde": 46, "metin": "Allahü teâlâ, Haşr sûresi yedinci âyetinde meâlen, (Resûlümün “sallallahü aleyhi ve sellem” getirdiklerini alınız!)", "arama": "Resûlümün “sallallahü aleyhi ve sellem” getirdiklerini alını"}, {"kisim": 1, "madde": 46, "metin": "Kendimizi âhıretin çeşidli azâblarından kurtaralım! Tahrîm sûresi altıncı âyetinde meâlen, (Ey îmân edenler, kendinizi ve çoluk çocuğunuzu öyle bir ateşden koruyun ki, onun tutuşdurucusu insanlarla taşlardır)", "arama": "Ey îmân edenler, kendinizi ve çoluk çocuğunuzu öyle bir ateş"}, {"kisim": 1, "madde": 46, "metin": "Bir âyet-i kerîmede meâlen, (Her nemâzı kılarken süslü, temiz, sevilen elbiselerinizi giyiniz!)", "arama": "Her nemâzı kılarken süslü, temiz, sevilen elbiselerinizi giy"}, {"kisim": 1, "madde": 48, "metin": "(Ha-mîm Secde) sûresinin dokuzuncu âyetinde meâlen, (Yeri iki günde yaratdı) ve onikinci âyetinde meâlen, (Sonra, yedi gökü de iki günde var eyledi)", "arama": "Sonra, yedi gökü de iki günde var eyledi"}, {"kisim": 1, "madde": 49, "metin": "(El-hâkka) sûresinde, bir âyet-i kerîmede meâlen, (Sûra bir kerre üfürülünce, yeryüzü ve dağlar, yerlerinden kaldırılıp silkilecekdir. O gün kıyâmet kopacak, gök yarılacak ve dağılacakdır)", "arama": "Sûra bir kerre üfürülünce, yeryüzü ve dağlar, yerlerinden ka"}, {"kisim": 1, "madde": 49, "metin": "ve (Tekvîr) sûresinde, bir âyet-i kerîmede meâlen, (Güneşin karardığı, yıldızların yerlerinden ayrılıp döküldükleri ve dağların dağılıp saçıldıkları zemâna...)", "arama": "Güneşin karardığı, yıldızların yerlerinden ayrılıp döküldükl"}, {"kisim": 1, "madde": 49, "metin": "ve (İnfitâr) sûresinde, bir âyet-i kerîmede meâlen, (Gökün yarıldığı ve yıldızların dağılıp yok oldukları zemân...)", "arama": "Gökün yarıldığı ve yıldızların dağılıp yok oldukları zemân.."}, {"kisim": 1, "madde": 49, "metin": "ve (Kasas) sûresinin son âyetinde meâlen, (Herşey yok olacakdır. Yalnız O kalacakdır!)", "arama": "Herşey yok olacakdır. Yalnız O kalacakdır!"}, {"kisim": 1, "madde": 49, "metin": "Böyle ahmaklara, ancak Kehf sûresindeki âyet-i kerîmede bildirildiği gibi, (Ağızlarından çıkan söz, çok kötüdür. Hep yalan söylüyorlar)", "arama": "Ağızlarından çıkan söz, çok kötüdür. Hep yalan söylüyorlar"}, {"kisim": 1, "madde": 50, "metin": "Bir âyet-i kerîmede meâlen, (Ni’metlerime şükr ederseniz, onları artdırırım)", "arama": "Ni’metlerime şükr ederseniz, onları artdırırım"}, {"kisim": 1, "madde": 50, "metin": "(Bir işde anlaşamazsanız, bu işin hükmünü Allahdan ve Resûlullahdan anlayınız!) meâlindeki ellisekizinci âyet-i kerîme, (Bir işde anlaşamazsanız, bu işin nasıl yapılacağını, âlim olanlarınız Allahın kitâbından ve Resûlullahın sünnetinden anlasınlar. Âlim olmıyanlarınız ise, âlimlerin anladıklarına uyarak yapsınlar)", "arama": "Bir işde anlaşamazsanız, bu işin nasıl yapılacağını, âlim ol"}, {"kisim": 1, "madde": 58, "metin": "irgivî vasıyyetnâmesi)ni şerh eden, Kâdî zâde, göz âfetlerini anlatırken diyor ki, Nûr sûresi, otuzuncu âyetinde meâlen, (Ey Resûlüm “sallallahü aleyhi ve sellem”! Mü’minlere söyle, harâma bakmasınlar ve avret yerlerini harâmdan korusunlar! Îmânı olan kadınlara da söyle, harâma bakmasınlar ve avret yerlerini harâm işlemekden korusunlar!)", "arama": "Ey Resûlüm “sallallahü aleyhi ve sellem”! Mü’minlere söyle, "}, {"kisim": 1, "madde": 60, "metin": "mâm-ı gâyetül irtifâ’ = arz-ı belde -meyl olduğundan: tan (Temâm-ı irtifâ’ı asr-ı evvel) = [1 + tan (arz – meyl)] ve tan (Temâm-ı irtifâ’ı asr-ı sânî)", "arama": "Temâm-ı irtifâ’ı asr-ı sânî"}, {"kisim": 1, "madde": 62, "metin": "[(Sâvî) tefsîrinde, (İnşirâh) sûresinde diyor ki, (Allahü teâlâ, senin ismini şarkda, garbda, yer küresinin her yerinde yükseltirim buyurdu)", "arama": "Allahü teâlâ, senin ismini şarkda, garbda, yer küresinin her"}, {"kisim": 1, "madde": 64, "metin": "e otuzüç kerre (Sübhânallah), otuzüç kerre (Elhamdülillah) ve otuzüç kerre (Allahü ekber) ve bir (kelime-i tehlîl) ya’nî (Lâ ilâhe illallah vahdehû lâ şerîke leh...)", "arama": "Lâ ilâhe illallah vahdehû lâ şerîke leh..."}, {"kisim": 1, "madde": 71, "metin": "Cum’a sûresi sonundaki âyet-i kerîmede meâlen; (Ey îmân etmekle şereflenen kullarım! Cum’a günü, öğle ezânı okunduğu zemân, hutbe dinlemek ve Cum’a nemâzı kılmak için câmi’e koşunuz. Alış-verişi bırakınız! Cum’a nemâzı ve hutbe, size, başka işlerinizden dahâ fâidelidir. Cum’a nemâzını kıldıkdan sonra, câmi’den çıkar, dünyâ işlerinizi yapmak için dağılabilirsiniz. Allahü teâlâdan rızk bekliyerek çalışırsınız. Allahü teâlâyı çok hâtırlayınız ki, ku", "arama": "Ey îmân etmekle şereflenen kullarım! Cum’a günü, öğle ezânı "}, {"kisim": 1, "madde": 73, "metin": "Ba’zı rivâyetlerde ise, otururken düâ zemânında, (Ey kalbleri istediği gibi çeviren Allahım, benim kalbimi kendi dînin üzerinde bulundur!)", "arama": "Ey kalbleri istediği gibi çeviren Allahım, benim kalbimi ken"}, {"kisim": 1, "madde": 74, "metin": "Allahü teâlâ buyuracak ki, (Ey kulum, nemâz hesâbının altından kalkarsan, kurtuluş senindir. Öteki hesâbları kolaylaşdırırım!)", "arama": "Ey kulum, nemâz hesâbının altından kalkarsan, kurtuluş senin"}, {"kisim": 1, "madde": 77, "metin": "erkânına riâyet etmediğini, rükü’dan kalkınca, dikilip durmadığını ve iki secde arasında oturmadığını görüp, buyurdu ki, (Eğer nemâzlarını böyle kılarak ölürsen, kıyâmet günü, sana benim ümmetimden demezler)", "arama": "Eğer nemâzlarını böyle kılarak ölürsen, kıyâmet günü, sana b"}, {"kisim": 1, "madde": 78, "metin": "ci maddenin son sahîfesine bakınız!\n\nBekara sûresinin ikiyüzyetmişbeşinci âyetinde meâlen, (Allah, fâiz ile elde edilenleri yok eder. İzlerini bile bırakmaz. Zekâtları verilen malları artdırır)", "arama": "Allah, fâiz ile elde edilenleri yok eder. İzlerini bile bıra"}, {"kisim": 1, "madde": 78, "metin": "Tevbe sûresi, otuzdördüncü âyet-i kerîmesi, böyle kimseler için olup, meâl-i şerîfi, (Malı, parayı birikdirip zekâtını, müslimân fakîrlerine vermeyenlere çok acı azâbı müjdele!)", "arama": "Malı, parayı birikdirip zekâtını, müslimân fakîrlerine verme"}, {"kisim": 1, "madde": 78, "metin": "Bu azâbı, bundan sonraki âyet-i kerîme bildirmekde olup, meâl-i şerîfinde: (Zekâtı verilmiyen mallar, paralar, Cehennem ateşinde kızdırılıp, sâhiblerinin alınlarına, böğürlerine, sırtlarına mühür basar gibi basdırılacakdır)", "arama": "Zekâtı verilmiyen mallar, paralar, Cehennem ateşinde kızdırı"}, {"kisim": 1, "madde": 78, "metin": "Haşr sûresi, dokuzuncu âyet-i kerîmede, (Zekâtını veren, elbette kurtulacakdır)", "arama": "Zekâtını veren, elbette kurtulacakdır"}, {"kisim": 1, "madde": 78, "metin": "Âl-i İmrân sûresinde, yüzsekseninci âyet-i kerîmede meâlen, (Allahü teâlânın ihsân etdiği malın zekâtını vermeyenler, iyi etdiklerini, zengin kalacaklarını sanıyor. Hâlbuki, kendilerine kötülük yapmış oluyorlar. O malları, Cehennemde azâb âleti olacak, yılan şeklinde boyunlarına sarılıp, başdan ayağa kadar onları sokacakdır)", "arama": "Allahü teâlânın ihsân etdiği malın zekâtını vermeyenler, iyi"}, {"kisim": 1, "madde": 79, "metin": "(Rıyâd-un-nâsıhîn)de diyor ki: (Bekara sûresindeki bir âyet-i kerîmede meâlen, (Beyâz iplik siyâhdan ayırd edilinceye kadar yiyiniz, içiniz!)", "arama": "Beyâz iplik siyâhdan ayırd edilinceye kadar yiyiniz, içiniz!"}, {"kisim": 1, "madde": 82, "metin": "Hac sûresi, yirmidokuzuncu âyet-i kerîmesinde meâlen, (Adaklarını yerine getirsinler!)", "arama": "Adaklarını yerine getirsinler!"}, {"kisim": 1, "madde": 83, "metin": "Çünki, Rum sûresinin kırkyedinci âyetinin meâl-i şerîfi, (Üzerimize hak oldu ki, mü’minlere yardım ederiz)", "arama": "Üzerimize hak oldu ki, mü’minlere yardım ederiz"}, {"kisim": 1, "madde": 83, "metin": "En’âm sûresinin onikinci âyetinin meâl-i şerîfi, (Allahü teâlâ kullarına merhamet etmeği kendisine lâzım kıldı)", "arama": "Allahü teâlâ kullarına merhamet etmeği kendisine lâzım kıldı"}, {"kisim": 1, "madde": 84, "metin": "der ve hicret gecesi gelmiş olan (İsrâ) sûresinin sekseninci âyetini ve nemâzda okunan salevât-ı şerîfleri okuyarak ve (Vagfir lî-zünûbî veftah lî ebvâbe rahmetike ve fadlike)", "arama": "Vagfir lî-zünûbî veftah lî ebvâbe rahmetike ve fadlike"}, {"kisim": 1, "madde": 95, "metin": "hü anh” alıp boşamak sûretiyle yüze yakın güzel kız ile evlenmiş ve babası imâm-ı Alî “radıyallahü anh”, bir hutbesinde, (Ey müslimânlar! Oğlum Hasene kız vermeyiniz! O, kızları çabuk boşuyor, bırakıyor)", "arama": "Ey müslimânlar! Oğlum Hasene kız vermeyiniz! O, kızları çabu"}, {"kisim": 1, "madde": 96, "metin": "(Hadâik-ul-hakâyık) kitâbında diyor ki,(Âyet-i kerîmede, (Sen huluk-ı azîm üzeresin)", "arama": "Sen huluk-ı azîm üzeresin"}, {"kisim": 1, "madde": 96, "metin": "Enbiyâ sûresinin yüzyedinci âyetinde meâlen, (Seni, âlemlere rahmet, iyilik için gönderdik)", "arama": "Seni, âlemlere rahmet, iyilik için gönderdik"}, {"kisim": 1, "madde": 97, "metin": "n-ı kerîmden sonra en kıymetli, en doğru kitâb olan (Buhârî-yi şerîf)deki bir hadîs-i şerîfde, Peygamberimiz buyurdu ki: (Her asrda, her zemânda yaşıyan insanların en iyilerinden, seçilmişlerinden dünyâya getirildim)", "arama": "Her asrda, her zemânda yaşıyan insanların en iyilerinden, se"}, {"kisim": 1, "madde": 97, "metin": "6 — Şü’arâ sûresi, ikiyüzondokuzuncu âyetinde meâlen, (Sen, ya’nî Senin nûrun, hep secde edenlerden dolaşdırılıp, sana inkılâb etmiş, ulaşmışdır)", "arama": "Sen, ya’nî Senin nûrun, hep secde edenlerden dolaşdırılıp, s"}, {"kisim": 1, "madde": 97, "metin": "Ehl-i sünnet âlimleri “rahmetullahi teâlâ aleyhim ecma’în”, bu âyet-i kerîmeyi tefsîr ederken, (Bütün ana ve babalarının mü’min ve günâhsız olduğunu)", "arama": "Bütün ana ve babalarının mü’min ve günâhsız olduğunu"}, {"kisim": 1, "madde": 97, "metin": "İşte, bunlar gibi, En’âm sûresinde meâl-i şerîfi, (İbrâhîm “aleyhisselâm” babası Âzere dediği zemân...)", "arama": "İbrâhîm “aleyhisselâm” babası Âzere dediği zemân..."}, {"kisim": 1, "madde": 97, "metin": "Îcâz, belâgat ve fesâhat kâ’idelerine göre, âyet-i kerîmenin ma’nâsı (İbrâhîm“aleyhisselâm”, Âzer olan babasına dediği zemân)", "arama": "İbrâhîm“aleyhisselâm”, Âzer olan babasına dediği zemân"}, {"kisim": 1, "madde": 97, "metin": "Bekara sûresinde, Ya’kûb aleyhisselâma, çocuklarının (Ve senin babaların İbrâhîm ve İsmâ’îl ve İshakın da Rabbi)", "arama": "Ve senin babaların İbrâhîm ve İsmâ’îl ve İshakın da Rabbi"}, {"kisim": 1, "madde": 97, "metin": "Bekara sûresinin yüzondokuzuncu âyeti gelerek, (Cehennem ehlinin hâlinden sorma!)", "arama": "Cehennem ehlinin hâlinden sorma!"}, {"kisim": 1, "madde": 98, "metin": "şdirmek câiz olmayınca, Kur’ân-ı kerîmi değişdirmek hiç câiz olur mu? (Hadîka)da dil âfetlerini anlatırken buyuruyor ki, (Kur’ân-ı kerîmdeki düâları okurken değişdirmek, Kur’ân-ı kerîmi kasden değişdirmek olur)", "arama": "Kur’ân-ı kerîmdeki düâları okurken değişdirmek, Kur’ân-ı ker"}, {"kisim": 1, "madde": 98, "metin": "[Mâide sûresinin yirmiyedinci âyetinde meâlen, (Allahü teâlâ, ancak takvâ sâhiblerinin [ibâdetlerini, düâlarını] kabûl eder)", "arama": "Allahü teâlâ, ancak takvâ sâhiblerinin [ibâdetlerini, düâlar"}, {"kisim": 2, "madde": 2, "metin": "Âl-i İmrân sûresinin yüzyirmialtıncı âyetinde ve Enfâl sûresinde meâlen, (Yardım, ancak ve yalnız Allahdandır)", "arama": "Yardım, ancak ve yalnız Allahdandır"}, {"kisim": 2, "madde": 9, "metin": "Allahü teâlâ, sevgili Peygamberine “aleyhi ve alâ âlihissalâtü vesselâm” emr olarak, Ahkâf sûresinde, (Peygamberlerden Ulül’azm olanların sabr etdikleri gibi Sen de sabr et! Onlara azâb verilmesi için düâ etmekde acele eyleme!)", "arama": "Peygamberlerden Ulül’azm olanların sabr etdikleri gibi Sen d"}, {"kisim": 2, "madde": 11, "metin": "[(Tefsîr-i Mazherî)de, Enbiyâ sûresinin seksenyedinci âyetinin tefsîrinde, hadîs-i şerîfde buyuruldu ki, (Birinize derd ve belâ gelince, Yûnüs Peygamberin düâsını okusun! Allahü teâlâ Onu muhakkak kurtarır. Düâ şudur: Lâ ilâhe illâ ente sübhâneke innî küntü minez-zâlimîn)", "arama": "Birinize derd ve belâ gelince, Yûnüs Peygamberin düâsını oku"}, {"kisim": 2, "madde": 13, "metin": "Nisâ sûresinin yüzyirminci âyetinde meâlen, (Şeytân insana çok şeyi sözverir ve birçok şeyi hâtırlatır. Şeytânın sözverdiği şeylerin hepsi yalandır)", "arama": "Şeytân insana çok şeyi sözverir ve birçok şeyi hâtırlatır. Ş"}, {"kisim": 2, "madde": 13, "metin": "Nisâ sûresinin yetmişaltıncı âyetinde meâlen, (Şeytânın aldatması, elbette za’îfdir)", "arama": "Şeytânın aldatması, elbette za’îfdir"}, {"kisim": 2, "madde": 14, "metin": "İbrâhîm sûresi yedinci âyetinde meâlen, (Şükr ederseniz, ni’metimi artdırırım!)", "arama": "Şükr ederseniz, ni’metimi artdırırım!"}, {"kisim": 2, "madde": 16, "metin": "ci âyet-i kerîmesinde meâlen, (Muhâcirînin ve Ensârın önce olanları ve bunlara tâbi’ olanlar, Allahü teâlâdan râzıdır. Allahü teâlâ da onlardan râzıdır. Onlara Cennetleri hâzırladım. Burada sonsuz kalacaklardır)", "arama": "Muhâcirînin ve Ensârın önce olanları ve bunlara tâbi’ olanla"}, {"kisim": 2, "madde": 17, "metin": "Cin sûresinin yirmialtıncı âyetinin meâli, (Allahü teâlâ, gaybdan bildiği şeylerden ba’zılarını yalnız Peygamberlerden dilediğine bildirir)", "arama": "Allahü teâlâ, gaybdan bildiği şeylerden ba’zılarını yalnız P"}, {"kisim": 2, "madde": 17, "metin": "Lutfen oradan okuyunuz!) (Tefsîr-i Mazherî)de bu âyet-i kerîmenin tefsîrinde buyuruyor ki, (Allahü teâlâ, Evliyâsına vâsıtasız da bildirir. Hazret-i Ömere Sâriyeyi gösterdi “radıyallahü teâlâ anhümâ”. Mûsâ aleyhisselâmın annesine, oğlunu denize koymasını, yine geriye göndereceğini ve Peygamber yapacağını bildirdiğini haber veriyor. Havârîlere vahy gibi bildirdiğini ve hazret-i Meryeme, (Hurma kütüğünü salla; tâze hurma olacak. Onları yi!)", "arama": "Allahü teâlâ, Evliyâsına vâsıtasız da bildirir. Hazret-i Öme"}, {"kisim": 2, "madde": 17, "metin": "Nihâyet (Yâ Rabbî! Oğlum Muhammed hurmeti için, bu babaya merhamet et) deyince, düâsı kabûl oldu ve (Yâ Âdem! Muhammed aleyhisselâmın ismi ile, her ne isteseydin kabûl ederdim, Muhammed olmasaydı, seni yaratmazdım)", "arama": "Yâ Âdem! Muhammed aleyhisselâmın ismi ile, her ne isteseydin"}, {"kisim": 2, "madde": 17, "metin": "İhvân-ül-müslimîn denilen mezhebsizlerin reîslerinden Seyyid Kutb da, Zümer sûresinin üçüncü âyetini tefsîr ederken, (Tevhîd ve ihlâs sâhibi, Allahdan başka kimseden birşey istemez. Hiçbir mahlûka i’timâd etmez. İnsanlar, islâmiyyetin bildirdiği tevhîdden ayrıldı. Bugün bütün memleketlerde Evliyâya ibâdet ediliyor. İslâmiyyetden evvelki arabların meleklere, heykellere tapındıkları gibi, onlardan şefâ’at istiyorlar. Allahın bildirdiği tevhîdde, ih", "arama": "Tevhîd ve ihlâs sâhibi, Allahdan başka kimseden birşey istem"}, {"kisim": 2, "madde": 17, "metin": "(Abese) sûresinin tefsîrinde, (Ölüyü yakmak, rûhu yersiz bırakmak olur. Ölüyü toprağa gömmek ise, rûh için bir yer belli etmek olur. Bunun içindir ki, gömülmüş olan Velîlerden ve başka Sâlihlerden fâidelenilmekdedir. Ölülere yardım etmek de mümkin olmakdadır. Yakılan ölüler için bunlar düşünülemez)", "arama": "Ölüyü yakmak, rûhu yersiz bırakmak olur. Ölüyü toprağa gömme"}, {"kisim": 2, "madde": 17, "metin": "Bu sünnî müslimân da, Bekara sûresinde, (Allah yolunda öldürülenlere ölü demeyiniz! Onlar diridir. Fekat, siz bunu anlamıyorsunuz)", "arama": "Allah yolunda öldürülenlere ölü demeyiniz! Onlar diridir. Fe"}, {"kisim": 2, "madde": 17, "metin": "Âl-i İmrân sûresinde, yüzüncü âyetinde meâlen, (Ey îmân edenler! Allahın dînine sarılınız. Birbirinizden ayrılmayınız!)", "arama": "Ey îmân edenler! Allahın dînine sarılınız. Birbirinizden ayr"}, {"kisim": 2, "madde": 17, "metin": "Çünki, Mâide sûresi, otuzbeşinci âyetinde meâlen, (Allahü teâlâya yaklaşmak için, vesîle arayınız!)", "arama": "Allahü teâlâya yaklaşmak için, vesîle arayınız!"}, {"kisim": 2, "madde": 17, "metin": "Enbiyâ sûresinde, (Bilmediklerinizi, bilenlerden sorup öğreniniz!)", "arama": "Bilmediklerinizi, bilenlerden sorup öğreniniz!"}, {"kisim": 2, "madde": 17, "metin": "(Nahl) ve (Enbiyâ) sûrelerinde, meâl-i şerîfleri, (Âlimlerden sorup öğreniniz!)", "arama": "Âlimlerden sorup öğreniniz!"}, {"kisim": 2, "madde": 17, "metin": "(Ey ilm sâhibleri! İ’tibâr ediniz!) âyet-i kerîmesi, (Bilmediklerinizi, bildiklerinize kıyâs ediniz!)", "arama": "Bilmediklerinizi, bildiklerinize kıyâs ediniz!"}, {"kisim": 2, "madde": 18, "metin": "ygamberimizin “sallallahü aleyhi ve sellem” öldüğü belli iken, hâlâ kabr ziyâreti ile ölülerden şefâ’at istemek olur mu? (Bütün şefâ’atler Allahın izni iledir)", "arama": "Bütün şefâ’atler Allahın izni iledir"}, {"kisim": 2, "madde": 18, "metin": "biri olan tefsîrinde, birinci âyet-i kerîmeye şöyle ma’nâ vermekdedir: Zümer sûresi, otuzuncu âyet-i kerîmesinde meâlen, (Sen öleceksin. O kâfirler de ölecekler. Sonra, kıyâmet günü, Rabbinizin huzûrunda hesâblaşacaksınız. Senin haklı olduğun, müşriklerin, bâtıl, bozuk olduğu meydâna çıkacak)", "arama": "Sen öleceksin. O kâfirler de ölecekler. Sonra, kıyâmet günü,"}, {"kisim": 2, "madde": 18, "metin": "Zümer sûresinin kırkdördüncü âyet-i kerîmesine gelince, (Kureyş kâfirleri, putların kendilerine şefâ’at edeceklerini söylüyor. Onlara söyle ki, Allahü teâlânın izni olmadan, hiç kimse şefâ’at edemez)", "arama": "Kureyş kâfirleri, putların kendilerine şefâ’at edeceklerini "}, {"kisim": 2, "madde": 18, "metin": "Müddessir sûresinin kırksekizinci âyet-i kerîmesi de, (Şefâ’at etmelerine izn verilenler, kâfirlere şefâ’at ederlerse, şefâ’atleri onlara fâide vermez)", "arama": "Şefâ’at etmelerine izn verilenler, kâfirlere şefâ’at ederler"}, {"kisim": 2, "madde": 18, "metin": "Süâl: Fâtır sûresinin yirmiikinci âyetinde meâlen, (Sen ölüye işitdiremezsin. Sen kabrde olana duyurucu değilsin!)", "arama": "Sen ölüye işitdiremezsin. Sen kabrde olana duyurucu değilsin"}, {"kisim": 2, "madde": 18, "metin": "Bu âyet-i kerîmede meâlen, (Ölülere sen işitdiremezsin. Senin sesini, Allahü teâlâ işitdirir)", "arama": "Ölülere sen işitdiremezsin. Senin sesini, Allahü teâlâ işitd"}, {"kisim": 2, "madde": 18, "metin": ") (Kıyâmet ve Âhıret) kitâbının (Müslimâna Nasîhat) kısmını okuyunuz! Enfâl sûresinin onyedinci âyetinde meâlen, (Kâfirlere atdığını sen atmadın, onları Allahü teâlâ atdı)", "arama": "Kâfirlere atdığını sen atmadın, onları Allahü teâlâ atdı"}, {"kisim": 2, "madde": 18, "metin": "Bu âyet-i kerîmeyi Kâdî Beydâvî “rahmetullahi teâlâ aleyh” şöyle tefsîr ediyor: (Yâ Muhammed “aleyhisselâm”! Kâfirlere atdığın o bir avuç toprağı, onların gözlerine sen götürmedin. Allahü teâlâ gözlerine götürdü. Yâhud Uhud gazâsında, Übeyy ibni Halefe atdığın süngüyü o kâfire sen atmadın. Allahü teâlâ atdı)", "arama": "Yâ Muhammed “aleyhisselâm”! Kâfirlere atdığın o bir avuç top"}, {"kisim": 2, "madde": 18, "metin": "Nisâ sûresinin yetmişsekizinci âyetinde meâlen, (Ey insan! Sana gelen her iyilik, Allahü teâlânın ihsânı olarak, ni’meti olarak gelmekdedir. Her derd ve belâ da, kötülüklerine karşılık olarak gelmekdedir. Hepsini yaratan, gönderen Allahü teâlâdır)", "arama": "Ey insan! Sana gelen her iyilik, Allahü teâlânın ihsânı olar"}, {"kisim": 2, "madde": 20, "metin": "İsrâ sûresinin onbeşinci âyetinde meâlen, (Biz, Peygamber göndererek bildirmeden önce, azâb yapıcı değiliz)", "arama": "Biz, Peygamber göndererek bildirmeden önce, azâb yapıcı deği"}, {"kisim": 2, "madde": 20, "metin": "Nisâ sûresinin yüzaltmışdördüncü âyetinde meâlen, (Peygamberleri, müjde vermek için ve korkutmak için gönderdim. Böylece, insanların Allahü teâlâya özr, behâne yapmaları önlendi)", "arama": "Peygamberleri, müjde vermek için ve korkutmak için gönderdim"}, {"kisim": 2, "madde": 20, "metin": "Ra’d sûresinin otuzuncu âyetinde meâlen, (İyi biliniz ki, kalbler, Allahü teâlânın zikri ile itmînâna, râhata kavuşur!)", "arama": "İyi biliniz ki, kalbler, Allahü teâlânın zikri ile itmînâna,"}, {"kisim": 2, "madde": 23, "metin": "Nitekim Vennecmi sûresi, üçüncü âyetinde meâlen, (O, boşuna konuşmaz. Hep, vahy olunanı söylemekdedir)", "arama": "O, boşuna konuşmaz. Hep, vahy olunanı söylemekdedir"}, {"kisim": 2, "madde": 23, "metin": "Nitekim, Mâide sûresi, kırkdördüncü âyetinde meâlen, (Allahü teâlânın gönderdiğine uymıyanlar kâfirdir)", "arama": "Allahü teâlânın gönderdiğine uymıyanlar kâfirdir"}, {"kisim": 2, "madde": 23, "metin": "er “radıyallahü anh” öyle bir Ömerdir ki, Hak teâlâ, onun için Resûlüne, Enfâl sûresinin altmışdördüncü âyetinde meâlen, (Ey Peygamberim “aleyhisselâm”! Sana, Allah ve mü’minlerden, senin izinde gidenler yetişir!)", "arama": "Ey Peygamberim “aleyhisselâm”! Sana, Allah ve mü’minlerden, "}, {"kisim": 2, "madde": 23, "metin": "Tevbe sûresi, kırküçüncü âyetinde meâlen, (Onlara izn verdiğin için olan hatânı, Allahü teâlâ afv etdi)", "arama": "Onlara izn verdiğin için olan hatânı, Allahü teâlâ afv etdi"}, {"kisim": 2, "madde": 23, "metin": "Haşr sûresinin ikinci âyetinde meâlen, (Ey akl sâhibleri, başkalarından ibret alınız!)", "arama": "Ey akl sâhibleri, başkalarından ibret alınız!"}, {"kisim": 2, "madde": 23, "metin": "] Âl-i İmrân sûresinin yüzellidokuzuncu âyetinde meâlen, (İşlerinde Eshâbın ile meşveret et, onlara danış!)", "arama": "İşlerinde Eshâbın ile meşveret et, onlara danış!"}, {"kisim": 2, "madde": 23, "metin": "Kur’ân-ı kerîmdeki müjdelere ne diyecekler? Meselâ, Tevbe sûresinin yüzüçüncü âyetinde meâlen, (Önce îmâna gelenlerden, her fazîletde öne geçenlerden, hem Mekkeden gelen Muhâcirlerden, hem de Medînede bunları karşılayıp yardım eden Ensârdan, önde olanlardan ve iyilikde bunların izinde gidenlerden Allahü teâlâ râzıdır.\n\nHepsini sever. Onlar da, Allahü teâlâdan râzıdır. Allahü teâlâ, Onlara Cenneti hâzırladı. Cennetde sonsuz kalacaklardır)", "arama": "Önce îmâna gelenlerden, her fazîletde öne geçenlerden, hem M"}, {"kisim": 2, "madde": 23, "metin": "ve Hadîd sûresinin, onuncu âyetinde meâlen, (Mekke şehri alınmadan önce, din düşmanları ile harb edenler ve mallarını, Allah yolunda harc edenler ile, Mekke alındıkdan sonra, bunları yapanlar, müsâvî, eşit değildir. Birinciler elbette dahâ yüksekdir. Allahü teâlâ, hepsine Hüsnâyı, ya’nî Cenneti söz verdi)", "arama": "Mekke şehri alınmadan önce, din düşmanları ile harb edenler "}, {"kisim": 2, "madde": 23, "metin": "Feth sûresi, onsekizinci âyetinde meâlen, (Ağaç altında, sana söz veren mü’minlerden, Allahü teâlâ elbette râzıdır)", "arama": "Ağaç altında, sana söz veren mü’minlerden, Allahü teâlâ elbe"}, {"kisim": 2, "madde": 23, "metin": "Bekara sûresi, otuzuncu âyetinin, (Yâ Rabbî! Yeryüzünde, fesâd çıkaracak ve kan dökecek olan kulları mı yaratacaksın? Biz, seni tesbîh ediyoruz, hamd ediyoruz. Seni her dürlü aybdan, kusûrdan takdîs ediyoruz dedi)", "arama": "Yâ Rabbî! Yeryüzünde, fesâd çıkaracak ve kan dökecek olan ku"}, {"kisim": 2, "madde": 23, "metin": "m” isminde bir oğul verileceği müjdelendiği zemân, Meryem sûresi, sekizinci âyetinin meâl-i şerîfinde bildirildiği gibi, (Benim hiç çocuğum olur mu? Zevcem kısırdır. Ben ise, ihtiyâr oldum)", "arama": "Benim hiç çocuğum olur mu? Zevcem kısırdır. Ben ise, ihtiyâr"}, {"kisim": 2, "madde": 23, "metin": "Meryem “radıyallahü anhâ” da, Meryem sûresi, yirminci âyetinin meâl-i şerîfinde bildirildiği gibi, (Benim hiç çocuğum olur mu? Bir erkek ile bir araya gelmedim. Günâh da işlemedim)", "arama": "Benim hiç çocuğum olur mu? Bir erkek ile bir araya gelmedim."}, {"kisim": 2, "madde": 23, "metin": "Allahü teâlâ Feth sûresi son âyetinde meâlen, (Onlar, birbirine, her zemân ve çok iyilik edicidir)", "arama": "Onlar, birbirine, her zemân ve çok iyilik edicidir"}, {"kisim": 2, "madde": 23, "metin": "Bu sûretle, Server-i âlemin “sallallahü aleyhi ve sellem” haber vermiş olduğu, (Bu benim oğlum seyyiddir. Ya’nî büyükdür. Allahü teâlâ, onun ile, mü’minlerden, iki büyük fırka arasını bulur. Ya’nî barışdırır)", "arama": "Bu benim oğlum seyyiddir. Ya’nî büyükdür. Allahü teâlâ, onun"}, {"kisim": 2, "madde": 25, "metin": "Hadîd sûresinin onuncu âyetinde meâlen, (Mekke-i mükerremenin fethinden önce malını veren ve cihâd eden kimseye, fethden sonra malını dağıtan ve cihâd edenden dahâ büyük derece vardır. Allahü teâlâ, hepsine Cenneti va’d etdi)", "arama": "Mekke-i mükerremenin fethinden önce malını veren ve cihâd ed"}, {"kisim": 2, "madde": 25, "metin": "Enfâl sûresinin, altmışdördüncü âyetinde meâlen, (Ey Peygamberim “sallallahü aleyhi ve sellem”! Sana yardımcı olarak Allahü teâlâ ve mü’minlerden sana tâbi’ olanlar yetişir)", "arama": "Ey Peygamberim “sallallahü aleyhi ve sellem”! Sana yardımcı "}, {"kisim": 2, "madde": 25, "metin": "Hâlbuki, Şûrâ sûresi, otuzuncu [30] âyetinde meâlen, (Size gelen belâlar, kabâhatlerinizin cezâsıdır)", "arama": "Size gelen belâlar, kabâhatlerinizin cezâsıdır"}, {"kisim": 2, "madde": 25, "metin": "Hadîd sûresi, yirmibeşinci [25] âyetinin meâl-i şerîfi, (Allahü teâlâ, Peygamberlerine, gaybdan, görmeden, yardım edenleri bilmek için...)", "arama": "Allahü teâlâ, Peygamberlerine, gaybdan, görmeden, yardım ede"}, {"kisim": 2, "madde": 25, "metin": "Tâhâ sûresi, yüzonbeşinci [115] âyetinde meâlen, (Âdeme önce söyledik. Fekat unutdu. Azm ile, karâr ile yapmadı)", "arama": "Âdeme önce söyledik. Fekat unutdu. Azm ile, karâr ile yapmad"}, {"kisim": 2, "madde": 25, "metin": "Nahl sûresi, otuzüçüncü [33] âyetinde meâlen, (Allahü teâlâ, onlara zulm etmez. Onlar, kendi kendilerine zulm edip, ağır cezâları hak etdiler)", "arama": "Allahü teâlâ, onlara zulm etmez. Onlar, kendi kendilerine zu"}, {"kisim": 2, "madde": 25, "metin": "Furkân sûresi, yedinci [7] âyetinde meâlen, (Kâfirler: Bu nasıl Peygamberdir? “sallallahü aleyhi ve sellem”. Bizim gibi yiyip içiyor, sokaklarda geziyor. Peygamber olsaydı, kendisine melek gelirdi. Yardımcıları olur, bize onlar da haber verir, Cehennem ile korkuturlardı. Yâhud, Rabbi, para hazîneleri gönderir, yâhud, meyve bağçeleri, çiftlikleri olur, istediğini yirdi dediler...)", "arama": "Kâfirler: Bu nasıl Peygamberdir? “sallallahü aleyhi ve selle"}, {"kisim": 2, "madde": 28, "metin": "(Yûnüs) sûresinin yirmibeşinci âyetinde meâlen, (Allahü teâlâ kullarını, selâmet, se’âdet yeri olan Cennetine da’vet ediyor. Dilediğini bu yola kavuşdurur)", "arama": "Allahü teâlâ kullarını, selâmet, se’âdet yeri olan Cennetine"}, {"kisim": 2, "madde": 28, "metin": "(Ankebût) sûresinin son âyetinde meâlen, (Nefslerine uyanlardan, doğru yolu arayanları, se’âdete ulaşdıran yollara kavuşdururuz)", "arama": "Nefslerine uyanlardan, doğru yolu arayanları, se’âdete ulaşd"}, {"kisim": 2, "madde": 30, "metin": "resinde, (Kullarıma hikmet ile ve güzel va’z ile beni tanıt!) meâlindeki yüzyirmibeşinci âyet-i kerîmeyi tefsîr ederken, (Anlayışlı, tahsîlli olanlara, fen bilgileri ile; hislerine tâbi’ olan câhil halka da, görünenleri anlatmakla bildir, demekdir)", "arama": "Anlayışlı, tahsîlli olanlara, fen bilgileri ile; hislerine t"}, {"kisim": 2, "madde": 30, "metin": "orsun, hâlbuki bunlar bulut gibi hareket etmekdedir) olan seksensekizinci âyet-i kerîmesini Kâdî Beydâvî tefsîr ederken, (Yerinde duruyor gördüğün dağlar, bulut gibi, boşlukda hızlı gitmekdedir. Büyük cismler, bir cihete doğru hızlı gidince, üstündekiler, bunun hareket etdiğini duymaz)", "arama": "Yerinde duruyor gördüğün dağlar, bulut gibi, boşlukda hızlı "}, {"kisim": 2, "madde": 30, "metin": "Bunu okutmasını hoş görmiyen biri, müslimân çocuklarına böyle ne okutuyorsun diye sorunca, meâl-i şerîfi, (Yerleri, gökleri, yıldızları, bitkileri ne güzel yaratdığımızı görmiyorlar mı?)", "arama": "Yerleri, gökleri, yıldızları, bitkileri ne güzel yaratdığımı"}, {"kisim": 2, "madde": 31, "metin": "Rahmân sûresindeki bir âyet-i kerîmede meâlen, (Ey cin ve ey insan! Gücünüz yeterse, yer yüzünden ve semâlardan dışarı çıkınız. Çıkmanız için, çok kuvvet ister. O kuvvet de sizde yokdur)", "arama": "Ey cin ve ey insan! Gücünüz yeterse, yer yüzünden ve semâlar"}, {"kisim": 2, "madde": 39, "metin": "Nûr sûresindeki âyet-i kerîmede meâlen, (Müslimân kadınlar, zînetlerini göstermesinler! İş yaparken zarûrî açılanlar günâh olmaz. Baş örtülerini yakalarına kadar örtsünler [Böylece, saçları, kulakları ve göğüsleri iyi örtülsün])", "arama": "Müslimân kadınlar, zînetlerini göstermesinler! İş yaparken z"}, {"kisim": 2, "madde": 39, "metin": "Yine bu sûrede, (Kadınlar ayaklarını yere vurarak yürümesinler ki, ayaklarındaki örtülü zînetlerin sesleri işitilmesin)", "arama": "Kadınlar ayaklarını yere vurarak yürümesinler ki, ayaklarınd"}, {"kisim": 2, "madde": 39, "metin": "îmin onyedi yerinde meâl-i şerîfleri, (Allahı seviyorsanız bana tâbi’ olunuz! Bana tâbi’ olanları Allahü teâlâ sever) ve (Allaha ve Resûle itâ’at ediniz. İtâ’at etmezseniz, Allah kâfirleri elbet sevmez)", "arama": "Allaha ve Resûle itâ’at ediniz. İtâ’at etmezseniz, Allah kâf"}, {"kisim": 2, "madde": 39, "metin": "(Tefsîr-i Mazherî) sâhibi “rahmetullahi teâlâ aleyh”, Nûr sûresinin tefsîrinde diyor ki, (Kadın ancak zarûret olduğu zemân ve başı, saçları, boynu ve bütün bedeni örtülü olarak sokağa çıkmalıdır. Kadının sokağa çıkması için zarûret, ihtiyâc maddelerini alacak ve dînini öğretecek kimsesi bulunmamakdır. Baş örtüsü ile yüzünü de örterek ve bedenini örtecek her şeklde kumaş ile örtünerek çıkması câizdir. Burada, yüzünü kelimesi, başını demekdir. Çünk", "arama": "Kadın ancak zarûret olduğu zemân ve başı, saçları, boynu ve "}, {"kisim": 2, "madde": 40, "metin": "] 1 — Halâl kazanmanın üstünlüğü ve sevâbı: Mü’minûn sûresi, elliikinci [52] âyetinde meâlen, (Ey Peygamberlerim “salevâtullahi aleyhim ecma’în”. Halâl ve temiz yiyiniz ve bana lâyık ibâdetler yapınız!)", "arama": "Ey Peygamberlerim “salevâtullahi aleyhim ecma’în”. Halâl ve "}, {"kisim": 2, "madde": 42, "metin": "Allahü teâlâ, Enfâl sûresi, altmışaltıncı âyetinde meâlen, (Yüz mü’min, ikiyüz kâfire gâlip gelir)", "arama": "Yüz mü’min, ikiyüz kâfire gâlip gelir"}, {"kisim": 2, "madde": 43, "metin": "ükleri, (Berîka) kitâbının sâhibi Hâdimî “rahmetullahi teâlâ aleyh” seksenbeşinci sahîfesinde diyor ki: Âyet-i kerîmede, (Habîs olan şeyler harâmdır)", "arama": "Habîs olan şeyler harâmdır"}, {"kisim": 2, "madde": 43, "metin": "inden başlıyarak diyor ki: Mâlikî âlimlerinden Alî Echürî (Gâyet-ül-beyân) kitâbında, şeyh Halîlden alarak buyuruyor ki, (Aklı götürüp hissi gidermiyen ve keyf veren maddeye (Müskir)", "arama": "Aklı götürüp hissi gidermiyen ve keyf veren maddeye (Müskir"}, {"kisim": 2, "madde": 43, "metin": "İbni Âbidîn “rahmetullahi teâlâ aleyh”, (Zebâ’ih) kısmında, En’âm sûresinin yüzkırkbeşinci âyetini ve (Allahü teâlânın, halâl ve harâm diye açıklamadığı şey, Allahü teâlânın afv etdiği şeylerdendir)", "arama": "Allahü teâlânın, halâl ve harâm diye açıklamadığı şey, Allah"}, {"kisim": 2, "madde": 43, "metin": "Çünki, Allahü teâlâ Bekara sûresinde, (Yerlerde olan herşeyi sizin için yaratdım)", "arama": "Yerlerde olan herşeyi sizin için yaratdım"}, {"kisim": 2, "madde": 44, "metin": "İsrâ sûresindeki âyet-i kerîmede de meâlen, (Tebzîr etme! Tebzîr edenler, şeytânların kardeşleridir)", "arama": "Tebzîr etme! Tebzîr edenler, şeytânların kardeşleridir"}, {"kisim": 2, "madde": 44, "metin": "Nisâ sûresindeki âyet-i kerîmede meâlen, (Mallarınızı sefîhlere, alçaklara vermeyiniz!)", "arama": "Mallarınızı sefîhlere, alçaklara vermeyiniz!"}, {"kisim": 2, "madde": 44, "metin": "Bekara sûresi, ikiyüzyetmişbeşinci âyetinde meâlen, (Fâiz yiyenler, kıyâmet günü mezârlarından, sar’a hastası gibi perişân kalkacaklardır)", "arama": "Fâiz yiyenler, kıyâmet günü mezârlarından, sar’a hastası gib"}, {"kisim": 2, "madde": 44, "metin": "Bundan sonraki âyet-i kerîmede meâlen, (Allahü teâlâ, fâiz alan ve verenlerin mallarının hepsini yok eder. İzini, eserini de bırakmaz. Zekât verenlerin malını elbette artdırır)", "arama": "Allahü teâlâ, fâiz alan ve verenlerin mallarının hepsini yok"}, {"kisim": 2, "madde": 44, "metin": "İbrâhîm sûresi, yedinci âyetinde meâlen, (Şükr ederseniz, verdiğim ni’metleri elbette artdırırım)", "arama": "Şükr ederseniz, verdiğim ni’metleri elbette artdırırım"}, {"kisim": 2, "madde": 44, "metin": "Şimdi bunu açıklamağa çalışacağız: Cenâb-ı Hak, Mü’minûn sûresinde, meâl-i şerîfi, (Verdiğimiz rızklardan, sadaka verirler)", "arama": "Verdiğimiz rızklardan, sadaka verirler"}, {"kisim": 2, "madde": 44, "metin": "n-i Râzî gibi büyük âlimlerin tefsîrlerinde ve dahâ birçok tefsîrlerde diyor ki, âyet-i kerîmede, (rızklardan) kelimesi, (rızkların ba’zısını, bir kısmını)", "arama": "rızkların ba’zısını, bir kısmını"}, {"kisim": 2, "madde": 44, "metin": "En’âm sûresi, yüzkırkbirinci âyetinde meâlen, (Ekini hasâd etdiğiniz zemân, fakîrlerin haklarını verin ve isrâf etmeyin. Allahü teâlâ, isrâf edenleri elbette sevmez)", "arama": "Ekini hasâd etdiğiniz zemân, fakîrlerin haklarını verin ve i"}, {"kisim": 2, "madde": 44, "metin": "İsrâ sûresi, yirmidokuzuncu âyetinde meâlen, (Ey Habîbim! Malını, kendine kalmıyacak şeklde dağıtma!)", "arama": "Ey Habîbim! Malını, kendine kalmıyacak şeklde dağıtma!"}, {"kisim": 2, "madde": 44, "metin": "Allahü teâlâ, (Mallarınızı sefîhlere vermeyiniz!) meâlindeki âyet-i kerîmeden sonra, (Onların hâlinde rüşd görürseniz, mallarını kendilerine teslîm ediniz!)", "arama": "Onların hâlinde rüşd görürseniz, mallarını kendilerine teslî"}, {"kisim": 2, "madde": 44, "metin": "Bunun kötülüğünü anlamak için, Vennecmi sûresi, otuzdokuzuncu âyet-i kerîmesinin, (İnsan, ancak çalışdığının fâidesini görür)", "arama": "İnsan, ancak çalışdığının fâidesini görür"}, {"kisim": 2, "madde": 47, "metin": "cü âyet-i kerîmede, (Eğer îmânınız varsa, Allahü teâlâya tevekkül ediniz!)", "arama": "Eğer îmânınız varsa, Allahü teâlâya tevekkül ediniz!"}, {"kisim": 2, "madde": 47, "metin": "cu âyet-i kerîmede, (Allahü teâlâ, tevekkül edenleri elbette sever)", "arama": "Allahü teâlâ, tevekkül edenleri elbette sever"}, {"kisim": 2, "madde": 47, "metin": "cü âyet-i kerîmede, (Bir kimse, Allahü teâlâya tevekkül ederse, Allahü teâlâ, ona kâfîdir)", "arama": "Bir kimse, Allahü teâlâya tevekkül ederse, Allahü teâlâ, ona"}, {"kisim": 2, "madde": 47, "metin": "cı âyet-i kerîmede, (Allahü teâlâ, kuluna kâfî değil midir?)", "arama": "Allahü teâlâ, kuluna kâfî değil midir?"}, {"kisim": 2, "madde": 47, "metin": "cı âyet-i kerîmede meâlen, (İlm-i yakîn ile bilseydiniz, Cehennemi elbette görürdünüz)", "arama": "İlm-i yakîn ile bilseydiniz, Cehennemi elbette görürdünüz"}, {"kisim": 2, "madde": 47, "metin": "ci âyet-i kerîmede meâlen, (Hepinizin dünyâya getirilmesi ve âhıretde tekrâr diriltilmesi, bir kişinin yaratılması ve diriltilmesi gibidir)", "arama": "Hepinizin dünyâya getirilmesi ve âhıretde tekrâr diriltilmes"}, {"kisim": 2, "madde": 47, "metin": "ci âyet-i kerîmede meâlen, (Onların âhıretdeki hâlleri, dünyâdaki hâlleri gibidir)", "arama": "Onların âhıretdeki hâlleri, dünyâdaki hâlleri gibidir"}, {"kisim": 2, "madde": 47, "metin": "cü âyet-i kerîmenin, (Allahü teâlâ bize yetişir. O, çok iyi vekîldir)", "arama": "Allahü teâlâ bize yetişir. O, çok iyi vekîldir"}, {"kisim": 2, "madde": 47, "metin": "cı âyet-i kerîmede bildirdiği gibi, (İnanmadın mı?) buyuruldukda, (İnandım. Fekat kalbim râhat etmek için istedim)", "arama": "İnandım. Fekat kalbim râhat etmek için istedim"}, {"kisim": 2, "madde": 47, "metin": "cu âyet-i kerîmede meâlen, (Herşeye kuvvet veren, ancak Allahü teâlâdır)", "arama": "Herşeye kuvvet veren, ancak Allahü teâlâdır"}, {"kisim": 2, "madde": 47, "metin": "Bir kimse, cenâb-ı Hakka, yâ Rabbî! Bana rızk verme diye düâ etse, Allahü teâlâ buyurur ki, (Ey câhil! Seni yaratdım. Rızkını vermez miyim?)", "arama": "Ey câhil! Seni yaratdım. Rızkını vermez miyim?"}, {"kisim": 2, "madde": 47, "metin": "ci âyet-i kerîmede meâlen, (Şeytân, muhtâc hâle düşeceğinizi, size söz veriyor)", "arama": "Şeytân, muhtâc hâle düşeceğinizi, size söz veriyor"}, {"kisim": 2, "madde": 47, "metin": "cı âyet-i kerîmenin, (Yer yüzündeki her cânlının rızkını, Allahü teâlâ, elbette gönderir)", "arama": "Yer yüzündeki her cânlının rızkını, Allahü teâlâ, elbette gö"}, {"kisim": 2, "madde": 47, "metin": "cı âyet-i kerîmesi olan, (Allahü teâlânın rızk vermediği, yer yüzünde bir mahlûk yokdur)", "arama": "Allahü teâlânın rızk vermediği, yer yüzünde bir mahlûk yokdu"}, {"kisim": 2, "madde": 47, "metin": "Sûre-i Ahzâbda, (Kâfirlerin ve münâfıkların zararlarına, işkencelerine karşılıkda bulunma! Ben onların cezâsını veririm. Onlardan korunmak, kurtulmak için Allahü teâlâya tevekkül et!)", "arama": "Kâfirlerin ve münâfıkların zararlarına, işkencelerine karşıl"}, {"kisim": 2, "madde": 47, "metin": "ci âyet-i kerîmesi ve sûre-i İbrâhîmde, (Yapdıkları işkencelere sabr ederiz. Tevekkül ediciler, yalnız Allahü teâlâya tevekkül etmelidir)", "arama": "Yapdıkları işkencelere sabr ederiz. Tevekkül ediciler, yalnı"}, {"kisim": 2, "madde": 47, "metin": "Vahy gelip, Allahü teâlâ buyurdu ki, (Sen tevekkül etmek için, benim âdetimi, hikmetimi değişdirmek istiyorsun. İlâclara, fâideli te’sîrleri kim verdi? Elbette ben yaratıyorum)", "arama": "Sen tevekkül etmek için, benim âdetimi, hikmetimi değişdirme"}, {"kisim": 2, "madde": 48, "metin": "Üçünü de sâdeleşdirerek, yazmayı uygun gördük: Ra’d sûresindeki, (Allahü teâlâ, dilediğini siler. Dilediğini değişdirmez. Ümm-ül-kitâb, Ondadır)", "arama": "Allahü teâlâ, dilediğini siler. Dilediğini değişdirmez. Ümm-"}, {"kisim": 2, "madde": 48, "metin": "p, nasıl böyle söylüyorsun, Allahü teâlâ meâlen, (Ecel, bir ân gecikmez ve vaktinden önce gelmez) buyurdu, dediklerinde, (Evet, ecel hâzır olduğu vakt gecikmez. Fekat, ecel hâsıl olmadan önce, sadaka ile, düâ ile, amel-i sâlih ile, ömür uzar. Zîrâ Fâtır sûresinde meâlen, (Herkesin ömrü ve ömürlerin kısalması hep yazılıdır)", "arama": "Evet, ecel hâzır olduğu vakt gecikmez. Fekat, ecel hâsıl olm"}, {"kisim": 2, "madde": 49, "metin": "İ CÜZ’İYYE İrâde-i cüz’iyye risâlesini Muhammed Akkermânî “rahmetullahi aleyh” yazmışdır: Dehr [veyâ İnsan] sûresindeki, (Siz, ancak Allahü teâlânın dilediğini arzû edersiniz!)", "arama": "Siz, ancak Allahü teâlânın dilediğini arzû edersiniz!"}, {"kisim": 2, "madde": 49, "metin": "meâlindeki âyet-i kerîmeden, Ebül-Hasen-i Eş’arî imâmımız “rahmetullahi teâlâ aleyh” (Allahü teâlâ, sizin istemenizi dilemedikce, birşey isteyemezsiniz!)", "arama": "Allahü teâlâ, sizin istemenizi dilemedikce, birşey isteyemez"}, {"kisim": 2, "madde": 49, "metin": "Yukarıdaki âyet-i kerîmenin ma’nâsını, Ebû Mensûr-i Mâtürîdî “rahmetullahi teâlâ aleyh” şöyle açıklıyor: (İhtiyârî işleriniz, yalnız sizin irâdenizle olmaz. Sizin irâdenizden sonra, Allahü teâlâ da, o işi irâde edip yaratır.)", "arama": "İhtiyârî işleriniz, yalnız sizin irâdenizle olmaz. Sizin irâ"}, {"kisim": 2, "madde": 49, "metin": "cı âyetinde meâlen, (İnsanları ve cinnîleri ancak, Beni bilip, itâ’at, ibâdet etmeleri için yaratdım!)", "arama": "İnsanları ve cinnîleri ancak, Beni bilip, itâ’at, ibâdet etm"}, {"kisim": 2, "madde": 49, "metin": "cü âyetinde meâlen, (Allahü teâlânın indinde din, islâm dînidir)", "arama": "Allahü teâlânın indinde din, islâm dînidir"}, {"kisim": 2, "madde": 49, "metin": "Kendisini unutanlara Bekara sûresinin yedinci âyetinde, meâlen (onların kalblerini mühürledik)", "arama": "onların kalblerini mühürledik"}, {"kisim": 2, "madde": 50, "metin": "Yasîn sûresindeki, (Onların îmân etmiyeceklerini ezelde söyledik) meâlindeki ve Müddessir sûresindeki, (Onu yalnız yaratdım, sonra çok mal, her işine hâzır yardımcı çocuklar ve yüksek rütbe ve mevkı’ verdim. Fekat o, bunları az görüp dahâ istedi ise de, artdırmadım. Çünki, benim Kur’ânıma ve Peygamberime inanmadı, inâd etdi. Sonra, onu Cehennemde (Sa’ûd)", "arama": "Onu yalnız yaratdım, sonra çok mal, her işine hâzır yardımcı"}, {"kisim": 2, "madde": 50, "metin": "Nitekim, Fahreddîn-i Râzî, Bekara sûresinin baş tarafındaki, (Allahü teâlâ, onların kalblerini mühürlemişdir!)", "arama": "Allahü teâlâ, onların kalblerini mühürlemişdir!"}, {"kisim": 2, "madde": 52, "metin": "Allahü teâlâ, Bekara sûresinin ikiyüzonaltıncı âyetinde meâlen, (Ba’zı şeyleri sever, fâideli dersiniz. Hâlbuki o şeyler size zararlıdır)", "arama": "Ba’zı şeyleri sever, fâideli dersiniz. Hâlbuki o şeyler size"}, {"kisim": 2, "madde": 52, "metin": "Burada birini bildirelim: Yasîn-i şerîf sûresinde seksenbirinci âyet-i kerîmenin sonunun meâli, (Onun yaratdıkları pek çokdur. O, herşeyi bilir)", "arama": "Onun yaratdıkları pek çokdur. O, herşeyi bilir"}, {"kisim": 2, "madde": 52, "metin": "Hâlbuki, bu âyet-i kerîme radyoda, ho-parlörde söylenirken ve lâtin harfleri ile okunurken, ma’nâsı bozularak, (O berberdir, herşeyi bilicidir)", "arama": "O berberdir, herşeyi bilicidir"}, {"kisim": 2, "madde": 52, "metin": "Bekara sûresi ikiyüzonaltıncı âyetinde meâlen, (Beğendiğiniz, sevdiğiniz çok şey vardır ki, sizin için zararlıdır!)", "arama": "Beğendiğiniz, sevdiğiniz çok şey vardır ki, sizin için zarar"}, {"kisim": 2, "madde": 53, "metin": "ise sirruh”, Cinnin var olduğunu, şu âyet-i kerîmeler ile gösteriyor: 1 — Zâriyât sûresinin ellialtıncı âyetinde meâlen, (İnsanları ve Cinnîleri ancak, beni bilip itâ’at, ibâdet etmeleri için yaratdım)", "arama": "İnsanları ve Cinnîleri ancak, beni bilip itâ’at, ibâdet etme"}, {"kisim": 2, "madde": 55, "metin": "A’râf sûresinin seksendokuzuncu âyetinde meâlen, (Ey Rabbimiz, bizimle kavmimiz arasında sen hak olanı hükm et. Sen hükm edenlerin hayrlısısın!)", "arama": "Ey Rabbimiz, bizimle kavmimiz arasında sen hak olanı hükm et"}, {"kisim": 2, "madde": 57, "metin": "Allahü teâlâ, Enfâl sûresinin altmışdördüncü âyetinde meâlen, (Ey Peygamberim! Allahü teâlâ ve senin yolunda olan mü’minler, sana kâfîdirler!)", "arama": "Ey Peygamberim! Allahü teâlâ ve senin yolunda olan mü’minler"}, {"kisim": 2, "madde": 57, "metin": "İkra’ sûresindeki âyet-i kerîmede meâlen, (İnsan, ihtiyâcsız olunca, elbette azar!)", "arama": "İnsan, ihtiyâcsız olunca, elbette azar!"}, {"kisim": 2, "madde": 61, "metin": "Sûre-i Mücâdele, onsekizinci [18] âyet-i kerîmesinin: (Onlar iyi bir iş yapdıklarını sanıyor. Biliniz ki, çok yalancıdırlar. Şeytân onları aldatmış, yoldan çıkarmışdır. Allahü teâlâyı o kadar unutdurmuş ki, ne dillerine, ne de gönüllerine getirmezler. Şeytânın askeri, uşakları olmuşlardır. Biliniz ki, şeytânın gürûhü olan bunlar, bitmez tükenmez ni’metleri elden kaçırdı. Sonsuz azâblara yakalandı)", "arama": "Onlar iyi bir iş yapdıklarını sanıyor. Biliniz ki, çok yalan"}, {"kisim": 2, "madde": 62, "metin": "î mısra tercemesi: Her ne olursa olsun, dostdan konuşmak dahâ tatlı!\n Bekara sûresinin yüzseksenaltıncı âyetinde meâlen, (Kullarım senden beni soruyorlar. Ben onlara çok yakınım!)", "arama": "Kullarım senden beni soruyorlar. Ben onlara çok yakınım!"}, {"kisim": 2, "madde": 62, "metin": "ve Mücâdele sûresinin yedinci âyetinde meâlen, (Üç adam gizli konuşunca, Allah onların dördüncüsü olur. Beş kişi gizli konuşunca, Allah onların altıncısı olur. Dahâ az veyâ dahâ çok kimseler olunca da, her nerede olursa olsunlar, Allah onlarla berâberdir)", "arama": "Üç adam gizli konuşunca, Allah onların dördüncüsü olur. Beş "}, {"kisim": 2, "madde": 62, "metin": "Mü’minûn sûresinin ellidördüncü âyetinde ve Rum sûresindeki bir âyet-i kerîmede meâlen, (Her fırkada bulunanlar, kendi anladıklarını doğru sanırlar)", "arama": "Her fırkada bulunanlar, kendi anladıklarını doğru sanırlar"}, {"kisim": 2, "madde": 67, "metin": "En’âm sûresinin yüzüçüncü âyetinde meâlen, (Onu gözler anlıyamaz. O ise, gözleri bilir, anlar. O, ihsân sâhibi bilicidir)", "arama": "Onu gözler anlıyamaz. O ise, gözleri bilir, anlar. O, ihsân "}, {"kisim": 2, "madde": 67, "metin": "Çünki, Kur’ân-ı kerîmin birçok sûresinde, (Allahü teâlâ yapdıklarınızı görücüdür) ve (O, işitici ve görücüdür) ve (Allahü teâlâ amelinizi görür)", "arama": "Allahü teâlâ amelinizi görür"}, {"kisim": 2, "madde": 67, "metin": "Allahü teâlâ, İsrâ sûresinin onbeşinci âyetinde meâlen, (Peygamber göndermedikce azâb yapmayız!)", "arama": "Peygamber göndermedikce azâb yapmayız!"}, {"kisim": 2, "madde": 67, "metin": "] İsrâ sûresinin onbeşinci âyetinde meâlen, (Biz, Peygamber göndermedikçe, azâb yapıcı değiliz)", "arama": "Biz, Peygamber göndermedikçe, azâb yapıcı değiliz"}, {"kisim": 2, "madde": 72, "metin": "cü âyet-i kerîmesi gelerek, (Allahü teâlâ îmânlarınızı zâyı’ eylemez!)", "arama": "Allahü teâlâ îmânlarınızı zâyı’ eylemez!"}, {"kisim": 2, "madde": 72, "metin": "cı âyetinin, (Onların çoğu Allahü teâlâya îmân ediyoruz derler. Fekat îmânsızdırlar. Başka şeylere ibâdet ederek müşrik olmuşlardır)", "arama": "Onların çoğu Allahü teâlâya îmân ediyoruz derler. Fekat îmân"}, {"kisim": 2, "madde": 72, "metin": "(Tefsîr-i Mazherî)de, Mâide sûresinin kırkdördüncü âyetinin tefsîrinde buyuruyor ki, (Hadîs-i şerîfde, (Îsâ aleyhisselâmın yapdığını yapmakda ben herkesden ilerideyim. Peygamberler “aleyhimüsselâm”, babaları bir olan kardeşler gibidirler. Anaları ayrıdır. Dinleri birdir)", "arama": "Îsâ aleyhisselâmın yapdığını yapmakda ben herkesden ileridey"}, {"kisim": 2, "madde": 73, "metin": "Bu âyet-i kerîme, meâlen, (Allahü teâlâ, bu üstünlüğü dilediğine ihsân eder)", "arama": "Allahü teâlâ, bu üstünlüğü dilediğine ihsân eder"}, {"kisim": 3, "madde": 2, "metin": "Nisâ sûresi, ellidokuzuncu [59] âyetinde meâlen, (Onlara, kâfirlere inanmayınız dediğim hâlde, onlar kâfirlerin sözleri ile hareket ediyorlar. Şeytân onları aldatıyor)", "arama": "Onlara, kâfirlere inanmayınız dediğim hâlde, onlar kâfirleri"}, {"kisim": 3, "madde": 2, "metin": "Sûre-i Yûsüfdeki âyet-i kerîmede meâlen, (Biz, Allahü teâlânın varlığına, birliğine, herşeyi yaratan O olduğuna inandık, müslimân olduk diyenlerin çoğu, başkalarına ibâdet ve itâ’at ederek ve dahâ birçok hareketleri ve sözleri ile, müşrik oluyorlar)", "arama": "Biz, Allahü teâlânın varlığına, birliğine, herşeyi yaratan O"}, {"kisim": 3, "madde": 2, "metin": "Nûr sûresindeki otuzuncu âyet-i kerîmede meâlen, (Mü’minlere söyle, yabancı kadınlara bakmasınlar ve zinâ etmesinler! Ve mü’min kadınlara söyle! Onlar da, yabancı erkeklere bakmasınlar ve zinâ etmesinler!)", "arama": "Mü’minlere söyle, yabancı kadınlara bakmasınlar ve zinâ etme"}, {"kisim": 3, "madde": 2, "metin": "(Rûh-ul-beyân)da, Tevbe sûresi, otuzyedinci âyetinin tefsîrinde diyor ki, (Resûlullah “sallallahü aleyhi ve sellem” teşrîf edince, günlerin mü’minlere uğursuz olmaları kalmadı)", "arama": "Resûlullah “sallallahü aleyhi ve sellem” teşrîf edince, günl"}, {"kisim": 3, "madde": 2, "metin": "Nisâ sûresi, yüzkırkyedinci [147] âyetinin meâl-i şerîfi: (Allahın ni’metlerine şükr eder ve îmân ederseniz, Allah size niçin azâb etsin?)", "arama": "Allahın ni’metlerine şükr eder ve îmân ederseniz, Allah size"}, {"kisim": 3, "madde": 15, "metin": "Hâlbuki, bu âyet-i kerîmenin meâli, (Mü’minlere saldıran zâlimlerle cihâd yapmağa izn verildi)", "arama": "Mü’minlere saldıran zâlimlerle cihâd yapmağa izn verildi"}, {"kisim": 3, "madde": 15, "metin": "Kur’ân-ı kerîmde, Mutaffifîn sûresi, birinci âyetinde meâlen, (Verirken noksân, alırken fazla ölçenlere acı azâblar yapacağım)", "arama": "Verirken noksân, alırken fazla ölçenlere acı azâblar yapacağ"}, {"kisim": 3, "madde": 16, "metin": "Şimdi ihsân nasıl yapılacağını anlatacağız: A’râf sûresi, ellibeşinci âyetinde meâlen, (İhsân edenlere, elbette rahmetim çok yakındır)", "arama": "İhsân edenlere, elbette rahmetim çok yakındır"}, {"kisim": 3, "madde": 16, "metin": "Allahü teâlâ buyuracak ki, (Ey kulum! Bugün sen fakîr, muhtâcsın! Sen dünyâda benim kullarıma acıdığın gibi, bugün biz de sana acırız)", "arama": "Ey kulum! Bugün sen fakîr, muhtâcsın! Sen dünyâda benim kull"}, {"kisim": 3, "madde": 17, "metin": "Münâfıkûn sûresi, dokuzuncu âyet-i kerîmesinde meâlen, (Mallarınız ve çocuklarınız, Allahü teâlâyı, hâtırlamanıza mâni’ olmasın!)", "arama": "Mallarınız ve çocuklarınız, Allahü teâlâyı, hâtırlamanıza mâ"}, {"kisim": 3, "madde": 19, "metin": "Böylece, Mâide sûresinin, (Ölüme sebeb olan sıkışık hâle düşen)", "arama": "Ölüme sebeb olan sıkışık hâle düşen"}, {"kisim": 3, "madde": 27, "metin": "Nitekim Şûrâ sûresinde, onüçüncü âyet-i kerîmede meâlen, (Allahü teâlâ, dilediğini seçerek kendine kavuşdurur)", "arama": "Allahü teâlâ, dilediğini seçerek kendine kavuşdurur"}, {"kisim": 3, "madde": 27, "metin": "(Tefsîr-i azîzî) sâhibi “rahmetullahi teâlâ aleyh”, Dehr sûresini açıklarken diyor ki, (Zikr etmek, Allahdan başka şeylerin sevgisini, onlara düşkün olmağı kalbden çıkarmak içindir.\n\nKalbin mahlûklara bağlılığını yok etmek için en iyi ilâcın zikr olduğu tecribelerle anlaşılmışdır. Hadîs-i şerîfde, (Zikr ederek, kalblerinin yükünü hafîfletenlerin yolunda olunuz!)", "arama": "Zikr etmek, Allahdan başka şeylerin sevgisini, onlara düşkün"}, {"kisim": 3, "madde": 27, "metin": "] Ra’d sûresindeki âyet-i kerîmede meâlen, (Biliniz ki kalbler, ancak Allahı zikr etmekle itmînâna kavuşur)", "arama": "Biliniz ki kalbler, ancak Allahı zikr etmekle itmînâna kavuş"}, {"kisim": 3, "madde": 27, "metin": "Bekara sûresi, yüzonbeşinci âyetinde meâlen, (Nereye dönerseniz, orada Allahü teâlâyı bulursunuz!)", "arama": "Nereye dönerseniz, orada Allahü teâlâyı bulursunuz!"}, {"kisim": 3, "madde": 28, "metin": "Nisâ sûresi, kırksekiz ve yüzonaltıncı âyet-i kerîmelerinde meâlen, (Allahü teâlâ, müşriki afv etmiyecekdir)", "arama": "Allahü teâlâ, müşriki afv etmiyecekdir"}, {"kisim": 3, "madde": 29, "metin": "Furkân sûresi, yetmişinci âyetinde meâlen, (Allahü teâlânın, günâhlarını iyiliklerle değişdireceği kimseler, onlardır. Allahü teâlânın magfireti, merhameti sonsuzdur)", "arama": "Allahü teâlânın, günâhlarını iyiliklerle değişdireceği kimse"}, {"kisim": 3, "madde": 30, "metin": "âlen, (Bizim gibi bir insan mı bize yol gösterecek, diyerek kâfir oldular) ve Furkân sûresinde, yedinci âyetinde meâlen, (Bu nasıl Peygamberdir? Bizim gibi yiyor ve sokaklarda dolaşıyor dediler)", "arama": "Bu nasıl Peygamberdir? Bizim gibi yiyor ve sokaklarda dolaşı"}, {"kisim": 3, "madde": 33, "metin": "Fussılet sûresinde, dokuzuncu âyetde meâlen, (Yer küresini iki günde yaratdı)", "arama": "Yer küresini iki günde yaratdı"}, {"kisim": 3, "madde": 33, "metin": "Nitekim, Hûd sûresinde, yedinci âyet-i kerîmede meâlen, (Allahü teâlâ, gökleri ve yeri altı günde yaratdı ve Arşı, su üzerinde idi)", "arama": "Allahü teâlâ, gökleri ve yeri altı günde yaratdı ve Arşı, su"}, {"kisim": 3, "madde": 33, "metin": "Kürsîye gelince, Bekara sûresi, ikiyüzellibeşinci âyeti olan Âyet-el-kürsîde meâlen, (Onun Kürsîsi, göklerden ve yerden genişdir)", "arama": "Onun Kürsîsi, göklerden ve yerden genişdir"}, {"kisim": 3, "madde": 37, "metin": "Zümer sûresinde, meâli, (Kalbleri Allahü teâlâyı zikr etmiyenlere azâb vardır)", "arama": "Kalbleri Allahü teâlâyı zikr etmiyenlere azâb vardır"}, {"kisim": 3, "madde": 37, "metin": "54] âyetinde meâlen, (Rabbinizi, yalvararak ve gizli ve sessiz çağırınız) ve Ra’d sûresi, otuzuncu [30] âyetinde meâlen, (Biliniz ki, kalbler, yalnız Allahü teâlâyı zikr etmekle râhat bulur)", "arama": "Biliniz ki, kalbler, yalnız Allahü teâlâyı zikr etmekle râha"}, {"kisim": 3, "madde": 37, "metin": "ve A’râf sûresi ikiyüzdördüncü [204] âyetinde meâlen, (Rabbini, içinden zikr et!)", "arama": "Rabbini, içinden zikr et!"}, {"kisim": 3, "madde": 37, "metin": "râbıta, Tevbe sûresinin yüzyirminci âyetinin, (Hep sâdıklarla birlikde bulunun!) ve En’âm sûresinin elliikinci âyetinin, (Rablerini istiyenlerle berâber olmağa çalış!)", "arama": "Rablerini istiyenlerle berâber olmağa çalış!"}, {"kisim": 3, "madde": 37, "metin": "meâllerinde emr olunan berâberlikdir ve (Allahü teâlânın sevdiklerini hâtırlamak, rahmet etmesine sebeb olur)", "arama": "Allahü teâlânın sevdiklerini hâtırlamak, rahmet etmesine seb"}, {"kisim": 3, "madde": 37, "metin": "ci âyetinde, (Ona kavuşmak için, vesîle, vâsıta arayınız!)", "arama": "Ona kavuşmak için, vesîle, vâsıta arayınız!"}, {"kisim": 3, "madde": 43, "metin": "Mücâdele sûresinin, ondokuzuncu âyetinde meâlen, (Şeytânın askeri elbette mağlûb olacak, ziyân edecekdir)", "arama": "Şeytânın askeri elbette mağlûb olacak, ziyân edecekdir"}, {"kisim": 3, "madde": 44, "metin": "Kendilerinde seyr etdikleri için, Zâriyât sûresinin (Kendinizde bulunmakdadır, niçin görmüyorsunuz?)", "arama": "Kendinizde bulunmakdadır, niçin görmüyorsunuz?"}, {"kisim": 3, "madde": 50, "metin": "Meâl-i şerîfi (Allahü teâlâ, îmân edenlerin velîsidir)", "arama": "Allahü teâlâ, îmân edenlerin velîsidir"}, {"kisim": 3, "madde": 50, "metin": "Çünki, Mâide sûresinde, (Ona kavuşmak için vesîle arayınız!)", "arama": "Ona kavuşmak için vesîle arayınız!"}, {"kisim": 3, "madde": 51, "metin": "(Şûra) sûresindeki âyet-i kerîmede meâlen, (Allahü teâlâ, dilediğini kendine seçer, kendine kavuşmak isteyenlere de, kavuşduran yolu gösterir)", "arama": "Allahü teâlâ, dilediğini kendine seçer, kendine kavuşmak ist"}, {"kisim": 3, "madde": 51, "metin": "Yûnüs sûresindeki âyet-i kerîmede meâlen, (Belki anlamadıkları için inanmıyorlar. Onun sözünün özünü anlamadılar. Bunlardan önce olanlar da, böyle inanmamışlardı)", "arama": "Belki anlamadıkları için inanmıyorlar. Onun sözünün özünü an"}, {"kisim": 3, "madde": 52, "metin": "Yasîn sûresi, son âyetinin meâl-i şerîfi, (Biz istediğimiz şeye ol deriz, hemen var olur)", "arama": "Biz istediğimiz şeye ol deriz, hemen var olur"}, {"kisim": 3, "madde": 55, "metin": "(Tefsîr-i Mazherî) sâhibi “rahmetullahi teâlâ aleyh”, (Talâk) sûresinin üçüncü âyetinin tefsîrinde buyuruyor ki, (İmâm-ı Rabbânî “rahmetullahi teâlâ aleyh”, din ve dünyâ zararlarından kurtulmak için, hergün beşyüz kerre (Lâ havle velâ kuvvete illâ billah)", "arama": "İmâm-ı Rabbânî “rahmetullahi teâlâ aleyh”, din ve dünyâ zara"}, {"kisim": 3, "madde": 70, "metin": "Meselâ Zümer sûresi, dokuzuncu âyetinde meâlen, (Bilen ile bilmiyen hiç bir olur mu? Bilen elbette kıymetlidir)", "arama": "Bilen ile bilmiyen hiç bir olur mu? Bilen elbette kıymetlidi"}, {"kisim": 3, "madde": 70, "metin": "Allahü teâlâ, Âl-i İmrân sûresinin otuzbirinci âyetinde, meâlen buyuruyor ki, (Onlara söyle! Eğer Allahı seviyorsanız, bana tâbi’ olunuz! Allah, bana tâbi’ olanları sever)", "arama": "Onlara söyle! Eğer Allahı seviyorsanız, bana tâbi’ olunuz! A"}, {"kisim": 3, "madde": 70, "metin": "Tevbe sûresi, yüzyirminci âyetinde meâlen, (Ey mü’minler! Dâimâ, her zemân, sâdıklar ile birlikde bulunun!)", "arama": "Ey mü’minler! Dâimâ, her zemân, sâdıklar ile birlikde bulunu"}, {"kisim": 3, "madde": 70, "metin": "Meâl-i şerîfi, (Onların sana bakdıklarını görürsün. Onlar, seni anlıyamıyorlar. Üstünlüğünü göremiyorlar)", "arama": "Onların sana bakdıklarını görürsün. Onlar, seni anlıyamıyorl"}], "hadisler": [{"kisim": 1, "madde": 1, "metin": "(Hadîka)da, (Bid’at sâhiblerinin ibâdetleri kabûl olmaz) hadîs-i şerîfini anlatırken buyuruyor ki, (Günâhlardan sakınmayan müslimânların ibâdetleri sahîh olsa da kabûl olmaz)", "arama": "Günâhlardan sakınmayan müslimânların ibâdetleri sahîh olsa d"}, {"kisim": 1, "madde": 1, "metin": "Hadîs-i şerîfde, (Allahü teâlâ, sizin sûretlerinize, mallarınıza, bakmaz. Kalblerinize ve amellerinize bakar)", "arama": "Allahü teâlâ, sizin sûretlerinize, mallarınıza, bakmaz. Kalb"}, {"kisim": 1, "madde": 1, "metin": "(Dürr-ül-muhtâr)daki hadîs-i şerîfde, (Bir sâat ilm öğrenmek veyâ öğretmek, sabâha kadar ibâdet etmekden dahâ sevâbdır)", "arama": "Bir sâat ilm öğrenmek veyâ öğretmek, sabâha kadar ibâdet etm"}, {"kisim": 1, "madde": 8, "metin": "Hâlbuki, Peygamberimiz “aleyhisselâm” buyurdu ki, (Kur’ân-ı kerîmden kendi aklı ile, kendi düşüncesi ve bilgisi ile ma’nâ çıkaran kâfirdir)", "arama": "Kur’ân-ı kerîmden kendi aklı ile, kendi düşüncesi ve bilgisi"}, {"kisim": 1, "madde": 11, "metin": "Hadîs-i şerîfde, (Oğullarınıza yüzmek ve ok atmak öğretiniz! Kadınların, evinde iplik iğirmesi ne güzel eğlencedir)", "arama": "Oğullarınıza yüzmek ve ok atmak öğretiniz! Kadınların, evind"}, {"kisim": 1, "madde": 11, "metin": "İkinci kısmda yirmialtıncı maddeye bakınız! İmâm-ı Alî “radıyallahü anh” buyurdu ki, (Müslimânlar, âhırete inanıyor. Kitâbsız kâfirler, inkâr ediyor. Tekrâr dirilmek olmasaydı, inanmıyanlar birşey kazanmaz, müslimânlar da, zarar etmezdi. Fekat, kâfirlerin dediği olmayınca, sonsuz azâb çekeceklerdir)", "arama": "Müslimânlar, âhırete inanıyor. Kitâbsız kâfirler, inkâr ediy"}, {"kisim": 1, "madde": 18, "metin": "[Peygamberimiz “sallallahü aleyhi ve sellem” buyuruyor ki, (Hepiniz bir sürünün çobanı gibisiniz. Çoban sürüsünü koruduğu gibi, siz de evlerinizde ve emrleriniz altında olanları Cehennemden korumalısınız! Onlara müslimânlığı öğretmelisiniz! Öğretmez iseniz mes’ûl olacaksınız)", "arama": "Hepiniz bir sürünün çobanı gibisiniz. Çoban sürüsünü koruduğ"}, {"kisim": 1, "madde": 18, "metin": "Bir kerre de buyurdu ki, (Çok müslimân evlâdı, babaları yüzünden Veyl ismindeki Cehenneme gideceklerdir. Çünki, bunların babaları, yalnız para kazanmak ve keyf sürmek hırsına düşüp ve yalnız dünyâ işleri arkasında koşup, evlâdlarına müslimânlığı ve Kur’ân-ı kerîmi öğretmediler. Ben böyle babalardan uzağım. Onlar da, benden uzakdır. Çocuklarına dinlerini öğretmiyenler, Cehenneme gideceklerdir)", "arama": "Çok müslimân evlâdı, babaları yüzünden Veyl ismindeki Cehenn"}, {"kisim": 1, "madde": 18, "metin": "Yine buyurdu ki, (Çocuklarına Kur’ân-ı kerîm öğretenlere veyâ Kur’ân-ı kerîm hocasına gönderenlere, öğretilen Kur’ânın her harfi için, on kerre Kâ’be-i mu’azzama ziyâreti sevâbı verilir ve kıyâmet günü, başına devlet tâcı konur. Bütün insanlar görüp imrenir)", "arama": "Çocuklarına Kur’ân-ı kerîm öğretenlere veyâ Kur’ân-ı kerîm h"}, {"kisim": 1, "madde": 18, "metin": "Yine buyurdu ki, (Çocuklarınıza nemâz kılmasını öğretiniz. Yedi yaşına gelince, nemâzı emr ediniz. On yaşına gelince kılmazlar ise, döverek kıldırınız)", "arama": "Çocuklarınıza nemâz kılmasını öğretiniz. Yedi yaşına gelince"}, {"kisim": 1, "madde": 18, "metin": "Yine buyurdu ki, (Bir müslimânın evlâdı ibâdet edince, kazandığı sevâb kadar, babasına da verilir. Bir kimse, çocuğuna fısk, günâh öğretirse, bu çocuk ne kadar günâh işlerse, babasına da o kadar günâh yazılır)", "arama": "Bir müslimânın evlâdı ibâdet edince, kazandığı sevâb kadar, "}, {"kisim": 1, "madde": 18, "metin": "(Mürşid-ün-nisâ)daki hadîs-i şerîfde, (Zevcesinin ve çocuklarının haklarını îfâ etmiyenin nemâzları, orucları kabûl olmaz)", "arama": "Zevcesinin ve çocuklarının haklarını îfâ etmiyenin nemâzları"}, {"kisim": 1, "madde": 18, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyuruyor ki, (Birbirinize müslimânlığı öğretiniz. Emr-i ma’rûfu bırakır iseniz, Allahü teâlâ, en kötünüzü başınıza musallat eder ve düâlarınızı kabûl etmez)", "arama": "Birbirinize müslimânlığı öğretiniz. Emr-i ma’rûfu bırakır is"}, {"kisim": 1, "madde": 18, "metin": "Ve buyurdu ki, (Bütün ibâdetlere verilen sevâb, Allah yolunda gazâya verilen sevâba göre, deniz yanında bir damla su gibidir. Gazânın sevâbı da, emr-i ma’rûf ve nehy-i anilmünker sevâbı yanında, denize nazaran bir damla su gibidir)", "arama": "Bütün ibâdetlere verilen sevâb, Allah yolunda gazâya verilen"}, {"kisim": 1, "madde": 19, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Îmânın temeli ve en kuvvetli alâmeti, müslimânları sevmek ve müslimânlara düşmanlık edenleri sevmemekdir).", "arama": "(Îmânın temeli ve en kuvvetli alâmeti, müslimânları sevmek v"}, {"kisim": 1, "madde": 25, "metin": "Okurken, hadîs-i şerîfe gelince, durmuş ve (Burası, yukarısına benzemiyor. Buradaki san’at dahâ yüksek)", "arama": "Burası, yukarısına benzemiyor. Buradaki san’at dahâ yüksek"}, {"kisim": 1, "madde": 31, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Ümmetimden büyük günâhları olanlara şefâ’at edeceğim)", "arama": "Ümmetimden büyük günâhları olanlara şefâ’at edeceğim"}, {"kisim": 1, "madde": 31, "metin": "İmâm-ı a’zam “aleyhirrahme” buyurdu ki, (O kimse yine mü’mindir. Günâh işlemekle, îmânı gitmez)", "arama": "O kimse yine mü’mindir. Günâh işlemekle, îmânı gitmez"}, {"kisim": 1, "madde": 31, "metin": "kuddise sirruh” yine buyurdu ki, Alî “radıyallahü anh” dedi ki, Peygamber “sallallahü aleyhi ve sellem” bana buyurdu ki: (Benden sonra halîfe Ebû Bekr olacakdır. Ondan sonra Ömer, ondan sonra Osmân, ondan sonra da sen “radıyallahü anhüm” olacaksın!)", "arama": "Benden sonra halîfe Ebû Bekr olacakdır. Ondan sonra Ömer, on"}, {"kisim": 1, "madde": 31, "metin": "Nerde kaldı ki, kâfir ve fâsık denilebilsin! Bu muhârebelerde Alî “radıyallahü anh” buyurdu ki, (Kardeşlerimiz bizden ayrıldı. Onlar kâfir, fâsık değildir. Çünki, ictihâdlarına göre hareket ediyorlar)", "arama": "Kardeşlerimiz bizden ayrıldı. Onlar kâfir, fâsık değildir. Ç"}, {"kisim": 1, "madde": 31, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Eshâbıma dil uzatmakdan sakınınız!)", "arama": "Eshâbıma dil uzatmakdan sakınınız!"}, {"kisim": 1, "madde": 31, "metin": "[Büyük âlim, Ebû Bekr-i Şiblî “kuddise sirruh” buyurdu ki: (Eshâb-ı kirâma hurmet etmiyen bir kimse, Muhammed aleyhisselâma îmân etmiş olmaz “radıyallahü teâlâ anhüm ecma’în”.)", "arama": "Eshâb-ı kirâma hurmet etmiyen bir kimse, Muhammed aleyhissel"}, {"kisim": 1, "madde": 31, "metin": "] Hâlbuki birçok hadîs-i şerîflerde buyuruldu ki: (Mehdînin başı hizâsında bir bulut olacakdır. Bulutdan bir melek: Bu Mehdîdir, sözünü dinleyiniz! diyecekdir.)", "arama": "Mehdînin başı hizâsında bir bulut olacakdır. Bulutdan bir me"}, {"kisim": 1, "madde": 31, "metin": "Bir hadîs-i şerîfde buyuruldu ki: (İsmini duyduğunuz kimselerden, yeryüzüne [ya’nî, o zemân bilinen memleketlerin çoğuna] dört kişi mâlik oldu. İkisi mü’min, ikisi de kâfir idi. Mü’min olan iki kişi, Zülkarneyn ile Süleymân “aleyhimesselâm” idi. Kâfir olan ikisi de, Nemrûd ile Buhtunnasar idi. Beşinci olarak, yeryüzüne, benim evlâdımdan biri, ya’nî Mehdî de, mâlik olacakdır)", "arama": "İsmini duyduğunuz kimselerden, yeryüzüne [ya’nî, o zemân bil"}, {"kisim": 1, "madde": 31, "metin": "Bir hadîs-i şerîfde buyuruldu ki: (Kıyâmet kopmadan önce, Allahü teâlâ, benim evlâdımdan birini yaratır ki, ismi benim ismim gibi, babasının ismi, benim babamın ismi gibi olur ve dünyâyı adâletle doldurur. Ondan önce dünyâ zulmle dolu iken, onun zemânında adl ile dolar)", "arama": "Kıyâmet kopmadan önce, Allahü teâlâ, benim evlâdımdan birini"}, {"kisim": 1, "madde": 31, "metin": "Bir hadîs-i şerîfde buyuruldu ki: (Eshâb-ı Kehf, hazret-i Mehdînin yardımcıları olacakdır ve Îsâ “aleyhisselâm” bunun zemânında gökden inecekdir. Îsâ “aleyhisselâm”, Deccâl ile harb ederken, hazret-i Mehdî, onunla berâber olacakdır. Bunun hükümdârlığı zemânında, her zemânkinin aksine olarak ve hesâbların tersine olarak, Ramezân-ı şerîfin ondördüncü günü güneş tutulacakdır ve birinci gecesinde ay tutulacakdır)", "arama": "Eshâb-ı Kehf, hazret-i Mehdînin yardımcıları olacakdır ve Îs"}, {"kisim": 1, "madde": 31, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Benî İsrâîl, yetmişbir fırkaya ayrılmışdı. Bunlardan yetmişi Cehenneme gidip, ancak bir fırkası kurtulmuşdur. Nasârâ da, yetmişiki fırkaya ayrılmışdı. Yetmişbiri Cehenneme gitmişdir. Bir zemân sonra, benim ümmetim de yetmişüç kısma ayrılır. Bunlardan yetmişikisi, Cehenneme gidip, yalnız bir fırkası kurtulur)", "arama": "Benî İsrâîl, yetmişbir fırkaya ayrılmışdı. Bunlardan yetmişi"}, {"kisim": 1, "madde": 31, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Benden sonra müslimânlar arasında çok ayrılık olacakdır. O zemânlarda yaşıyanlar benim yoluma ve Hulefâ-i râşidînin “aleyhimürrıdvân” yoluna yapışsın! Sonradan meydâna çıkan, moda olan şeylerden kaçınsın! Çünki, dinde yenilik, reform yapmak doğru yoldan çıkmakdır. Benden sonra, dinde yapılacak değişikliklerin hepsi dinsizlikdir)", "arama": "Benden sonra müslimânlar arasında çok ayrılık olacakdır. O z"}, {"kisim": 1, "madde": 36, "metin": "Şeyh buyurdu ki, (Öyle ise, şimdiden onlara cevâb hâzırla!) 6 — Kıyâmet günü Allahü teâlâ (Günâhı olanlar, Cehenneme gitsin!)", "arama": "Günâhı olanlar, Cehenneme gitsin!"}, {"kisim": 1, "madde": 36, "metin": "Hadîs-i kudsîde buyuruyor ki, (Önce gelenleriniz, sonra gelenleriniz; küçüğünüz, büyüğünüz; dirileriniz, ölüleriniz; insanlarınız, cinleriniz; en müttekî, itâ’atli kulum gibi olsanız, büyüklüğüm artmaz. Aksine olarak, hepiniz, bana karşı duran, Peygamberlerimi “aleyhimüsselâm” aşağı gören, düşmanım gibi olsanız, ülûhiyyetimden bir şey eksilmez. Allahü teâlâ, sizden ganîdir, Ona hiçbiriniz lâzım değildir. Siz ise, var olmanız için ve varlıkda kala", "arama": "Önce gelenleriniz, sonra gelenleriniz; küçüğünüz, büyüğünüz;"}, {"kisim": 1, "madde": 37, "metin": "e yazılı hadîs-i şerîflerde buyuruyor ki, (Mes’ûd o kimsedir ki, dünyâ onu terk etmezden önce, o dünyâyı terk etmişdir), (Arzûsu âhıret olup, âhıret için çalışana, Allahü teâlâ dünyâyı hizmetci yapar)", "arama": "Arzûsu âhıret olup, âhıret için çalışana, Allahü teâlâ dünyâ"}, {"kisim": 1, "madde": 38, "metin": "Bu hadîs-i şerîfde, Peygamberimiz “sallallahü aleyhi ve sellem”, (Allahü teâlâ, yüzbin Âdem yaratmışdır)", "arama": "Allahü teâlâ, yüzbin Âdem yaratmışdır"}, {"kisim": 1, "madde": 41, "metin": "Resûlullah “sallallahü aleyhi ve sellem”, bir hadîs-i şerîfde, (Îmânında veyâ ibâdetinde bid’at, bozukluk bulunan bir kimseye, Allah için sert bakanın kalbini, Allahü teâlâ îmânla doldurur ve korkudan korur)", "arama": "Îmânında veyâ ibâdetinde bid’at, bozukluk bulunan bir kimsey"}, {"kisim": 1, "madde": 41, "metin": "Şeyh-ul islâm Hirevî Abdüllah Ensârî buyurdu ki, (Sôfiyye arasında emr-i ma’rûfa ve nehy-i münkere nikâr denir)", "arama": "Sôfiyye arasında emr-i ma’rûfa ve nehy-i münkere nikâr denir"}, {"kisim": 1, "madde": 41, "metin": "Nitekim, hadîs-i şerîfde, (Günâh işleyeni, eliniz ile men’ ediniz, buna kuvvetiniz yetmezse, söz ile mâni’ olunuz. Bunu da yapamaz iseniz, kalbiniz ile beğenmeyiniz! Bu ise, îmânın en aşağısıdır)", "arama": "Günâh işleyeni, eliniz ile men’ ediniz, buna kuvvetiniz yetm"}, {"kisim": 1, "madde": 41, "metin": "Nitekim, bir hadîs-i şerîfde, (Allahü teâlâ, Cebrâîl aleyhisselâma, filân şehri yerin dibine geçir, diye emr etdi. Cebrâîl, yâ Rabbî! Bu şehrdeki filânca kulun sana bir ân ısyân etmedi. Hep itâ’at ve ibâdet ediyor deyince, onu da berâber geçir! Zîrâ günâh işleyenleri görünce, bir kerrecik yüzünü değişdirmedi)", "arama": "Allahü teâlâ, Cebrâîl aleyhisselâma, filân şehri yerin dibin"}, {"kisim": 1, "madde": 41, "metin": "Ubeydüllah-i Ahrâr “kuddise sirruh” buyurdu ki, (Kalbe gelen bütün keşfleri, hâlleri bize verseler, fekat kalbimizi Ehl-i sünnet i’tikâdı ile süslemeseler, kendimi mahv olmuş ve hâlimi harâb bilirim. Bütün harâblıkları, felâketleri üzerime yığsalar, lâkin kalbimi Ehl-i sünnet vel-cemâ’at i’tikâdı ile şereflendirseler, hiç üzülmem)", "arama": "Kalbe gelen bütün keşfleri, hâlleri bize verseler, fekat kal"}, {"kisim": 1, "madde": 42, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Dîninizin direği, temeli vera’dır)", "arama": "Dîninizin direği, temeli vera’dır"}, {"kisim": 1, "madde": 42, "metin": "Bir hadîs-i şerîfde, (Hiçbir şey vera’ gibi olamaz)", "arama": "Hiçbir şey vera’ gibi olamaz"}, {"kisim": 1, "madde": 43, "metin": "Peygamberlerin sonuncusu ve en yükseği olan Muhammed “aleyhi ve aleyhimüssalevât” buyuruyor ki, (Kalbimde [envâr-ı ilâhiyyenin gelmesine engel olan] perde hâsıl oluyor. Bunun için hergün, yetmiş kerre istigfâr ediyorum)", "arama": "Kalbimde [envâr-ı ilâhiyyenin gelmesine engel olan] perde hâ"}, {"kisim": 1, "madde": 43, "metin": "[(Tergîb-üs-salât)da diyor ki, Hadîs-i şerîfde buyuruldu ki, (Bir nemâzı özrsüz, vaktinden sonra kılan, seksen hukbe Cehennemde yanacakdır. Bir hukbe seksen senedir. Her senesi üçyüzaltmış gündür. Her günü, seksen dünyâ senesidir)", "arama": "Bir nemâzı özrsüz, vaktinden sonra kılan, seksen hukbe Cehen"}, {"kisim": 1, "madde": 43, "metin": "Bir hadîs-i şerîfde, (Bir kimse, bir günâh işler, sonra pişmân olursa, bu pişmânlığı, günâhına keffâret olur. Ya’nî, afvına sebeb olur)", "arama": "Bir kimse, bir günâh işler, sonra pişmân olursa, bu pişmânlı"}, {"kisim": 1, "madde": 43, "metin": "Bir hadîs-i şerîfde, (Günâhı olan kimse, istigfâr eder ve tevbe eder, sonra bu günâhı tekrâr yapar, sonra yine istigfâr söyler, tevbe eder. Üçüncüye yine yapar ve yine tevbe ederse, dördüncü olarak yapınca, büyük günâh yazılır)", "arama": "Günâhı olan kimse, istigfâr eder ve tevbe eder, sonra bu gün"}, {"kisim": 1, "madde": 43, "metin": "Abdüllah ibni Mubârek buyurdu ki, (Harâm olarak ele geçen bir kuruşu, sâhibine geri vermek, yüz kuruş sadaka vermekden dahâ sevâbdır)", "arama": "Harâm olarak ele geçen bir kuruşu, sâhibine geri vermek, yüz"}, {"kisim": 1, "madde": 43, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Allahü teâlâ buyuruyor ki: Ey kulum! Emr etdiğim farzları yap, insanların en âbidi olursun. Yasak etdiğim harâmlardan sakın, vera’ sâhibi olursun. Verdiğim rızka kanâ’at eyle, insanların en ganîsi olursun, kimseye muhtâc kalmazsın)", "arama": "Allahü teâlâ buyuruyor ki: Ey kulum! Emr etdiğim farzları ya"}, {"kisim": 1, "madde": 43, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” Ebû Hüreyreye “radıyallahü anh” buyurdu ki, (Vera’ sâhibi ol ki, insanların en âbidi olursun!)", "arama": "Vera’ sâhibi ol ki, insanların en âbidi olursun!"}, {"kisim": 1, "madde": 43, "metin": "Ebû Hüreyre “radıyallahü anh” buyurdu ki, (Kıyâmet günü Allahü teâlânın huzûrunda kıymetli olanlar vera’ ve zühd sâhibleridir)", "arama": "Kıyâmet günü Allahü teâlânın huzûrunda kıymetli olanlar vera"}, {"kisim": 1, "madde": 46, "metin": "Resûlullah “sallallahü aleyhi ve sellem” vefâtına yakın, buyurdu ki: (Bana malını, cânını, Ebû Bekr kadar çok fedâ eden, başkası yokdur. Eğer, dost edinseydim, elbette Ebû Bekri dost edinirdim)", "arama": "Bana malını, cânını, Ebû Bekr kadar çok fedâ eden, başkası y"}, {"kisim": 1, "madde": 46, "metin": "Bir hadîs-i şerîfde buyuruldu ki: (Allahü teâlâ, beni size Peygamber gönderdi. İnanmadınız. Ebû Bekr inandı. Bana malı ile, cânı ile yardım etdi. Onu hiç incitmeyin ve Ona hurmet ve ta’zîm edin!)", "arama": "Allahü teâlâ, beni size Peygamber gönderdi. İnanmadınız. Ebû"}, {"kisim": 1, "madde": 46, "metin": "Bir hadîs-i şerîfde buyurdu ki: (Benden sonra Peygamber gelmiyecekdir. Eğer gelseydi, elbette Ömer Peygamber olurdu)", "arama": "Benden sonra Peygamber gelmiyecekdir. Eğer gelseydi, elbette"}, {"kisim": 1, "madde": 46, "metin": "Emîr [Alî] “radıyallahü anh”buyurdu ki: (Ebû Bekr ile Ömerden, her biri, bu ümmetin en yükseğidir. Beni onlardan üstün tutan, iftirâcıdır. İftirâ edenler dövüldüğü gibi, onu döverim)", "arama": "Ebû Bekr ile Ömerden, her biri, bu ümmetin en yükseğidir. Be"}, {"kisim": 1, "madde": 46, "metin": "Bir hadîs-i şerîfde, (Onları seven, beni sevdiği için sever)", "arama": "Onları seven, beni sevdiği için sever"}, {"kisim": 1, "madde": 46, "metin": "Hadîs-i şerîfde, (Onlara düşmanlık eden, bana düşman olduğu için eder)", "arama": "Onlara düşmanlık eden, bana düşman olduğu için eder"}, {"kisim": 1, "madde": 46, "metin": "Resûl-i ekrem “sallallahü aleyhi ve sellem” buyurdu ki: (İslâmın binâsı beş direk üzerine kurulmuşdur. Birincisi, Eşhedü en lâ ilâhe illallah ve eşhedü enne Muhammeden abdühu ve resûlüh, demek ve bunun ma’nâsına inanmakdır)", "arama": "İslâmın binâsı beş direk üzerine kurulmuşdur. Birincisi, Eşh"}, {"kisim": 1, "madde": 46, "metin": "Hadîs-i şerîfde buyuruldu ki, (Kıyâmetde, sahîfesinde çok istigfâr bulunanlara, müjdeler olsun!)", "arama": "Kıyâmetde, sahîfesinde çok istigfâr bulunanlara, müjdeler ol"}, {"kisim": 1, "madde": 46, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Farz nemâzlarından sonra Âyet-el-kürsî okuyan kimse ile Cennet arasında, ölümden başka mâni’ yokdur)", "arama": "Farz nemâzlarından sonra Âyet-el-kürsî okuyan kimse ile Cenn"}, {"kisim": 1, "madde": 46, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Bu düâyı gündüz okuyan, o günün şükrünü yapmış olur. Gece okuyunca, o gecenin şükrünü îfâ etmiş olur)", "arama": "Bu düâyı gündüz okuyan, o günün şükrünü yapmış olur. Gece ok"}, {"kisim": 1, "madde": 46, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Oruc, mü’mini Cehennemden koruyan bir kalkandır)", "arama": "Oruc, mü’mini Cehennemden koruyan bir kalkandır"}, {"kisim": 1, "madde": 46, "metin": "Hadîs-i şerîfde, (Kabûl olan bir hac, geçmiş günâhları yok eder)", "arama": "Kabûl olan bir hac, geçmiş günâhları yok eder"}, {"kisim": 1, "madde": 46, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Âlimlerin uykusu ibâdetdir)", "arama": "Âlimlerin uykusu ibâdetdir"}, {"kisim": 1, "madde": 46, "metin": "(Künûz-üd-dekâık)deki hadîs-i şerîfde, (Herşeyin menba’ı vardır. İhlâsın, takvânın menba’ı, kaynağı, Âriflerin kalbleridir)", "arama": "Herşeyin menba’ı vardır. İhlâsın, takvânın menba’ı, kaynağı,"}, {"kisim": 1, "madde": 46, "metin": "Resûlullah “sallallahü aleyhi ve sellem” vefâtına yakın, buyurdu ki: (Bana malını, cânını, Ebû Bekr kadar çok fedâ eden, başkası yokdur.", "arama": "cânını, Ebû Bekr kadar çok fedâ eden, başkası yokdur."}, {"kisim": 1, "madde": 48, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Ey Eshâbım! Siz öyle bir zemânda geldiniz ki, Allahü teâlânın emrlerinden onda dokuzunu yapıp, birini yapmazsanız, helâk olursunuz, Cehenneme gidersiniz! Bir zemân gelecek ki, o zemânın mü’minleri, emrlerin birini yapabilip, dokuzunu bıraksalar, Cehennemden kurtulurlar. O zemânda îmânı olanlara müjdeler olsun!)", "arama": "Ey Eshâbım! Siz öyle bir zemânda geldiniz ki, Allahü teâlânı"}, {"kisim": 1, "madde": 50, "metin": "Allahü teâlânın Peygamberi “sallallahü aleyhi ve sellem” buyurdu ki: (Bir mü’min nemâz kılmağa başlayınca, Cennet kapıları onun için açılır. Rabbi ile onun arasında bulunan perdeler kalkar. Cennetde olan hûru’în onu karşılar. Bu hâl, nemâz bitinceye kadar devâm eder)", "arama": "Bir mü’min nemâz kılmağa başlayınca, Cennet kapıları onun iç"}, {"kisim": 1, "madde": 54, "metin": "(Ey Oğul İlmihâli)nin doksanbirinci sahîfesinde yazılı hadîs-i şerîfde, (Kirlenince, çabuk gusl abdesti alın! Çünki kirâmen kâtibîn melekleri, cünüb gezen kimseden incinir)", "arama": "Kirlenince, çabuk gusl abdesti alın! Çünki kirâmen kâtibîn m"}, {"kisim": 1, "madde": 54, "metin": "Yine, aynı sahîfede: İmâm-ı Gazâlî buyurdu ki, bir kimse, rü’yâda bana dedi ki, (Bir mikdâr zemân, cünüb kaldım. Şimdi üzerime ateşden gömlek giydirdiler. Hâlâ ateş içindeyim)", "arama": "Bir mikdâr zemân, cünüb kaldım. Şimdi üzerime ateşden gömlek"}, {"kisim": 1, "madde": 58, "metin": "Bir hadîs-i şerîfde buyurdu ki: (Komşu kadına ve arkadaşların kadınlarına şehvet ile bakmak, yabancı kadınlara bakmakdan on kat dahâ günâhdır. Evli kadınlara bakmak, kızlara bakmakdan bin kat dahâ çok günâhdır. Zinâ günâhları da böyledir)", "arama": "Komşu kadına ve arkadaşların kadınlarına şehvet ile bakmak, "}, {"kisim": 1, "madde": 58, "metin": "Bir hadîs-i şerîfde, (Allah için yapılan cihâdda düşmanı gözleyen veyâ Allah korkusundan ağlıyan veyâ harâmlara bakmıyan gözler, kıyâmetde Cehennem ateşini görmiyeceklerdir)", "arama": "Allah için yapılan cihâdda düşmanı gözleyen veyâ Allah korku"}, {"kisim": 1, "madde": 58, "metin": "(Tergîb-üs-salât)daki hadîs-i şerîflerde, (Örtülü olan çıplaklara ve erkek gibi giyinen kadınlara ve kadın gibi giyinen, süslenen erkeklere la’net edildi)", "arama": "Örtülü olan çıplaklara ve erkek gibi giyinen kadınlara ve ka"}, {"kisim": 1, "madde": 58, "metin": "Bir hadîs-i şerîfde, (Ananın ayağını öpmek, Cennet kapısının eşiğini öpmek gibidir)", "arama": "Ananın ayağını öpmek, Cennet kapısının eşiğini öpmek gibidir"}, {"kisim": 1, "madde": 58, "metin": "Hadîs-i şerîflerde buyuruldu ki: (Kıyâmet yaklaşınca, Kur’ân-ı kerîm mizmârdan okunur) ve (Bir zemân gelir ki, Kur’ân-ı kerîm mizmârlardan okunur. Allah için değil, keyf için okunur)", "arama": "Bir zemân gelir ki, Kur’ân-ı kerîm mizmârlardan okunur. Alla"}, {"kisim": 1, "madde": 60, "metin": "(Tergîb-üs-salât)daki hadîs-i şerîfde, (Nemâz vaktlerinin bir evveli vardır. Bir de sonu vardır)", "arama": "Nemâz vaktlerinin bir evveli vardır. Bir de sonu vardır"}, {"kisim": 1, "madde": 60, "metin": "Bu hadîs-i şerîf, (Tulû’ ve gurûb vaktleri hesâb edilirken, güneşin hakîkî ve zâhirî irtifâ’ları değil, şer’î üfukdan olan şer’î irtifâ’larının kullanılacağını)", "arama": "Tulû’ ve gurûb vaktleri hesâb edilirken, güneşin hakîkî ve z"}, {"kisim": 1, "madde": 60, "metin": "(Künûz-üd-dekâık)da yazılı ve Hâkimin ve Tirmüzînin bildirdikleri hadîs-i şerîfde, (İbâdetlerin en kıymetlisi, evvel vaktinde kılınan nemâzdır)", "arama": "İbâdetlerin en kıymetlisi, evvel vaktinde kılınan nemâzdır"}, {"kisim": 1, "madde": 63, "metin": "Bir hadîs-i şerîfde, (Mü’min ile kâfiri ayıran fark, nemâzdır)", "arama": "Mü’min ile kâfiri ayıran fark, nemâzdır"}, {"kisim": 1, "madde": 63, "metin": "Buyurdu ki, (Nemâz kılmıyanlar, kıyâmet günü, Allahü teâlâyı kızgın olarak bulacaklardır)", "arama": "Nemâz kılmıyanlar, kıyâmet günü, Allahü teâlâyı kızgın olara"}, {"kisim": 1, "madde": 63, "metin": "Hadîs-i şerîfde, (Nemâz kılmıyanın, islâmdan nasîbi yokdur!)", "arama": "Nemâz kılmıyanın, islâmdan nasîbi yokdur!"}, {"kisim": 1, "madde": 63, "metin": "(Mişkât)da ve (Künûz-üd-dekâık)da ve (Sahîhayn)de ve (Halebî)de bildirilen hadîs-i şerîfde de, (İnsan ile küfr arasındaki fark, nemâzı terk etmekdir!)", "arama": "İnsan ile küfr arasındaki fark, nemâzı terk etmekdir!"}, {"kisim": 1, "madde": 63, "metin": "Bu hadîs-i şerîf, (İnsan ile ölüm arasındaki fark, nefes almamakdır)", "arama": "İnsan ile ölüm arasındaki fark, nefes almamakdır"}, {"kisim": 1, "madde": 64, "metin": "Hadîs-i şerîfde, (Her nemâzdan sonra, üç kerre, Estagfirullahel’azîm ellezî lâ ilâhe illâ huv el-hayyel-kayyûme ve etûbü ileyh okuyanın, bütün günâhları afv olur)", "arama": "Her nemâzdan sonra, üç kerre, Estagfirullahel’azîm ellezî lâ"}, {"kisim": 1, "madde": 64, "metin": "Hadîs-i şerîfde, (Beş vakt farz nemâzdan sonra yapılan düâ kabûl olur)", "arama": "Beş vakt farz nemâzdan sonra yapılan düâ kabûl olur"}, {"kisim": 1, "madde": 64, "metin": "Çünki, Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Unutulmuş bir sünnetimi meydâna çıkarana yüz şehîd sevâbı vardır)", "arama": "Unutulmuş bir sünnetimi meydâna çıkarana yüz şehîd sevâbı va"}, {"kisim": 1, "madde": 64, "metin": "(Şir’at-ül-islâm) şerhınde diyor ki, (Hadîs-i şerîfde, (Gece seher vaktinde ve nemâzlardan sonra yapılan düâ kabûl olunur)", "arama": "Gece seher vaktinde ve nemâzlardan sonra yapılan düâ kabûl o"}, {"kisim": 1, "madde": 68, "metin": "(Zevâcir)in yirmialtıncı sahîfesindeki hadîs-i şerîfde, (Elinize geçen resmleri yırtınız, bozunuz!)", "arama": "Elinize geçen resmleri yırtınız, bozunuz!"}, {"kisim": 1, "madde": 70, "metin": "Hadîs-i şerîfde, (Müttekî bir âlim ile nemâz kılan, bir Peygamber ile kılmış gibidir)", "arama": "Müttekî bir âlim ile nemâz kılan, bir Peygamber ile kılmış g"}, {"kisim": 1, "madde": 71, "metin": "[Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Bir zemân gelecek maymun sıfatlı, insan sûretli kimseler, minbere çıkıp, sizlere, din aleyhindeki sözleri, dinsizliği, din diye söyliyeceklerdir)", "arama": "Bir zemân gelecek maymun sıfatlı, insan sûretli kimseler, mi"}, {"kisim": 1, "madde": 71, "metin": "Hadîs-i şerîfde buyuruldu ki, (Cum’a günü tırnağını kesen kimse, bir hafta, belâlardan emîn olur)", "arama": "Cum’a günü tırnağını kesen kimse, bir hafta, belâlardan emîn"}, {"kisim": 1, "madde": 71, "metin": "Bu hadîs-i şerîf, (Berîka) ve (Hadîka)da ve Yûsüf Kardâvînin (El-halâl vel-harâm fil-islâm)", "arama": "El-halâl vel-harâm fil-islâm"}, {"kisim": 1, "madde": 71, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir müslimân, Cum’a günü gusl abdesti alıp, Cum’a nemâzına giderse, bir haftalık günâhları afv olur ve her adımı için sevâb verilir)", "arama": "Bir müslimân, Cum’a günü gusl abdesti alıp, Cum’a nemâzına g"}, {"kisim": 1, "madde": 71, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Günlerin en kıymetlisi Cum’adır. Cum’a günü, bayram günlerinden ve aşûre gününden dahâ kıymetlidir. Cum’a, dünyâda ve Cennetde mü’minlerin bayramıdır)", "arama": "Günlerin en kıymetlisi Cum’adır. Cum’a günü, bayram günlerin"}, {"kisim": 1, "madde": 71, "metin": "Bir hadîs-i şerîfde, (Cum’a nemâzı kılmıyanların kalblerini, Allahü teâlâ mühürler. Gâfil olurlar)", "arama": "Cum’a nemâzı kılmıyanların kalblerini, Allahü teâlâ mühürler"}, {"kisim": 1, "madde": 71, "metin": "Bir hadîs-i şerîfde, (Bir kimse, mâni’ yok iken, üç Cum’a nemâzı kılmazsa, Allahü teâlâ, kalbini mühürler. Ya’nî, iyilik yapmaz olur)", "arama": "Bir kimse, mâni’ yok iken, üç Cum’a nemâzı kılmazsa, Allahü "}, {"kisim": 1, "madde": 71, "metin": "usl abdesti alınız! Her akşam abdestli olarak yatınız! Her hâlinizde, Allahü teâlâyı hâtırlayınız!) Bir hadîs-i şerîfde, (Cum’a günlerinde bir ân vardır ki, mü’minin o ânda etdiği düâ red olmaz)", "arama": "Cum’a günlerinde bir ân vardır ki, mü’minin o ânda etdiği dü"}, {"kisim": 1, "madde": 71, "metin": "] Bir hadîs-i şerîfde, (Cum’a nemâzından sonra, yedi def’a İhlâs ve Mu’avvizeteyn okuyanı, Allahü teâlâ, bir hafta, kazâdan, belâdan ve kötü işlerden korur)", "arama": "Cum’a nemâzından sonra, yedi def’a İhlâs ve Mu’avvizeteyn ok"}, {"kisim": 1, "madde": 71, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Cumartesi günleri yehûdîlere, pazar günleri nasârâya verildiği gibi, Cum’a günü, müslimânlara verildi. Bugün, müslimânlara hayr, bereket, iyilik vardır)", "arama": "Cumartesi günleri yehûdîlere, pazar günleri nasârâya verildi"}, {"kisim": 1, "madde": 71, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir müslimân, Cum’a günü gusl abdesti alıp, Cum’a nemâzına giderse, bir haftalık günâhları afv olur ve her adımı için sevâb verilir).", "arama": "Cum’a günü gusl abdesti alıp, Cum’a nemâzına giderse, bir ha"}, {"kisim": 1, "madde": 74, "metin": "Hadîs-i şerîfde, (Bir nemâzı uykuda geçiren veyâ unutan kimse, sonraki nemâzı cemâ’at ile kılarken hâtırlarsa, imâmla nemâzı bitirip, sonra önceki nemâzını kazâ etsin! Bundan sonra, imâmla kıldığını tekrâr kılsın!)", "arama": "Bir nemâzı uykuda geçiren veyâ unutan kimse, sonraki nemâzı "}, {"kisim": 1, "madde": 74, "metin": "Çünki, hadîs-i şerîfde (Allahü teâlânın en çok sevdiği amel, hubb-i fillah ve buğd-ı fillahdır)", "arama": "Allahü teâlânın en çok sevdiği amel, hubb-i fillah ve buğd-ı"}, {"kisim": 1, "madde": 74, "metin": "Alî ibni Ebî Tâlib “radıyallahü anh” bildiriyor: Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Üzerinde farz nemâzı borcu olan kimse, kazâsını kılmadan nâfile kılarsa, boş yere zahmet çekmiş olur. Bu kimse, kazâsını ödemedikçe, Allahü teâlâ, onun nâfile nemâzlarını kabûl etmez)", "arama": "Üzerinde farz nemâzı borcu olan kimse, kazâsını kılmadan nâf"}, {"kisim": 1, "madde": 74, "metin": "Abdülkâdir-i Geylânînin yazdığı bu hadîs-i şerîfi şerh eden Hanefî mezhebi âlimlerinden Abdülhak-ı Dehlevî buyuruyor ki, (Bu haber, farz borcu olanların, sünnetlerinin ve nâfilelerinin kabûl olmıyacağını göstermekdedir. Sünnetlerin, farzları temâmlıyacağını biliyoruz. Bunun ma’nâsı, farzlar yapılırken, bunların kemâllerine sebeb olan birşey kaçırılırsa, sünnetler, kılınan farzın kemâl bulmasına sebeb olur. Farz borcu olanın kabûl edilmiyen sünnet", "arama": "Bu haber, farz borcu olanların, sünnetlerinin ve nâfilelerin"}, {"kisim": 1, "madde": 74, "metin": "İbni Âbidîn de, nâfile bahsinde buyuruyor ki, (Hadîs-i şerîfde, (Temâm yapılmamış olan nemâz, zekât ve başka farzlar, nâfileler ile temâmlanacakdır)", "arama": "Temâm yapılmamış olan nemâz, zekât ve başka farzlar, nâfilel"}, {"kisim": 1, "madde": 74, "metin": "Çünki, başka bir hadîs-i şerîfde, (Bir kimse, nemâzını temâmlamadı ise, o nemâzın üzerine, temâmlanıncaya kadar, nâfile nemâzları eklenir)", "arama": "Bir kimse, nemâzını temâmlamadı ise, o nemâzın üzerine, temâ"}, {"kisim": 1, "madde": 74, "metin": "Hadîs-i kudsîde, (Bir kimse, kendisine farz yapdığım ibâdeti yapmakla bana yaklaşdığı gibi, hiçbirşeyle yaklaşamaz)", "arama": "Bir kimse, kendisine farz yapdığım ibâdeti yapmakla bana yak"}, {"kisim": 1, "madde": 74, "metin": "Başka bir hadîs-i şerîfde, (Yasak edilmiş şeyin zerresini yapmamak, bütün insanların ve cinnin ibâdetlerinden dahâ çok sevâbdır)", "arama": "Yasak edilmiş şeyin zerresini yapmamak, bütün insanların ve "}, {"kisim": 1, "madde": 74, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Bir nemâzı, vakti çıkdıkdan sonra kılan kimseyi, Allahü teâlâ, seksen hukbe Cehennemde bırakacakdır)", "arama": "Bir nemâzı, vakti çıkdıkdan sonra kılan kimseyi, Allahü teâl"}, {"kisim": 1, "madde": 74, "metin": "Bir hadîs-i şerîfde buyurdu ki, (Kıyâmet günü, îmândan sonra, ilk süâl nemâzdan olacakdır)", "arama": "Kıyâmet günü, îmândan sonra, ilk süâl nemâzdan olacakdır"}, {"kisim": 1, "madde": 74, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Bir nemâzı, bilerek, özrsüz kılmıyan kimse, seksen hukbe Cehennemde kalacakdır!)", "arama": "Bir nemâzı, bilerek, özrsüz kılmıyan kimse, seksen hukbe Ceh"}, {"kisim": 1, "madde": 74, "metin": "Hadîs-i şerîfde, (Büyük günâh işleyenlere şefâ’at edeceğim)", "arama": "Büyük günâh işleyenlere şefâ’at edeceğim"}, {"kisim": 1, "madde": 74, "metin": "kınız! [(Ümmetimin arasında fitne, fesâd yayıldığı zemân, sünnetime sarılana yüz şehîd sevâbı vardır) hadîs-i şerîfi de, (Selef-i sâlihîn zemânındaki îmân ve ahkâm-ı islâmiyye bilgilerine uyan kimseye yüz şehîd sevâbı vardır)", "arama": "Selef-i sâlihîn zemânındaki îmân ve ahkâm-ı islâmiyye bilgil"}, {"kisim": 1, "madde": 74, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Üzerinde farz nemâzı borcu olan kimse, kazâsını kılmadan nâfile kılarsa, boş yere zahmet çekmiş olur.", "arama": "(Üzerinde farz nemâzı borcu olan kimse, kazâsını kılmadan nâ"}, {"kisim": 1, "madde": 77, "metin": "Bir def’a da buyurdu ki, (Rükü’da ve secdelerde, belini yerine yerleşdirip biraz durmayan kimsenin nemâzını Allahü teâlâ kabûl etmez)", "arama": "Rükü’da ve secdelerde, belini yerine yerleşdirip biraz durma"}, {"kisim": 1, "madde": 77, "metin": "Yine buyurdu ki, (Sizlerden biriniz, nemâz kılarken, rükü’dan sonra temâm kalkıp, dik durmadıkca ve ayakda, her uzv yerine yerleşip durmadıkca nemâzı temâm olmaz)", "arama": "Sizlerden biriniz, nemâz kılarken, rükü’dan sonra temâm kalk"}, {"kisim": 1, "madde": 77, "metin": "Bir kerre de buyurdu ki, (İki secde arasında dik oturmadıkca, nemâzınız temâm olmaz)", "arama": "İki secde arasında dik oturmadıkca, nemâzınız temâm olmaz"}, {"kisim": 1, "madde": 77, "metin": "erkânına riâyet etmediğini, rükü’dan kalkınca, dikilip durmadığını ve iki secde arasında oturmadığını görüp, buyurdu ki, (Eğer nemâzlarını böyle kılarak ölürsen, kıyâmet günü, sana benim ümmetimden demezler)", "arama": "Eğer nemâzlarını böyle kılarak ölürsen, kıyâmet günü, sana b"}, {"kisim": 1, "madde": 77, "metin": "Ebû Hüreyre “radıyallahü anh” buyurdu ki, (Altmış sene, bütün nemâzlarını kılıp da, hiçbir nemâzı kabûl olmıyan kimse, rükü’ ve secdelerini temâm yapmıyan kimsedir)", "arama": "Altmış sene, bütün nemâzlarını kılıp da, hiçbir nemâzı kabûl"}, {"kisim": 1, "madde": 77, "metin": "Hadîs-i şerîfde (Müslimânların kabri Cennet bağçelerindendir)", "arama": "Müslimânların kabri Cennet bağçelerindendir"}, {"kisim": 1, "madde": 77, "metin": "Hadîs-i şerîfde buyuruldu ki, (Bir yere gelen kimse E’ûzü bikelimâtillâhit-tâmmâti min şerri mâ haleka okursa, o yerden kalkıncaya kadar, ona hiçbirşey zarar, kötülük yapmaz)", "arama": "Bir yere gelen kimse E’ûzü bikelimâtillâhit-tâmmâti min şerr"}, {"kisim": 1, "madde": 78, "metin": "Hadîs-i şerîfde, (Allahü teâlâ, iyilik edenlere, karşılığını elbette verecekdir)", "arama": "Allahü teâlâ, iyilik edenlere, karşılığını elbette verecekdi"}, {"kisim": 1, "madde": 78, "metin": "Hadîs-i şerîfde, (Zekât vererek, malınızı zarardan koruyunuz!)", "arama": "Zekât vererek, malınızı zarardan koruyunuz!"}, {"kisim": 1, "madde": 78, "metin": "(Sahîh-i Müslim)deki bir hadîs-i şerîfde, (Ey Âdem oğlu! Benim malım, benim malım dersin. O maldan senin olan, yiyerek yok etdiğin, giyerek eskitdiğin ve Allah için vererek, sonsuz yaşatdığındır)", "arama": "Ey Âdem oğlu! Benim malım, benim malım dersin. O maldan seni"}, {"kisim": 1, "madde": 78, "metin": "Resûlullah “sallallahü aleyhi ve sellem”, vedâ’ haccında buyurdu ki, (Malınızın zekâtını veriniz! Biliniz ki, zekâtını vermiyenlerin, nemâzı, orucu, haccı ve cihâdı ve îmânı yokdur).", "arama": "(Malınızın zekâtını veriniz! Biliniz ki, zekâtını vermiyenle"}, {"kisim": 1, "madde": 79, "metin": "(Sahîh-i Buhârî)deki bir hadîs-i şerîfde buyuruldu ki: (Bir kimse, Ramezân ayında oruc tutmağı farz bilir, vazîfe bilir ve orucun sevâbını, Allahü teâlâdan beklerse, geçmiş günâhları afv olur)", "arama": "Bir kimse, Ramezân ayında oruc tutmağı farz bilir, vazîfe bi"}, {"kisim": 1, "madde": 79, "metin": "(Merâkıl-felâh)daki hadîs-i şerîfde, (Ayı görünce oruc tutunuz! Tekrâr görünce, orucu bırakınız!)", "arama": "Ayı görünce oruc tutunuz! Tekrâr görünce, orucu bırakınız!"}, {"kisim": 1, "madde": 79, "metin": "Orucu ta’rîf ederken yazdığı (Oradan gece başlayınca iftâr edilir) hadîs-i şerîfinin (Şark tarafında karanlık başlayınca iftâr edilir)", "arama": "Şark tarafında karanlık başlayınca iftâr edilir"}, {"kisim": 1, "madde": 81, "metin": "Bir hadîs-i şerîfde, (Hasîslerin en kötüsü, [kesmesi vâcib olduğu hâlde] kurban kesmiyendir)", "arama": "Hasîslerin en kötüsü, [kesmesi vâcib olduğu hâlde] kurban ke"}, {"kisim": 1, "madde": 83, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Tüccârın, pazarcıların çoğu fâcirdir!) Sebebini sorduklarında, (Alış-verişleri halâl olmaz. Çünki, çok yemîn ederek günâha girerler ve yalan söylerler)", "arama": "Alış-verişleri halâl olmaz. Çünki, çok yemîn ederek günâha g"}, {"kisim": 1, "madde": 83, "metin": "Bir hadîs-i şerîfde, (Yalan yere yemîn ederek, birinin malını alan kimse, kıyâmet günü, Allahü teâlâyı gadablı görecekdir)", "arama": "Yalan yere yemîn ederek, birinin malını alan kimse, kıyâmet "}, {"kisim": 1, "madde": 83, "metin": "[Üçüncü kısm, onbeşinci maddede, ikinci sahîfeye bakınız!] Bir hadîs-i şerîfde, (Îmân sâhibi, her kabâhati yapabilir. Fekat, hiyânet yapamaz ve yalan söyliyemez)", "arama": "Îmân sâhibi, her kabâhati yapabilir. Fekat, hiyânet yapamaz "}, {"kisim": 1, "madde": 83, "metin": "ve bir hadîs-i şerîfde de, (Yalan üç yerde câiz olur: Harbde [ve her zemân, din düşmanlarının zararından korunmak veyâ müslimânları korumak için]. İkincisi, iki müslimânı barışdırmak için, birinden diğerine iyi lâf getirmek. Üçüncüsü, zevcelerini idâre etmek için)", "arama": "Yalan üç yerde câiz olur: Harbde [ve her zemân, din düşmanla"}, {"kisim": 1, "madde": 83, "metin": "Bir hadîs-i şerîfde de, (Yalan yemîn ederek bir müslimânın hakkını alan kimsenin gideceği yer, Cehennemdir)", "arama": "Yalan yemîn ederek bir müslimânın hakkını alan kimsenin gide"}, {"kisim": 1, "madde": 83, "metin": "Ebû Dâvüddeki hadîs-i şerîfde, (Emânet, ya’nî nâmus için yemîn eden, bizden değildir)", "arama": "Emânet, ya’nî nâmus için yemîn eden, bizden değildir"}, {"kisim": 1, "madde": 83, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Tüccârın, pazarcıların çoğu fâcirdir!) Sebebini sorduklarında, (Alış-verişleri halâl olmaz.", "arama": "pazarcıların çoğu fâcirdir!) Sebebini sorduklarında, (Alış-v"}, {"kisim": 1, "madde": 84, "metin": "(Künûz-üd-dekâık)da yazılı Bezzârın bildirdiği hadîs-i şerîfde, (Kadın, yanında bir mahremi olmadan hacca gidemez!)", "arama": "Kadın, yanında bir mahremi olmadan hacca gidemez!"}, {"kisim": 1, "madde": 84, "metin": "Ebû Hüreyrenin haber verdiği hadîs-i şerîfde, (Mescidimi Yemendeki San’â şehrine kadar genişletseler, hepsi mescidim olur)", "arama": "Mescidimi Yemendeki San’â şehrine kadar genişletseler, hepsi"}, {"kisim": 1, "madde": 85, "metin": "hîfede, Alî “radıyallahü anh” aşağıdaki hadîs-i şerîfi haber verdi: Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Farz nemâzı kılmamış olanın nâfile nemâzları kılması, vakti temâm olmuş hâmile kadına benzer. Çocuğu olacağı günlerde, çocuğu düşürür, aldırır. Çocuğu yok olduğu için, bu kadına, hâmile denemez. Ana da denemez. Bu kimse de böyledir. Farz nemâzlarını ödemedikce, Allahü teâlâ, nâfile nemâzlarını kabûl etmez)", "arama": "Farz nemâzı kılmamış olanın nâfile nemâzları kılması, vakti "}, {"kisim": 1, "madde": 85, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Farz nemâzı kılmamış olanın nâfile nemâzları kılması, vakti temâm olmuş hâmile kadına benzer.", "arama": "(Farz nemâzı kılmamış olanın nâfile nemâzları kılması, vakti"}, {"kisim": 1, "madde": 90, "metin": "Hadîs-i şerîfde, (Tanıdığınız ve tanımadığınız müslimânlara selâm veriniz!)", "arama": "Tanıdığınız ve tanımadığınız müslimânlara selâm veriniz!"}, {"kisim": 1, "madde": 90, "metin": "krem “sallallahü aleyhi ve sellem” Medîneye hicret buyurduğu zemân, mubârek ağzından ilk işitdiğim hadîs-i şerîf şu idi: (Birbirinize selâm veriniz! Birbirinize yiyecek ikrâm ediniz! Akrabânızın haklarını gözetiniz! Gece, herkes uyurken nemâz kılınız! Bunları yaparak, selâmetle Cennete giriniz!)", "arama": "Birbirinize selâm veriniz! Birbirinize yiyecek ikrâm ediniz!"}, {"kisim": 1, "madde": 94, "metin": "Bir hadîs-i şerîfde, Rabbinden şöyle nakl etdi: (Yedi kat göklerin ve bunlarda bulunanların ve yedi kat yerin hepsi, Lâ ilâhe illallah kelimesi ile ölçülse, bu kelimenin sevâbı dahâ çok olur)", "arama": "Yedi kat göklerin ve bunlarda bulunanların ve yedi kat yerin"}, {"kisim": 1, "madde": 95, "metin": "aleyhi ve sellem”, en çok sevdiği üç Eshâbının üzülmesini hiç istemediğinden, onları sevindirmek için, hemen buyurdu ki, (Yâ Ömer! Kızını, Ebû Bekrden ve Osmândan “radıyallahü anhüm” dahâ iyi birisine versem ister misin?)", "arama": "Yâ Ömer! Kızını, Ebû Bekrden ve Osmândan “radıyallahü anhüm”"}, {"kisim": 1, "madde": 96, "metin": "Ebû Sa’îd-i Hudrî “radıyallahü anh” buyurdu ki, (Resûlullahın “sallallahü aleyhi ve sellem” hayâsı, bâkire islâm kızlarının hayâlarından dahâ çokdu)", "arama": "Resûlullahın “sallallahü aleyhi ve sellem” hayâsı, bâkire is"}, {"kisim": 1, "madde": 97, "metin": "3 — Tirmizînin bildirdiği hadîs-i şerîfde, (Allahü teâlâ, insanları yaratdı. Beni insanların en iyi kısmından vücûde getirdi. Sonra, bu kısmlarından en iyisini Arabistânda yetişdirdi. Beni bunlardan vücûde getirdi. Sonra evlerden, âilelerden en iyilerini seçip, beni bunlardan meydâna getirdi. O hâlde, benim rûhum ve cesedim, mahlûkların en iyisidir. Benim silsilem, ecdâdım en iyi insanlardır)", "arama": "Allahü teâlâ, insanları yaratdı. Beni insanların en iyi kısm"}, {"kisim": 1, "madde": 97, "metin": "(Envâr-ül-Muhammediyye)de diyor ki, hazret-i Alînin “radıyallahü teâlâ anh” bildirdiği hadîs-i şerîfde, (Âdem aleyhisselâmdan babam Abdüllaha gelinceye kadar, hep nikâhlı ana babalardan geldim. Hiçbir babamın nikâhsız, ya’nî zinâ ile çocuğu olmadı)", "arama": "Âdem aleyhisselâmdan babam Abdüllaha gelinceye kadar, hep ni"}, {"kisim": 1, "madde": 97, "metin": "Hadîs-i şerîfde, (Ben sizin en iyiniz olduğum gibi, babam da, babalarınızdan dahâ iyidir)", "arama": "Ben sizin en iyiniz olduğum gibi, babam da, babalarınızdan d"}, {"kisim": 1, "madde": 98, "metin": "3 — Hadîs ilmi mütehassısı meşhûr Taberânî diyor ki, Abdüllah ibni Abbâs “radıyallahü teâlâ anhümâ” buyurdu ki, (Resûlullah “sallallahü aleyhi ve sellem” nemâzda, selâm vermeden evvel, Sübhâne rabbike âyet-i kerîmesini okurdu)", "arama": "Resûlullah “sallallahü aleyhi ve sellem” nemâzda, selâm verm"}, {"kisim": 1, "madde": 98, "metin": "7 — İbni Hibbân, Ebû Şa’bîden alarak diyor ki, (Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Kıyâmet günü büyük ölçeklerle, bol sevâb kazanmak istiyen kimse, bir meclisden kalkınca Sübhâne rabbike âyet-i kerîmesini okusun!)", "arama": "Kıyâmet günü büyük ölçeklerle, bol sevâb kazanmak istiyen ki"}, {"kisim": 1, "madde": 98, "metin": "Hadîs-i kudsîde de, (Bir kulum bana yaklaşırsa, ona sesleri duyurur ve saklı şeyleri gösteririm)", "arama": "Bir kulum bana yaklaşırsa, ona sesleri duyurur ve saklı şeyl"}, {"kisim": 1, "madde": 98, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse nemâz sonunda, üç def’a Sübhâne rabbike âyet-i kerîmesini okursa, yetişir mikdârda sevâba kavuşur).", "arama": "(Bir kimse nemâz sonunda, üç def’a Sübhâne rabbike âyet-i ke"}, {"kisim": 1, "madde": 98, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Kıyâmet günü büyük ölçeklerle, bol sevâb kazanmak istiyen kimse, bir meclisden kalkınca Sübhâne rabbike âyet-i kerîmesini okusun!).", "arama": "(Kıyâmet günü büyük ölçeklerle, bol sevâb kazanmak istiyen k"}, {"kisim": 2, "madde": 1, "metin": "Peygamberimiz “aleyhi ve alâ âlihissalâtü vesselâm” buyurdu ki, (Kıyâmet yaklaşdıkca, fitneler çoğalır. Gece başlarken karanlığın artması gibi olur. Sabâh evinden mü’min olarak çıkan çok kimse akşam kâfir olarak döner. Akşam mü’min iken, gece safâlarında îmânları gider. Böyle zemânlarda, evinde kapanmak fitneye karışmakdan hayrlıdır. Kenârda kalan, ileri atılandan hayrlıdır. O gün oklarınızı kırınız! Silâhlarınızı, kılınclarınızı bırakınız! Herke", "arama": "Kıyâmet yaklaşdıkca, fitneler çoğalır. Gece başlarken karanl"}, {"kisim": 2, "madde": 2, "metin": "Hep doğru söyleyici, (Muhbir-i sâdık) “aleyhi minessalevâti etemmühâ” buyurdu ki, (Kıyâmet günü, şehîdlerin kanını, âlimlerin mürekkebi ile dartarlar. Mürekkeb ağır gelir)", "arama": "Kıyâmet günü, şehîdlerin kanını, âlimlerin mürekkebi ile dar"}, {"kisim": 2, "madde": 4, "metin": "] Hadîs-i şerîfde, (Lâ ilâhe illallah ehline kâfir demeyiniz! Bunlara kâfir diyenin kendisi kâfir olur)", "arama": "Lâ ilâhe illallah ehline kâfir demeyiniz! Bunlara kâfir diye"}, {"kisim": 2, "madde": 5, "metin": "İmâm-ı Şâfi’î yine buyurdu ki, (Ehl-i sünnet i’tikâdını iyi öğrenmeden önce ilm-i kelâm ile uğraşmanın zararı bilinmiş olsaydı, kelâm ilmi ile uğraşmakdan, arslandan kaçar gibi kaçınılırdı)", "arama": "Ehl-i sünnet i’tikâdını iyi öğrenmeden önce ilm-i kelâm ile "}, {"kisim": 2, "madde": 5, "metin": "Birincisi: Hadîs-i şerîfin sâhibi olan Fahr-i Rusül “sallallahü aleyhi ve sellem”, (bu benim hadîsim değildir)", "arama": "bu benim hadîsim değildir"}, {"kisim": 2, "madde": 7, "metin": "Allahü teâlâ, (Hadîs-i kudsî)de buyuruyor ki, (Kazâ ve kaderime râzı olmıyan, beğenmiyen ve gönderdiğim belâlara sabr etmiyen, benden başka Rab arasın. Yeryüzünde kulum olarak bulunmasın!)", "arama": "Kazâ ve kaderime râzı olmıyan, beğenmiyen ve gönderdiğim bel"}, {"kisim": 2, "madde": 11, "metin": "(Tergîb-üs-salât), ellidördüncü faslındaki hadîs-i şerîfde, (Sabâh, kalkınca, üç kerre Bismillâhillezî lâ-yedurru ma’ asmihî şey’ün fil-erdı velâ fissemâi ve hüvessemî’ul’alîm okuyana akşama kadar, hiç derd, belâ gelmez)", "arama": "Sabâh, kalkınca, üç kerre Bismillâhillezî lâ-yedurru ma’ asm"}, {"kisim": 2, "madde": 13, "metin": "[Uzun bir hadîs-i şerîfde] (Her mü’minin kalbinde, Allahü teâlânın bir vâ’ızı vardır)", "arama": "Her mü’minin kalbinde, Allahü teâlânın bir vâ’ızı vardır"}, {"kisim": 2, "madde": 14, "metin": "Bir hadîs-i şerîfde, (Kur’ân-ı kerîm okuyan çok kimse vardır ki, Kur’ân-ı kerîm bunlara la’net eder)", "arama": "Kur’ân-ı kerîm okuyan çok kimse vardır ki, Kur’ân-ı kerîm bu"}, {"kisim": 2, "madde": 14, "metin": "Başka bir hadîs-i şerîfde, (Oruc tutan çok kimse vardır ki, onların orucu, yalnız açlık ve susuzluk çekmek olur)", "arama": "Oruc tutan çok kimse vardır ki, onların orucu, yalnız açlık "}, {"kisim": 2, "madde": 14, "metin": "Yetmişdokuzuncu sahîfede diyor ki, Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Müslimân demek, müslimânlara eli ile, dili ile zarar vermiyen kimse demekdir)", "arama": "Müslimân demek, müslimânlara eli ile, dili ile zarar vermiye"}, {"kisim": 2, "madde": 14, "metin": "Bir hadîs-i şerîfde, (Îmânı kâmil olanınız, ahlâkı güzel olanınızdır!)", "arama": "Îmânı kâmil olanınız, ahlâkı güzel olanınızdır!"}, {"kisim": 2, "madde": 14, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Müslimân demek, müslimânlara eli ile, dili ile zarar vermiyen kimse demekdir).", "arama": "müslimânlara eli ile, dili ile zarar vermiyen kimse demekdir"}, {"kisim": 2, "madde": 16, "metin": "Hadîs-i şerîfde, (Ok atmasını ve ata binmesini öğreniniz!)", "arama": "Ok atmasını ve ata binmesini öğreniniz!"}, {"kisim": 2, "madde": 16, "metin": "Bir hadîs-i şerîfde, (Ok atmasını öğrenip, sonra unutan bizden değildir), başka bir hadîs-i şerîfde, (Oyunun fâidesi olmaz. Yalnız, ok atmağı öğrenmek ve atını terbiye etmek ve âilesi ile oynamak hakdır)", "arama": "Oyunun fâidesi olmaz. Yalnız, ok atmağı öğrenmek ve atını te"}, {"kisim": 2, "madde": 16, "metin": "Hadîs-i şerîfde, (Kur’ân-ı kerîmi üç günden önce hatm eden, ma’nâsını anlayamaz)", "arama": "Kur’ân-ı kerîmi üç günden önce hatm eden, ma’nâsını anlayama"}, {"kisim": 2, "madde": 16, "metin": ")da ve (Mir’ât-i kâinât)da ve (Dürr-ül-muhtâr)da yazılı olan ve (İbni Âbidîn)de sahîh olduğu bildirilen hadîs-i şerîfde, (Âdem ve bütün Peygamberler “aleyhimüsselâm”, benimle öğündüğü gibi, ben de, ümmetim içinde, soy adı Ebû Hanîfe, ismi Nu’mân olan bir kimse ile öğünürüm ki, ümmetimin ışığı olacakdır. Onları, yoldan çıkmakdan, cehâlet karanlığına düşmekden koruyacakdır)", "arama": "Âdem ve bütün Peygamberler “aleyhimüsselâm”, benimle öğündüğ"}, {"kisim": 2, "madde": 16, "metin": "Hadîs-i şerîfde, (Ümmetimden, Ebû Hanîfe adında biri gelecekdir. Bu, kıyâmet günü, ümmetimin ışığı olacakdır)", "arama": "Ümmetimden, Ebû Hanîfe adında biri gelecekdir. Bu, kıyâmet g"}, {"kisim": 2, "madde": 16, "metin": "Bir hadîs-i şerîfde, (Nu’mân bin Sâbit adında ve Ebû Hanîfe denilen biri gelecek, Allahü teâlânın dînini ve benim sünnetimi canlandıracakdır)", "arama": "Nu’mân bin Sâbit adında ve Ebû Hanîfe denilen biri gelecek, "}, {"kisim": 2, "madde": 16, "metin": ") Süyûtî, Zehebî ve Askalânî gibi hadîs âlimleri, birkaç hadîs-i şerîfe mevdû’ demişler ise de, bu sözleri, (Benim mezhebimdeki sahîh olmak şartları yokdur)", "arama": "Benim mezhebimdeki sahîh olmak şartları yokdur"}, {"kisim": 2, "madde": 16, "metin": "âmlarını överken, vehhâbîler için bakınız ne buyuruyor: (Tenbîh)de ve (Muhtasar-ı tezkire)de yazılı iki hadîs-i şerîfde, (Kıyâmete yakın ilm azalır, cehâlet artar)", "arama": "Kıyâmete yakın ilm azalır, cehâlet artar"}, {"kisim": 2, "madde": 16, "metin": "Yine imâm-ı Şâfi’î buyurdu ki, (İmâm-ı Muhammedden öğrendiklerimle, bir hayvan yükü kitâb yazdım. O olmasaydı, ilmden birşey edinemiyecekdim. İlmde, herkes, Irâk âlimlerinin çocuklarıdır. Irâk âlimleri de, Kûfe âlimlerinin talebesidir. Kûfe âlimleri ise, Ebû Hanîfenin talebesidir)", "arama": "İmâm-ı Muhammedden öğrendiklerimle, bir hayvan yükü kitâb ya"}, {"kisim": 2, "madde": 17, "metin": "adîka)da, yüzseksenikinci sahîfede diyor ki, (Buhârînin, Ebû Hüreyreden “radıyallahü anh” haber verdiği hadîs-i şerîfde, (Allahü teâlâ, kulum farzları yapmakla bana yaklaşdığı gibi başka şeyle yaklaşamaz. Kulum nâfile ibâdetleri yapınca, onu çok severim. Öyle olur ki, benimle işitir. Benimle görür. Benimle herşeyi tutar. Benimle yürür. Benden her ne isterse veririm. Bana sığınınca, onu korurum buyurdu)", "arama": "Allahü teâlâ, kulum farzları yapmakla bana yaklaşdığı gibi b"}, {"kisim": 2, "madde": 17, "metin": "Alî Râmîtenî hazretleri buyurdu ki, (Günâh işlememiş bir dil ile düâ ediniz ki, kabûl olsun!)", "arama": "Günâh işlememiş bir dil ile düâ ediniz ki, kabûl olsun!"}, {"kisim": 2, "madde": 17, "metin": "(Buhârî)deki hadîs-i şerîfde Peygamberimiz “sallallahü aleyhi ve sellem”, (Kâfirler, kâfirler için gelmiş olan âyet-i kerîmeleri, müslimânlara yükletirler)", "arama": "Kâfirler, kâfirler için gelmiş olan âyet-i kerîmeleri, müsli"}, {"kisim": 2, "madde": 17, "metin": "Bir hadîs-i şerîfde, (Müslimân ismini taşıyanlardan en çok korkduğum kimse, Kur’ân-ı kerîmin ma’nâsını, yerinden değişdirenlerdir)", "arama": "Müslimân ismini taşıyanlardan en çok korkduğum kimse, Kur’ân"}, {"kisim": 2, "madde": 17, "metin": "Taberânînin bildirdiği hadîs-i şerîfde, (Çölde yalnız kalan kimse, birşey gayb ederse, ey Allahın kulları, bana yardım ediniz desin! Çünki, Allahü teâlânın, sizin göremediğiniz kulları vardır)", "arama": "Çölde yalnız kalan kimse, birşey gayb ederse, ey Allahın kul"}, {"kisim": 2, "madde": 17, "metin": "Ebû Dâvüdün ve başkalarının bildirdikleri hadîs-i şerîfde, Resûlullah, seferde iken akşam olunca, (Ey Rabbimin yeri! Senin şerrinden Allaha sığınırım)", "arama": "Ey Rabbimin yeri! Senin şerrinden Allaha sığınırım"}, {"kisim": 2, "madde": 17, "metin": "(Künûz)da yazılı, Deylemînin bildirdiği hadîs-i şerîfde, (Öldükden sonra da, hayâtda olduğum gibi bilirim)", "arama": "Öldükden sonra da, hayâtda olduğum gibi bilirim"}, {"kisim": 2, "madde": 17, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Arabistânın şark tarafından bir kimseler çıkar. Kur’ân-ı kerîmi okurlar. Fekat, Kur’ân-ı kerîm, bunların buğazlarından aşağıya gitmez. Ok yaydan çıkar gibi islâmiyyetden çıkarlar. Yüzleri de hep traşlıdır)", "arama": "Arabistânın şark tarafından bir kimseler çıkar. Kur’ân-ı ker"}, {"kisim": 2, "madde": 17, "metin": "Bir hadîs-i şerîfde, (Korkulu olan yerde, üç kerre: Ey Allahın kulları! Bana yardım ediniz demeli)", "arama": "Korkulu olan yerde, üç kerre: Ey Allahın kulları! Bana yardı"}, {"kisim": 2, "madde": 17, "metin": "Bir hadîs-i şerîfde, (Birşeyden zarar gören, abdest alıp iki rek’at nemâz kılsın! Sonra; Yâ Rabbî! Senden istiyorum. Senin âlemlere rahmet olan Peygamberin Muhammed aleyhisselâmı vesîle kılarak sana yalvarıyorum. Yâ Muhammed! Dileğimi kabûl etmesi için Rabbime seni vesîle ediyorum. Yâ Rabbî! Onu bana şefâ’atcı et desin)", "arama": "Birşeyden zarar gören, abdest alıp iki rek’at nemâz kılsın! "}, {"kisim": 2, "madde": 17, "metin": "Dört mezhebin inceliklerine vâkıf, derin âlim, veliy-yi-kâmil, seyyid Abdülhakîm efendi “kuddise sirruh” buyurdu ki, (Hanefî mezhebinde en mükemmel ve en kıymetli fıkh kitâbı, İbni Âbidînin (Dürr-ül-muhtâr hâşiyesi)", "arama": "Hanefî mezhebinde en mükemmel ve en kıymetli fıkh kitâbı, İb"}, {"kisim": 2, "madde": 17, "metin": "İbni Mâcenin bildirdiği hadîs-i şerîfde, (Ümmetim yetmişüç fırkaya ayrılacak, bunlardan yalnız biri Cennete gidecekdir. Bunlar, benim ve Eshâbımın yolunda olanlardır)", "arama": "Ümmetim yetmişüç fırkaya ayrılacak, bunlardan yalnız biri Ce"}, {"kisim": 2, "madde": 17, "metin": "Çünki, hadîs-i şerîfde, (Ümmetimin ayrılması rahmetdir)", "arama": "Ümmetimin ayrılması rahmetdir"}, {"kisim": 2, "madde": 17, "metin": "Bir hadîs-i şerîfde de, (Kitâbullahda ve benim sünnetimde bulamadıklarınızı, Eshâbımın sözlerinden alınız! Eshâbım, gökdeki yıldızlar gibidir. Hangisine uyarsanız, hidâyete kavuşursunuz. Eshâbımın birbirlerinden ayrılıkları rahmetdir)", "arama": "Kitâbullahda ve benim sünnetimde bulamadıklarınızı, Eshâbımı"}, {"kisim": 2, "madde": 17, "metin": "Hadîs-i şerîfde, (Her asr, önceki asrdan dahâ bozuk olur. Böylece kıyâmete kadar hep bozulur)", "arama": "Her asr, önceki asrdan dahâ bozuk olur. Böylece kıyâmete kad"}, {"kisim": 2, "madde": 17, "metin": "Hadîs-i şerîfde, (Fitne veyâ bid’at yayıldığı ve Eshâbım kötülendiği zemânda, hakkı bilen, bilgisini müslimânlara duyursun! Hakkı, ya’nî doğru yolu bildiği hâlde, müslimânlara duyurmayanlara, Allahü teâlâ ve melekler ve bütün insanlar la’net eylesin! Allahü teâlâ, bu kimsenin farzlarını ve nâfile ibâdetlerini kabûl etmez)", "arama": "Fitne veyâ bid’at yayıldığı ve Eshâbım kötülendiği zemânda, "}, {"kisim": 2, "madde": 18, "metin": "ın mü’minlere şefâ’at edeceğini bildiren çeşidli hadîs-i şerîfler vardır: Hatîb-i Bağdâdînin bildirdiği hadîs-i şerîfde, (Ümmetimden, Ehl-i beytimi sevenlere şefâ’at edeceğim)", "arama": "Ümmetimden, Ehl-i beytimi sevenlere şefâ’at edeceğim"}, {"kisim": 2, "madde": 18, "metin": "Yine Deylemînin bildirdiği hadîs-i şerîfde, (Ümmetimden, nefsine zulm edenlere, nefslerine aldananlara şefâ’at edeceğim)", "arama": "Ümmetimden, nefsine zulm edenlere, nefslerine aldananlara şe"}, {"kisim": 2, "madde": 18, "metin": "İbni Ebî Şeybenin bildirdiği hadîs-i şerîfde, (Kıyâmet günü, mezârdan önce çıkan ben olacağım ve en önce şefâ’at eden ben olacağım)", "arama": "Kıyâmet günü, mezârdan önce çıkan ben olacağım ve en önce şe"}, {"kisim": 2, "madde": 18, "metin": "(Şir’at-ül-islâm) şerhi, yirmisekizinci sahîfesindeki hadîs-i şerîfde, (Şefâ’atime inanmıyan, ona kavuşamaz)", "arama": "Şefâ’atime inanmıyan, ona kavuşamaz"}, {"kisim": 2, "madde": 18, "metin": "Hadîs-i şerîfde buyuruldu ki, (Kabristâna giren kimse, Yasîn sûresini okusa, o gün meyyitlerin azâbları hafîfler. Meyyitlerin sayısı kadar, ona da sevâb verilir)", "arama": "Kabristâna giren kimse, Yasîn sûresini okusa, o gün meyyitle"}, {"kisim": 2, "madde": 18, "metin": "Bir hadîs-i şerîfde de, (Onbir ihlâs okuyup, sevâbı ölülere gönderilirse, mevtâların sayısınca ona da sevâb verilir)", "arama": "Onbir ihlâs okuyup, sevâbı ölülere gönderilirse, mevtâların "}, {"kisim": 2, "madde": 18, "metin": "(Müslim-i şerîf)de bildirilen bir hadîs-i şerîfde de: (Defnden sonra cemâ’at dağılırken, ölü, bunların ayak sesini işitir)", "arama": "Defnden sonra cemâ’at dağılırken, ölü, bunların ayak sesini "}, {"kisim": 2, "madde": 19, "metin": "Hadîs-i şerîfde, (Allahü teâlânın, bir kulunu sevmemesinin alâmeti, onun mâ-lâ-ya’nî ile vakt geçirmesidir)", "arama": "Allahü teâlânın, bir kulunu sevmemesinin alâmeti, onun mâ-lâ"}, {"kisim": 2, "madde": 21, "metin": "berimizin “sallallahü teâlâ aleyhi ve sellem” hadîs-i şerîfini nasıl değişdiriyor? Nasıl hiyle yapıyor? Hadîs-i şerîfde, (Bir müctehid, âyet-i kerîmeden ve hadîs-i şerîfden [amele âid] bir hükm çıkarırken, isâbet ederse, buna on sevâb verilir. Hatâ ederse, bir sevâb verilir)", "arama": "Bir müctehid, âyet-i kerîmeden ve hadîs-i şerîfden [amele âi"}, {"kisim": 2, "madde": 23, "metin": "“radıyallahü anh”, (Halîfe olduğun zemân, yumuşak ol veyâ güzel idâre et!) buyurdukları gibi, diğer bir hadîs-i şerîfde, (İslâmiyyet değirmeni, otuzbeş sene veyâhud otuzyedi sene devâm edecekdir)", "arama": "İslâmiyyet değirmeni, otuzbeş sene veyâhud otuzyedi sene dev"}, {"kisim": 2, "madde": 23, "metin": "m-ı Beyhekî diyor ki, Alî “radıyallahü anh” buyurdu ki, Resûlullahdan “sallallahü aleyhi ve sellem” işitdim, buyurdu ki: (Ümmetimden ba’zı kimseler meydâna çıkacak, Eshâbımı kötüliyeceklerdir. Bunlar, müslimânlıkdan ayrılacaklardır)", "arama": "Ümmetimden ba’zı kimseler meydâna çıkacak, Eshâbımı kötüliye"}, {"kisim": 2, "madde": 24, "metin": "anlara la’net etmek emr edilmeyince, dostlara la’net sevâb olur mu? Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse, şeytâna la’net ederse, ben zâten mel’ûn oldum. Bu la’netin bana zararı olmaz der. Yâ Rabbî! Beni şeytândan koru derse, eyvâh bel kemiğimi kırdın der)", "arama": "Bir kimse, şeytâna la’net ederse, ben zâten mel’ûn oldum. Bu"}, {"kisim": 2, "madde": 24, "metin": "Bir başka hadîs-i şerîfde, (Şeytâna söğmeyiniz! Şerrinden, Allahü teâlâya sığınınız)", "arama": "Şeytâna söğmeyiniz! Şerrinden, Allahü teâlâya sığınınız"}, {"kisim": 2, "madde": 24, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse, şeytâna la’net ederse, ben zâten mel’ûn oldum.", "arama": "şeytâna la’net ederse, ben zâten mel’ûn oldum."}, {"kisim": 2, "madde": 25, "metin": "Bunun için Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Ümmetimden herhangi biri, Uhud dağı kadar altın sadaka verse, Eshâbımın bir müd arpa sadakasına verilen sevâba kavuşamaz)", "arama": "Ümmetimden herhangi biri, Uhud dağı kadar altın sadaka verse"}, {"kisim": 2, "madde": 25, "metin": "Alî “radıyallahü anh” buyurdu ki: (Ebû Bekr ile Ömer “radıyallahü teâlâ anhümâ” bu ümmetin en üstünüdür. Beni onlardan üstün sanan, iftirâ etmekdedir. İftirâ edeni dövdükleri gibi, onu sopa ile döverim)", "arama": "Ebû Bekr ile Ömer “radıyallahü teâlâ anhümâ” bu ümmetin en ü"}, {"kisim": 2, "madde": 25, "metin": "Hattâ, bunun için hadîs-i şerîfde, (Dünyâ kâfirlerin Cennetidir)", "arama": "Dünyâ kâfirlerin Cennetidir"}, {"kisim": 2, "madde": 26, "metin": "Hadîs-i şerîfde, (İşçiye, alnının teri kurumadan hakkını veriniz)", "arama": "İşçiye, alnının teri kurumadan hakkını veriniz"}, {"kisim": 2, "madde": 34, "metin": "Bir hadîs-i şerîfde de, (Nikâh yapmak, benim sünnetimdir. Sünnetimi yapmıyan kimse, benden değildir)", "arama": "Nikâh yapmak, benim sünnetimdir. Sünnetimi yapmıyan kimse, b"}, {"kisim": 2, "madde": 34, "metin": "Hadîs-i şerîfde buyuruldu ki, (Kadın, yâ malı için veyâ güzelliği için, yâhud dîni için alınır. Siz dîni olanı alınız! Malı için alan, malına kavuşamaz. Yalnız cemâl için alan, cemâlinden mahrûm kalır)", "arama": "Kadın, yâ malı için veyâ güzelliği için, yâhud dîni için alı"}, {"kisim": 2, "madde": 34, "metin": "(Rıyâdunnâsıhîn)deki hadîs-i şerîfde, (Mehr vermemek niyyeti ile nikâh yapan kimse, kıyâmet günü hırsızlar arasında haşr olunacakdır)", "arama": "Mehr vermemek niyyeti ile nikâh yapan kimse, kıyâmet günü hı"}, {"kisim": 2, "madde": 36, "metin": "(Kâdîhân) fetvâsında diyor ki, (Ebülleys-i Semerkandî buyurdu ki, erkek nikâh yaparken, (Boşanmak senin elinde olmak üzere, seni nikâh etdim)", "arama": "Boşanmak senin elinde olmak üzere, seni nikâh etdim"}, {"kisim": 2, "madde": 38, "metin": "Hadîs-i şerîfde, (Komşuya hurmet etmek, anaya hurmet etmek gibi lâzımdır)", "arama": "Komşuya hurmet etmek, anaya hurmet etmek gibi lâzımdır"}, {"kisim": 2, "madde": 38, "metin": "Hadîs-i şerîfde, (Komşusu, şerrinden emîn olmıyan kimse, Allahü teâlâya îmân etmemişdir)", "arama": "Komşusu, şerrinden emîn olmıyan kimse, Allahü teâlâya îmân e"}, {"kisim": 2, "madde": 38, "metin": "Hadîs-i şerîfde, (Zimmî komşunun bir hakkı, müslimân komşunun iki hakkı, akrabâ olan komşunun üç hakkı vardır)", "arama": "Zimmî komşunun bir hakkı, müslimân komşunun iki hakkı, akrab"}, {"kisim": 2, "madde": 38, "metin": "Hadîs-i şerîfde, (Evinizde pişen yemekden, komşunuzun hakkını veriniz!)", "arama": "Evinizde pişen yemekden, komşunuzun hakkını veriniz!"}, {"kisim": 2, "madde": 38, "metin": "Hadîs-i şerîfde, (Sıkıntıya düşen komşusuna yardım eden, sıkıntısını gideren kimseye, Allahü teâlâ kıyâmet günü kıymetli elbise giydirecekdir)", "arama": "Sıkıntıya düşen komşusuna yardım eden, sıkıntısını gideren k"}, {"kisim": 2, "madde": 38, "metin": "Hadîs-i şerîfde, (Allahü teâlâ, bir sâlih müslimânın hurmetine, komşularından binlerce belâyı, felâketi uzaklaşdırır)", "arama": "Allahü teâlâ, bir sâlih müslimânın hurmetine, komşularından "}, {"kisim": 2, "madde": 38, "metin": "Hadîs-i şerîfde, (Kendisinin iyi mi, kötü mü olduğunu anlamak istiyen kimse, sâlih, hâlis olan komşularının kendisi hakkında ne dediklerini öğrensin! İyi kimsedir diyorlarsa, ind-i ilâhîde iyi olduğunu anlasın!)", "arama": "Kendisinin iyi mi, kötü mü olduğunu anlamak istiyen kimse, s"}, {"kisim": 2, "madde": 39, "metin": "(Tenbîh-ul-gâfilîn)de yazılı hadîs-i şerîfde, (Dört şeyi yapan, ya’nî kocasına hıyânet etmiyen, beş vakt nemâz kılan, Ramezân-ı şerîfde oruc tutan ve [onsekiz erkekden] başkasına, [başı, saçı, kolları, bacakları] açık olarak görünmiyen kadın Cennete gidecekdir)", "arama": "Dört şeyi yapan, ya’nî kocasına hıyânet etmiyen, beş vakt ne"}, {"kisim": 2, "madde": 39, "metin": "(Tenbîh-ul-gâfilîn)de ve (Şir’a) şerhinde yazılı hadîs-i şerîfde, Peygamberimiz “sallallahü teâlâ aleyhi ve sellem”, (Bir kadın, beş vakt nemâzını kılar, Ramezân ayında oruc tutar, nâmûsunu korur ve zevcine itâ’at ederse, dilediği kapıdan Cennete girer)", "arama": "Bir kadın, beş vakt nemâzını kılar, Ramezân ayında oruc tuta"}, {"kisim": 2, "madde": 39, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Müslimânların en iyisi, en fâidelisi, zevcesine karşı iyi ve fâideli olandır)", "arama": "Müslimânların en iyisi, en fâidelisi, zevcesine karşı iyi ve"}, {"kisim": 2, "madde": 39, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Bir erkek, zevcesini döğerse, kıyâmetde ben onun da’vâcısı olurum)", "arama": "Bir erkek, zevcesini döğerse, kıyâmetde ben onun da’vâcısı o"}, {"kisim": 2, "madde": 39, "metin": "Hadîs-i şerîfde, (Her dürlü lehv harâmdır. Yalnız, zevce ile oynamak, at ve silâh ile ta’lîm, yarış yapmak câizdir)", "arama": "Her dürlü lehv harâmdır. Yalnız, zevce ile oynamak, at ve si"}, {"kisim": 2, "madde": 39, "metin": "(Mecma’ul-enhür)deki hadîs-i şerîfde, Peygamberimiz “sallallahü aleyhi ve sellem”, (Hür kadının, yüzünden ve iki eli ayasından başka, bütün bedeni avretdir)", "arama": "Hür kadının, yüzünden ve iki eli ayasından başka, bütün bede"}, {"kisim": 2, "madde": 39, "metin": "Hadîs-i şerîfde, (Kadının neresine olursa olsun, şehvet ile bakan kimsenin gözlerine kıyâmet günü erimiş kurşun dökülecek, sonra Cehenneme atılacakdır)", "arama": "Kadının neresine olursa olsun, şehvet ile bakan kimsenin göz"}, {"kisim": 2, "madde": 39, "metin": "Hadîs-i şerîfde, (Yabancı genc kadının elini tutan kimsenin eline kıyâmet günü ateş doldurulacakdır)", "arama": "Yabancı genc kadının elini tutan kimsenin eline kıyâmet günü"}, {"kisim": 2, "madde": 39, "metin": "hadîs-i şerîflerde, (Zevcinin evinden başka yerde başını açan kadın, Rabbi ile kendi arasındaki perdeyi yırtmış olur) ve (Allaha ve Kıyâmet gününe inanan, hamâma gitmesin ve Allaha ve Kıyâmet gününe inanan, zevcesini hamâma göndermesin ve Allaha ve Kıyâmet gününe inanan, şerâb içmesin ve Allaha ve Kıyâmet gününe inanan, şerâb içilen sofrada oturmasın ve Allaha ve Kıyâmet gününe inanan, yabancı bir kadınla, yalnız kalıp halvet etmesin)", "arama": "Allaha ve Kıyâmet gününe inanan, hamâma gitmesin ve Allaha v"}, {"kisim": 2, "madde": 39, "metin": "Hattâ, (Harâmdan olan Cilbâb giyenin nemâzı kabûl olmaz!) hadîs-i şerîfindeki (Cilbâb) kelimesine, (Kitâb-ül-fıkh-ı alel-mezâhib-il erbe’a)", "arama": "Kitâb-ül-fıkh-ı alel-mezâhib-il erbe’a"}, {"kisim": 2, "madde": 39, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (İki zevcesi olup da, ikisine müsâvî bakmıyan kimse, kıyâmet günü, mahşer meydânına yarı iğrilmiş olarak gelecekdir)", "arama": "İki zevcesi olup da, ikisine müsâvî bakmıyan kimse, kıyâmet "}, {"kisim": 2, "madde": 39, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse, kızını fâsıka [kötü kimseye] verirse, Allahü teâlânın emânetine hıyânet etmiş olur. Emânete hıyânet edenlerin gideceği yer, Cehennemdir)", "arama": "Bir kimse, kızını fâsıka [kötü kimseye] verirse, Allahü teâl"}, {"kisim": 2, "madde": 39, "metin": "Bir hadîs-i şerîfde buyurdu ki, (Kızını fâsıka veren kimse, mel’ûndur)", "arama": "Kızını fâsıka veren kimse, mel’ûndur"}, {"kisim": 2, "madde": 39, "metin": "(Şir’a) şerhindeki hadîs-i şerîfde, (Şefâ’atime kavuşmak istiyen, kızını fâsıka vermesin!)", "arama": "Şefâ’atime kavuşmak istiyen, kızını fâsıka vermesin!"}, {"kisim": 2, "madde": 39, "metin": "(Eşi’at-ül-lemeât)da, nemâzı gecikdirmemeli bâbındaki hadîs-i şerîfde, (Yâ Alî! Üç şeyi gecikdirme! Nemâzı evvel vaktinde kıl! Hâzırlanmış cenâzenin nemâzını hemen kıl! Dul veyâ kızı küfvü isteyince, hemen evlendir!)", "arama": "Yâ Alî! Üç şeyi gecikdirme! Nemâzı evvel vaktinde kıl! Hâzır"}, {"kisim": 2, "madde": 40, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Halâl kazanmak her müslimâna farzdır)", "arama": "Halâl kazanmak her müslimâna farzdır"}, {"kisim": 2, "madde": 40, "metin": "Ve buyurdu ki, (Bir kimse, hiç harâm karışdırmadan, kırk gün halâl yirse, Allahü teâlâ, onun kalbini nûr ile doldurur. Kalbine, nehrler gibi hikmet akıtır. Dünyâ muhabbetini, kalbinden giderir)", "arama": "Bir kimse, hiç harâm karışdırmadan, kırk gün halâl yirse, Al"}, {"kisim": 2, "madde": 40, "metin": "Bir hadîs-i şerîfde, (Çok kimse vardır ki, yidikleri ve giydikleri harâmdır. Sonra ellerini kaldırıp düâ ederler. Böyle düâ, nasıl kabûl olunur?)", "arama": "Çok kimse vardır ki, yidikleri ve giydikleri harâmdır. Sonra"}, {"kisim": 2, "madde": 40, "metin": "Bir kerre de buyurdu ki, (Harâm yiyenlerin ne farzları, ne de sünnetleri kabûl olmaz)", "arama": "Harâm yiyenlerin ne farzları, ne de sünnetleri kabûl olmaz"}, {"kisim": 2, "madde": 40, "metin": "] Yine buyurdu ki, (On liralık elbisenin, bir lirası harâm olsa, o elbise ile kılınan nemâzlar kabûl olmaz)", "arama": "On liralık elbisenin, bir lirası harâm olsa, o elbise ile kı"}, {"kisim": 2, "madde": 40, "metin": "Yine buyurdu ki, (Harâm ile beslenen vücûdün ateşde yanması dahâ iyidir)", "arama": "Harâm ile beslenen vücûdün ateşde yanması dahâ iyidir"}, {"kisim": 2, "madde": 40, "metin": "Yine buyurdu ki, (Malın halâlden mi, harâmdan mı geldiğini düşünmiyenler, Cehenneme, neresinden atılırsa atılsınlar, Allahü teâlâ, onlara acımıyacakdır)", "arama": "Malın halâlden mi, harâmdan mı geldiğini düşünmiyenler, Cehe"}, {"kisim": 2, "madde": 40, "metin": "Yine buyurdu ki, (İbâdet on kısmdır, dokuz kısmı, halâl kazanmakdır)", "arama": "İbâdet on kısmdır, dokuz kısmı, halâl kazanmakdır"}, {"kisim": 2, "madde": 40, "metin": "Bir def’a da buyurdu ki, (Halâl kazanmak için yorulup, evine dönen kimse, günâhsız olarak yatar. Allahü teâlânın sevdiği kimse olarak kalkar)", "arama": "Halâl kazanmak için yorulup, evine dönen kimse, günâhsız ola"}, {"kisim": 2, "madde": 40, "metin": "Yine buyurdu ki, (Allahü teâlâ buyuruyor ki, harâmdan kaçınanlara hesâb sormağa utanırım)", "arama": "Allahü teâlâ buyuruyor ki, harâmdan kaçınanlara hesâb sormağ"}, {"kisim": 2, "madde": 40, "metin": "Ve buyurdu ki, (Bir dirhem fâiz [almak ve vermek], otuz zinâdan dahâ günâhdır)", "arama": "Bir dirhem fâiz [almak ve vermek], otuz zinâdan dahâ günâhdı"}, {"kisim": 2, "madde": 40, "metin": "Ve buyurdu ki, (Harâm maldan verilen sadaka kabûl edilmez. Saklanırsa, Cehenneme gidinceye kadar, ona yolluk olur)", "arama": "Harâm maldan verilen sadaka kabûl edilmez. Saklanırsa, Cehen"}, {"kisim": 2, "madde": 40, "metin": "Abdüllah bin Ömer “radıyallahü anhümâ” buyurdu ki, (Kanbur oluncıya kadar nemâz kılsanız ve kıl gibi oluncıya kadar oruc tutsanız, harâmdan kaçınmadıkca, kabûl edilmez, fâidesi olmaz)", "arama": "Kanbur oluncıya kadar nemâz kılsanız ve kıl gibi oluncıya ka"}, {"kisim": 2, "madde": 40, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir müslimân, tehlükeli olan şeyin korkusundan dolayı, tehlükesiz şeyden sakınmadıkca, müttekî olamaz!)", "arama": "Bir müslimân, tehlükeli olan şeyin korkusundan dolayı, tehlü"}, {"kisim": 2, "madde": 40, "metin": "Ömer “radıyallahü anh” buyurdu ki, (Bizler harâma düşmek korkusu ile, halâllerin onda dokuzundan kaçındık)", "arama": "Bizler harâma düşmek korkusu ile, halâllerin onda dokuzundan"}, {"kisim": 2, "madde": 40, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (İnsanların en kötüsü, köşkler, çeşidli yemekler, renkli elbiseler içinde, boş oturup, herkese hoş gelen, lüzûmsuz sözlerle vakt geçirenlerdir)", "arama": "İnsanların en kötüsü, köşkler, çeşidli yemekler, renkli elbi"}, {"kisim": 2, "madde": 40, "metin": "Çünki hadîs-i şerîfde, (Her yıl, kendinden önceki yıldan dahâ kötü olacakdır)", "arama": "Her yıl, kendinden önceki yıldan dahâ kötü olacakdır"}, {"kisim": 2, "madde": 40, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (İstemeden verilen şeyi alınız! Allahü teâlânın gönderdiği rızkdır)", "arama": "İstemeden verilen şeyi alınız! Allahü teâlânın gönderdiği rı"}, {"kisim": 2, "madde": 40, "metin": "(Şir’at-ül-islâm) ikiyüzkırkaltıncı sahîfesindeki hadîs-i şerîfde, (Allaha ve Âhıret gününe inanan kimse, şerâb içilen sofraya oturmasın!)", "arama": "Allaha ve Âhıret gününe inanan kimse, şerâb içilen sofraya o"}, {"kisim": 2, "madde": 40, "metin": "(Dürr-ül-muhtâr)daki hadîs-i şerîfde, (Kâr haddi koymayınız! Fiyât koyan, Allahü teâlâdır)", "arama": "Kâr haddi koymayınız! Fiyât koyan, Allahü teâlâdır"}, {"kisim": 2, "madde": 40, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Halâl kazanmak her müslimâna farzdır).", "arama": "(Halâl kazanmak her müslimâna farzdır)."}, {"kisim": 2, "madde": 40, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir müslimân, tehlükeli olan şeyin korkusundan dolayı, tehlükesiz şeyden sakınmadıkca, müttekî olamaz!).", "arama": "tehlükeli olan şeyin korkusundan dolayı, tehlükesiz şeyden s"}, {"kisim": 2, "madde": 40, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (İnsanların en kötüsü, köşkler, çeşidli yemekler, renkli elbiseler içinde, boş oturup, herkese hoş gelen, lüzûmsuz sözlerle vakt geçirenlerdir).", "arama": "(İnsanların en kötüsü, köşkler, çeşidli yemekler, renkli elb"}, {"kisim": 2, "madde": 42, "metin": "Çünki hadîs-i şerîfde, (Şerâb, üzüm ve hurmadan olur)", "arama": "Şerâb, üzüm ve hurmadan olur"}, {"kisim": 2, "madde": 42, "metin": "(İbni Âbidîn) beşinci cild, ikiyüzotuzsekizinci sahîfedeki hadîs-i şerîfde, (Suyu, alkollü içki içenler gibi içmek harâmdır)", "arama": "Suyu, alkollü içki içenler gibi içmek harâmdır"}, {"kisim": 2, "madde": 42, "metin": "] Bir hadîs-i şerîfde buyuruldu ki, (Şerâb içmek, büyük günâhların en büyüğüdür. Bütün kötülüklerin anasıdır, başıdır. Şerâb içen, nemâz kılmaz. Anası ile, halası ile, teyzesi ile zinâ eder)", "arama": "Şerâb içmek, büyük günâhların en büyüğüdür. Bütün kötülükler"}, {"kisim": 2, "madde": 42, "metin": "Bir hadîs-i şerîfde, (Şerâb içen ile arkadaşlık etmeyiniz! Cenâzesine gitmeyiniz! Buna kız vermeyiniz ve onun kızı ile evlenmeyiniz! Muhakkak biliniz ki, şerâb içen, kıyâmet günü, mezârdan yüzü kara, gözleri mâvi olarak kalkar. Dili sarkmış, pis kokulu olur. Herkes, bunun pis kokusundan kaçar)", "arama": "Şerâb içen ile arkadaşlık etmeyiniz! Cenâzesine gitmeyiniz! "}, {"kisim": 2, "madde": 42, "metin": "Bir hadîs-i şerîfde, (Şerâb içen Cennete girmez)", "arama": "Şerâb içen Cennete girmez"}, {"kisim": 2, "madde": 42, "metin": "Bir hadîs-i şerîfde, (Şerâb içmeği âdet eden, vesene tapan gibidir)", "arama": "Şerâb içmeği âdet eden, vesene tapan gibidir"}, {"kisim": 2, "madde": 42, "metin": "Bir hadîs-i şerîfde, (Bir yudum şerâb içene, Allahü teâlâ üç gün gadab eder)", "arama": "Bir yudum şerâb içene, Allahü teâlâ üç gün gadab eder"}, {"kisim": 2, "madde": 42, "metin": "Bir hadîs-i şerîfde, (Şerâbda devâ, ilâc hâssası yokdur. Hastalık yapar)", "arama": "Şerâbda devâ, ilâc hâssası yokdur. Hastalık yapar"}, {"kisim": 2, "madde": 42, "metin": "(Erba’în)de diyor ki: Abdüllah bin Mes’ûd buyurdu ki, (Şerâb içen kimse, tevbesiz ölürse, mezârını açınız! Yüzünü kıbleye karşı görürseniz, beni öldürünüz!)", "arama": "Şerâb içen kimse, tevbesiz ölürse, mezârını açınız! Yüzünü k"}, {"kisim": 2, "madde": 42, "metin": "Hadîs-i şerîfde buyuruldu ki, (Gece nemâz kılanların yüzü güzel olur)", "arama": "Gece nemâz kılanların yüzü güzel olur"}, {"kisim": 2, "madde": 43, "metin": "Hadîs-i şerîfde, (Şübheli şeyleri yapan, harâm da işler)", "arama": "Şübheli şeyleri yapan, harâm da işler"}, {"kisim": 2, "madde": 43, "metin": "Binüçyüzkırkyedinci sahîfede diyor ki: Hadîs-i şerîfde, (Soğan, sarmısak yiyen, mescidimize gelmesin!)", "arama": "Soğan, sarmısak yiyen, mescidimize gelmesin!"}, {"kisim": 2, "madde": 43, "metin": "Bunlara ne dersiniz? Alî Echürî hazretleri, cevâbında buyurdu ki, (Bunların hiçbiri hadîs değildir. Hadîs âlimleri, bunların yalan ve iftirâ olduklarını bildirdiler. Hem de, bu sözlerin düzgün ve edebiyyâta uygun olmaması da, Resûlullahın mubârek ağzından çıkmadıklarını göstermekdedir. Rebî’ bin Haysem buyurdu ki, güneşde ışık olduğu gibi, hadîs-i şerîflerde de nûr vardır. İftirâ olarak uydurulan sözlerde ise, zulmet vardır. Hadîs uyduran, Cehenn", "arama": "Bunların hiçbiri hadîs değildir. Hadîs âlimleri, bunların ya"}, {"kisim": 2, "madde": 43, "metin": "ve (Müslim)de yazılı hadîs-i şerîfde, (Söylemediğim birşeyi hadîs diyerek yalan söyliyen, Cehennemde ateşden kazık üzerine oturtulacakdır)", "arama": "Söylemediğim birşeyi hadîs diyerek yalan söyliyen, Cehennemd"}, {"kisim": 2, "madde": 44, "metin": "İmâm-ı Tirmizînin, Ebû Kebşe-i Ensârîden “radıyallahü teâlâ anh” alarak bildirdiği bir hadîs-i şerîfde, (Allahü teâlâ, bir kuluna mal ve ilm verir. Bu kul da harâmlardan kaçınır. Akrabâsını sevindirir. Malından, hakkı olanları bilip verir ise, Cennetin yüksek derecesine gider)", "arama": "Allahü teâlâ, bir kuluna mal ve ilm verir. Bu kul da harâmla"}, {"kisim": 2, "madde": 44, "metin": "] Büyük âlim ibni Cevzî “rahimehullah” buyurdu ki, (İyi niyyet ile mal kazanmak, mal kazanmamakdan iyidir)", "arama": "İyi niyyet ile mal kazanmak, mal kazanmamakdan iyidir"}, {"kisim": 2, "madde": 45, "metin": "İmâm-ı Ca’fer-i Sâdık buyurdu ki, (Malı ve evlâdı çok olmak istiyen bitkisel yemek çok yisin!)", "arama": "Malı ve evlâdı çok olmak istiyen bitkisel yemek çok yisin!"}, {"kisim": 2, "madde": 45, "metin": "Hadîs-i şerîfde, (İyiliklerin başı açlıkdır. Kötülüklerin başı toklukdur)", "arama": "İyiliklerin başı açlıkdır. Kötülüklerin başı toklukdur"}, {"kisim": 2, "madde": 45, "metin": "Hadîs-i şerîfde, (Sağ el ile yiyiniz. Sağ el ile içiniz)", "arama": "Sağ el ile yiyiniz. Sağ el ile içiniz"}, {"kisim": 2, "madde": 45, "metin": "Hadîs-i şerîfde buyuruldu ki, (İnsan kalbi, tarladaki ekin gibidir. Yemek, yağmur gibidir. Fazla su, ekini kurutduğu gibi, fazla gıdâ kalbi öldürür)", "arama": "İnsan kalbi, tarladaki ekin gibidir. Yemek, yağmur gibidir. "}, {"kisim": 2, "madde": 45, "metin": "Bir hadîs-i şerîfde, (Çok yiyeni, çok içeni Allahü teâlâ sevmez)", "arama": "Çok yiyeni, çok içeni Allahü teâlâ sevmez"}, {"kisim": 2, "madde": 45, "metin": "Hadîs-i şerîfde, (Günâhı çok olan, çok su dağıtsın!)", "arama": "Günâhı çok olan, çok su dağıtsın!"}, {"kisim": 2, "madde": 45, "metin": "Alî “radıyallahü anh” buyurdu ki, (Üç şey ahmaklıkdır: Diş ile tırnak uçlarını yimek, sakal yolmak ve balçık yimek)", "arama": "Üç şey ahmaklıkdır: Diş ile tırnak uçlarını yimek, sakal yol"}, {"kisim": 2, "madde": 45, "metin": "Hadîs-i şerîfde, (Allahü teâlâ, kuluna derd vermek isterse, sakalını yolmağı ve tırnağını ısırmağı âdet eder)", "arama": "Allahü teâlâ, kuluna derd vermek isterse, sakalını yolmağı v"}, {"kisim": 2, "madde": 45, "metin": "Hadîs-i şerîfde, (Üç şey, bedeni besler: Güzel koku, yumuşak kumaşdan güzel elbise ve bal yimek)", "arama": "Üç şey, bedeni besler: Güzel koku, yumuşak kumaşdan güzel el"}, {"kisim": 2, "madde": 46, "metin": "Hadîs-i şerîfde, (Ümmetim hulbenin fâidesini bilse, ağırlığı kadar altın verip, satın alırdı)", "arama": "Ümmetim hulbenin fâidesini bilse, ağırlığı kadar altın verip"}, {"kisim": 2, "madde": 47, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyuruyor ki, (Ümmetimden bir kısmını, bana gösterdiler. Dağları, sahrâları doldurmuşlardı. Böyle çok olduklarına şaşdım ve sevindim. Sevindin mi, dediler, evet dedim. Bunlardan ancak yetmişbin adedi hesâbsız Cennete girer dediler. Bunlar hangileridir diye sordum. İşlerine sihr, büyü, dağlamak, fal karışdırmayıp, Allahü teâlâdan başkasına, tevekkül ve i’timâd etmiyenlerdir buyuruldu)", "arama": "Ümmetimden bir kısmını, bana gösterdiler. Dağları, sahrâları"}, {"kisim": 2, "madde": 47, "metin": "Bir hadîs-i şerîfde, (Allahü teâlâya tam tevekkül etseydiniz, kuşların rızkını verdiği gibi, size de gönderirdi. Kuşlar, sabâh mi’deleri boş, aç gider. Akşam mi’deleri dolmuş, doymuş olarak döner)", "arama": "Allahü teâlâya tam tevekkül etseydiniz, kuşların rızkını ver"}, {"kisim": 2, "madde": 47, "metin": "Bir hadîs-i şerîfde, (Bir kimse, Allahü teâlâya sığınırsa, Allahü teâlâ, onun her işine yetişir. Hiç ummadığı yerden, ona rızk verir. Her kim, dünyâya güvenirse, onu dünyâda bırakır)", "arama": "Bir kimse, Allahü teâlâya sığınırsa, Allahü teâlâ, onun her "}, {"kisim": 2, "madde": 47, "metin": "Bunun için, hadîs-i şerîfde, (Gadab, ya’nî asabiyyet, Cehennem ateşinden bir parçadır)", "arama": "Gadab, ya’nî asabiyyet, Cehennem ateşinden bir parçadır"}, {"kisim": 2, "madde": 47, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse geceyi, yarın yapacağı işleri düşünmekle geçirir. Hâlbuki o iş, bu kimsenin felâketine sebeb olacakdır. Allahü teâlâ, bu kuluna acıyıp, o işi yapdırmaz. O ise, iş olmadığı için, üzülür. Bu işim neden olmıyor. Kim yapdırmıyor. Bana kim düşmanlık ediyor diye arkadaşlarına kötü gözle bakmağa başlar. Hâlbuki, Allahü teâlâ, ona merhamet ederek felâketden korumuşdur)", "arama": "Bir kimse geceyi, yarın yapacağı işleri düşünmekle geçirir. "}, {"kisim": 2, "madde": 47, "metin": "Bu niyyet, şuna benzer ki, bir hadîs-i şerîfde buyuruldu ki, (Bir kimse, âilesi ile buluşdukda, azl eylemez ise, ya’nî çocuk olmasına mâni’ olmazsa, çocuk olsa da olmasa da, bu kimseye, şehîd oluncıya kadar cihâd eden bir yeğid sevâbı verilir)", "arama": "Bir kimse, âilesi ile buluşdukda, azl eylemez ise, ya’nî çoc"}, {"kisim": 2, "madde": 47, "metin": "Hadîs-i şerîfde buyuruldu ki, (İnsan, kendine zulm edene beddüâ eder. Böylece, hakkını, dünyâda almış olur. Belki, zâlimin hakkı da, kendine geçmiş olur)", "arama": "İnsan, kendine zulm edene beddüâ eder. Böylece, hakkını, dün"}, {"kisim": 2, "madde": 47, "metin": "Bir hadîs-i şerîfde, (Bütün Meleklerden işitdim ki, ümmetine söyle, hacâmat yapdırsınlar. Ya’nî kan aldırsınlar dediler)", "arama": "Bütün Meleklerden işitdim ki, ümmetine söyle, hacâmat yapdır"}, {"kisim": 2, "madde": 47, "metin": "Bir hadîs-i şerîfde, (Arabî ayın onyedinci veyâ ondokuzuncu veyâ yirmibirinci günleri hacâmat olunuz ki, kan artarsa [ya’nî tansiyon yükselirse], ölüme sebeb olur)", "arama": "Arabî ayın onyedinci veyâ ondokuzuncu veyâ yirmibirinci günl"}, {"kisim": 2, "madde": 47, "metin": "Bir hadîs-i şerîfde, (Allahü teâlânın ölüme sebeb yapdığı hastalıklardan birisi, kanın artmasıdır)", "arama": "Allahü teâlânın ölüme sebeb yapdığı hastalıklardan birisi, k"}, {"kisim": 2, "madde": 47, "metin": "Vahy gelip, Allahü teâlâ buyurdu ki, (Sen tevekkül etmek için, benim âdetimi, hikmetimi değişdirmek istiyorsun. İlâclara, fâideli te’sîrleri kim verdi? Elbette ben yaratıyorum)", "arama": "Sen tevekkül etmek için, benim âdetimi, hikmetimi değişdirme"}, {"kisim": 2, "madde": 47, "metin": "Hadîs-i şerîfde buyuruldu ki, (Mûsâ “aleyhisselâm”, Yâ Rabbî! Hastalığı yapan kimdir, hastalığı iyi eden kimdir, dedi. Cenâb-ı Hak, her ikisini de yapan benim, buyurdu. O hâlde, tabîbe ne lüzûm var deyince, onlar, şifâ için yaratdığım sebebleri bilir ve kullarıma verir. Ben de onlara, bu yoldan rızk ve sevâb veririm, buyurdu)", "arama": "Mûsâ “aleyhisselâm”, Yâ Rabbî! Hastalığı yapan kimdir, hasta"}, {"kisim": 2, "madde": 47, "metin": "Hadîs-i şerîfde buyuruldu ki, (Şübhe edilen altını, ateşle mu’âyene etdikleri gibi, Allahü teâlâ, insanları derd ile, belâ ile imtihân eder. Ba’zısı, belâ ateşinden hâlis olarak çıkar. Ba’zısı da, bozuk olarak çıkar)", "arama": "Şübhe edilen altını, ateşle mu’âyene etdikleri gibi, Allahü "}, {"kisim": 2, "madde": 47, "metin": "Hadîs-i şerîfde buyuruldu ki, (Sıtma hastalığı, insanın günâhlarının hepsini temizler. Dolu dânesinde toz olmadığı gibi, sıtmalının günâhı kalmaz)", "arama": "Sıtma hastalığı, insanın günâhlarının hepsini temizler. Dolu"}, {"kisim": 2, "madde": 47, "metin": "Îsâ “aleyhisselâm” buyurdu ki, (Hasta olup, musîbete, felâkete uğrayıp da, günâhları afv olacağı için sevinmiyen kimse, âlim değildir)", "arama": "Hasta olup, musîbete, felâkete uğrayıp da, günâhları afv ola"}, {"kisim": 2, "madde": 47, "metin": "nlerde, üç şeyden biri bulunur: Kıllet ya’nî fakîrlik, ıllet ya’nî hastalık, zillet, ya’nî i’tibârsızlık) ve buyurdu ki, (Allahü teâlâ buyurdu ki: Hastalık benim kemendim, tuzağımdır ve fakîrlik zındânımdır. Buralara sevdiklerimi sokarım)", "arama": "Allahü teâlâ buyurdu ki: Hastalık benim kemendim, tuzağımdır"}, {"kisim": 2, "madde": 47, "metin": "deki hadîs-i şerîfde, (Allahü teâlâ, harâm olan şeylerde, size şifâ yaratmamışdır)", "arama": "Allahü teâlâ, harâm olan şeylerde, size şifâ yaratmamışdır"}, {"kisim": 2, "madde": 47, "metin": "Hadîs-i şerîflerde buyuruluyor ki, (Vebâ hastalığı bulunan yerden kaçmak, muhârebede kâfir karşısından kaçmak gibi, büyük günâhdır)", "arama": "Vebâ hastalığı bulunan yerden kaçmak, muhârebede kâfir karşı"}, {"kisim": 2, "madde": 47, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Allahü teâlâdan âfiyet isteyiniz. Belâ istemeyiniz!)", "arama": "Allahü teâlâdan âfiyet isteyiniz. Belâ istemeyiniz!"}, {"kisim": 2, "madde": 47, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse geceyi, yarın yapacağı işleri düşünmekle geçirir.", "arama": "(Bir kimse geceyi, yarın yapacağı işleri düşünmekle geçirir."}, {"kisim": 2, "madde": 48, "metin": "Çünki, hadîs-i kudsîde: (İnsanların kalbi Rahmânın kudretindedir. Kalbleri, dilediği gibi çevirir)", "arama": "İnsanların kalbi Rahmânın kudretindedir. Kalbleri, dilediği "}, {"kisim": 2, "madde": 48, "metin": "Hadîs-i şerîfde buyuruldu ki, (Kader, tedbîr ile, sakınmakla değişmez. Fekat kabûl olan düâ, o belâ gelirken korur)", "arama": "Kader, tedbîr ile, sakınmakla değişmez. Fekat kabûl olan düâ"}, {"kisim": 2, "madde": 48, "metin": "Bir hadîs-i şerîfde, (Kazâ-i mu’allakı, hiçbirşey değişdiremez. Yalnız düâ değişdirir ve ömrü, yalnız, ihsân, iyilik artdırır)", "arama": "Kazâ-i mu’allakı, hiçbirşey değişdiremez. Yalnız düâ değişdi"}, {"kisim": 2, "madde": 49, "metin": "Büyük Peygamberimizin “sallallahü aleyhi ve sellem” çok güzel bir hadîs-i şerîfi var: (Bir müslimân, kendisine istediği bir iyiliği, başka bir müslimân için istemezse ve bir müslimân, kendisine gelecek bir kötülüğü, istemediği hâlde, o kötülüğü başka bir müslimân için isterse, onun îmânı tam değildir)", "arama": "Bir müslimân, kendisine istediği bir iyiliği, başka bir müsl"}, {"kisim": 2, "madde": 50, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse, bütün ömrünce Cehennem ateşine götürecek günâhlar yapar. Bu kimse, ömrünün son günlerinde, Cennete götürecek iyilikler yaparak, Cennete gider)", "arama": "Bir kimse, bütün ömrünce Cehennem ateşine götürecek günâhlar"}, {"kisim": 2, "madde": 52, "metin": "i şerîfde, Resûlullah “sallallahü aleyhi ve sellem”, Eshâbına “radıyallahü teâlâ anhüm ecma’în” hitâb ederek buyurdu ki, (Sizden sonra, bir zemân gelecekdir. O zemânda bulunan müslimânların en sefîlleri, en aşağıları, müezzinlerdir)", "arama": "Sizden sonra, bir zemân gelecekdir. O zemânda bulunan müslim"}, {"kisim": 2, "madde": 52, "metin": "(Hadîka)da, dil âfetlerini anlatırken buyuruyor ki, hadîs-i şerîfde, (Nikâhı herkese duyurunuz! Bunun için de, câmi’lerde yapınız ve defler çalınız!)", "arama": "Nikâhı herkese duyurunuz! Bunun için de, câmi’lerde yapınız "}, {"kisim": 2, "madde": 52, "metin": "(Muhtasar-üt-Tezkire)deki hadîs-i şerîflerde, (Âhır zemânda, câhil din adamları ve fâsık hâfızlar çoğalır), (Öyle zemân gelecekdir ki, o zemânın din adamları, eşek leşinden dahâ çok bozulmuş, kokmuş olacaklardır)", "arama": "Öyle zemân gelecekdir ki, o zemânın din adamları, eşek leşin"}, {"kisim": 2, "madde": 52, "metin": "Derin âlim, şeyh-ül-islâm Ahmed ibni Kemâl efendinin kırk hadîsinin tercemesinde, otuzdokuzuncu hadîs-i şerîfde, (Mizmârları kırmak için ve hınzırları öldürmek için gönderildim)", "arama": "Mizmârları kırmak için ve hınzırları öldürmek için gönderild"}, {"kisim": 2, "madde": 52, "metin": "Başka bir hadîs-i şerîfde, (Kur’ân-ı kerîmi arab şîvesi ile, onların sesi ile okuyunuz! Fâsıklar, şarkıcılar gibi okumayınız!)", "arama": "Kur’ân-ı kerîmi arab şîvesi ile, onların sesi ile okuyunuz! "}, {"kisim": 2, "madde": 52, "metin": "Resûlullah “aleyhisselâm” buyurdu ki, (Ümmetimdeki münâfıkların çoğu, Kur’ân-ı kerîm okuyanlardan olacakdır).", "arama": "(Ümmetimdeki münâfıkların çoğu, Kur’ân-ı kerîm okuyanlardan "}, {"kisim": 2, "madde": 53, "metin": "(Hadîkat-ün-nediyye)de, bütün bedenin âfetlerini bildirirken, yazılı olan hadîs-i şerîfde buyuruluyor ki, (Tetayyur eden ve tetayyur olunan ve kâhinlik yapan ve kâhine giden ve sihr, büyü yapan ve yapdıran ve bunlara inanan, bizden değildir. Kur’ân-ı kerîme inanmamışdır)", "arama": "Tetayyur eden ve tetayyur olunan ve kâhinlik yapan ve kâhine"}, {"kisim": 2, "madde": 53, "metin": "Buyurdu ki, (Yâ Ebâ Dücâne! Allahü teâlâ, evine hayr ve bereket versin!)", "arama": "Yâ Ebâ Dücâne! Allahü teâlâ, evine hayr ve bereket versin!"}, {"kisim": 2, "madde": 53, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (O mektûbu kaldır. Yoksa, mektûbun acısını, kıyâmete kadar çekerler!)", "arama": "O mektûbu kaldır. Yoksa, mektûbun acısını, kıyâmete kadar çe"}, {"kisim": 2, "madde": 53, "metin": "cü sahîfesindeki hadîs-i şerîfde, (Yatarken Âyet-el kürsî okuyana, şeytân yaklaşamaz)", "arama": "Yatarken Âyet-el kürsî okuyana, şeytân yaklaşamaz"}, {"kisim": 2, "madde": 61, "metin": "Übeydüllah-i Ahrârın oğlu hâce Muhammed Yahyâ buyurdu ki: (Tesarruf sâhibleri üç nev’dir: Bir kısmı, Allahü teâlânın izni ile, her istedikleri zemânda, diledikleri kimselerin kalbinde tesarruf ederek, onu fenâ makâmına erişdirirler. Ba’zısı, Allahü teâlânın emri olmadan tesarruf etmez. Emr olunan kimseye teveccüh ederler. Bir kısmı ise, kendilerine bir sıfat, bir hâl geldiği zemân kalblere tesarruf ederler)", "arama": "Tesarruf sâhibleri üç nev’dir: Bir kısmı, Allahü teâlânın iz"}, {"kisim": 2, "madde": 61, "metin": "Server-i âlem “sallallahü aleyhi ve sellem” buyurdu ki, (Karşıki ağaca git, de ki, Allahın Peygamberi seni çağırıyor!)", "arama": "Karşıki ağaca git, de ki, Allahın Peygamberi seni çağırıyor!"}, {"kisim": 2, "madde": 72, "metin": "Üstâdım [Mazher-i Cân-ı Cânân] buyurdu ki, (Nemâz kılarken, Allahü teâlâyı görmek mümkin değil ise de, görür gibi bir hâl hâsıl olmakdadır)", "arama": "Nemâz kılarken, Allahü teâlâyı görmek mümkin değil ise de, g"}, {"kisim": 2, "madde": 72, "metin": "Bu hadîs-i şerîf, (Allahü teâlâ nemâzda zuhûr ediyor, müşâhede olunuyor. Böylece gözüme râhatlık geliyor)", "arama": "Allahü teâlâ nemâzda zuhûr ediyor, müşâhede olunuyor. Böylec"}, {"kisim": 2, "madde": 72, "metin": "Bir hadîs-i şerîfde, (Yâ Bilâl “radıyallahü teâlâ anh”! Beni râhatlandır!) buyuruldu ki, (Ey Bilâl! Ezân okuyarak ve nemâzın ikâmetini söyliyerek, beni râhata kavuşdur)", "arama": "Ey Bilâl! Ezân okuyarak ve nemâzın ikâmetini söyliyerek, ben"}, {"kisim": 2, "madde": 73, "metin": "Hadîs-i şerîfde, (Küfrü açık bilinmiyen kimseye kâfir diyen, kâfir olur)", "arama": "Küfrü açık bilinmiyen kimseye kâfir diyen, kâfir olur"}, {"kisim": 2, "madde": 73, "metin": "Hadîs-i şerîfde, (Kolay şeyleri yapınız! İşlerinizi güçleşdirmeyiniz! Gücünüz yetdiği şeyleri yapınız! Allahü teâlâ, kolay olanları yapmanızı istiyor)", "arama": "Kolay şeyleri yapınız! İşlerinizi güçleşdirmeyiniz! Gücünüz "}, {"kisim": 2, "madde": 73, "metin": "Hadîs-i şerîfde, (Geceleri, Rabbimin ziyâfetindeyim. Beni doyuruyor ve içiriyor)", "arama": "Geceleri, Rabbimin ziyâfetindeyim. Beni doyuruyor ve içiriyo"}, {"kisim": 3, "madde": 1, "metin": "[Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Bir zemân gelecek ki, ümmetimde müslimânlığın yalnız adı kalacak. Mü’min olanlar, yalnız birkaç islâm âdetini yapacak. Îmânları kalmıyacak. Kur’ân-ı kerîm yalnız, okunacak. Emrlerinden, yasaklarından haberleri bile olmıyacak. Düşünceleri yalnız yiyip içmek olacak. Allahü teâlâyı unutacaklar. Yalnız paraya tapınacaklar. Kadınlara köle olacaklar. Az kazanmak ile kanâ’at etmiyecekler. Çok kaz", "arama": "Bir zemân gelecek ki, ümmetimde müslimânlığın yalnız adı kal"}, {"kisim": 3, "madde": 1, "metin": "Hadîs-i şerîfde, (Bid’at işliyenlere büyük diyen, müslimânlığı yıkmağa yardım etmiş olur)", "arama": "Bid’at işliyenlere büyük diyen, müslimânlığı yıkmağa yardım "}, {"kisim": 3, "madde": 2, "metin": "Hâlbuki hadîs-i kudsîde buyuruldu ki, (Oruc benim için tutulur. Onun karşılığını ben veririm!)", "arama": "Oruc benim için tutulur. Onun karşılığını ben veririm!"}, {"kisim": 3, "madde": 2, "metin": "sonunda diyor ki, İbni Ömer buyurdu ki, birşeyi gayb olan, çalınan kimse, hergün iki rek’at nemâz kılıp, selâmdan sonra, (Allahümme yâ Hâdî ve yâ Râddeddâlleti, erdid aleyye dâlletî bi-izzetike ve sultânike fe-innehâ min fadlike ve atâike)", "arama": "Allahümme yâ Hâdî ve yâ Râddeddâlleti, erdid aleyye dâlletî "}, {"kisim": 3, "madde": 2, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Zinânın dünyâda üç fenâlığı vardır: Biri, güzelliği ve parlaklığı giderir. İkincisi, fakîrliğe sebeb olur. Üçüncüsü, ömrün kısalmasına sebeb olur. Âhıretdeki üç zararına gelince, Allahü teâlânın gadabına sebeb olur. İkincisi, süâlin, hesâbın fenâ geçmesine sebeb olur.\n\nÜçüncüsü, Cehennem ateşinde azâb çekmeğe sebeb olur)", "arama": "Zinânın dünyâda üç fenâlığı vardır: Biri, güzelliği ve parla"}, {"kisim": 3, "madde": 2, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Yabancı kadınlara bakmak, gözlerin zinâsıdır. Onları tutmak, ellerin zinâsıdır. Onlara gitmek, ayakların zinâsıdır)", "arama": "Yabancı kadınlara bakmak, gözlerin zinâsıdır. Onları tutmak,"}, {"kisim": 3, "madde": 2, "metin": "çin (Bostân-ül-ârifîn) sonunda diyor ki, Abdüllah ibni Abbâs “radıyallahü teâlâ anhümâ” buyurdu ki, bir tas, tabak içine (Bismillâhillezî lâ ilâhe illâ huv El-Halîm-ül Kerîm. Sübhâne Rabbil’ Arş-il’azîm Elhamdülillahi Rabbil’ âlemîn)", "arama": "Bismillâhillezî lâ ilâhe illâ huv El-Halîm-ül Kerîm. Sübhâne"}, {"kisim": 3, "madde": 2, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Hac edenin geçmiş günâhları afv olur!)", "arama": "Hac edenin geçmiş günâhları afv olur!"}, {"kisim": 3, "madde": 2, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Müslimânlıkda, uğursuzluk ve hastalığın sağlam kimseye muhakkak geçmesi yokdur)", "arama": "Müslimânlıkda, uğursuzluk ve hastalığın sağlam kimseye muhak"}, {"kisim": 3, "madde": 2, "metin": "Hadîs-i şerîfde buyuruldu ki, (Müslimân sihr yapamaz. Allah saklasın îmânı gitdikden sonra, sihri te’sîr eder.)", "arama": "Müslimân sihr yapamaz. Allah saklasın îmânı gitdikden sonra,"}, {"kisim": 3, "madde": 3, "metin": "Buyurdu ki, (Allahü teâlâ güzeldir. Yalnız güzel yapılan ibâdetleri kabûl eder. Allahü teâlâ, Peygamberlerine emr etdiğini, mü’minlere de emr etdi ve buyurdu ki, ey Peygamberlerim! Halâl yiyiniz ve sâlih, iyi işler yapınız! Mü’minlere de emr etdi ki, ey îmân edenler! Sizlere verdiğim rızklardan halâl olanları yiyiniz!)", "arama": "Allahü teâlâ güzeldir. Yalnız güzel yapılan ibâdetleri kabûl"}, {"kisim": 3, "madde": 3, "metin": "Resûl “aleyhisselâm” sözüne devâm ederek buyurdu ki, (Uzak yoldan gelmiş, saçı sakalı dağılmış, yüzü gözü toz içinde bir kimse, ellerini göke doğru uzatıp düâ ediyor. “Yâ Rabbî!” diye yalvarıyor. Hâlbuki yidiği harâm, içdiği harâm, gıdâsı hep harâm. Bunun düâsı nasıl kabûl olur?)", "arama": "Uzak yoldan gelmiş, saçı sakalı dağılmış, yüzü gözü toz için"}, {"kisim": 3, "madde": 3, "metin": "Hadîs-i şerîfde, (Elinin emeği, alnının teri ile yi, dînini satıp yime!)", "arama": "Elinin emeği, alnının teri ile yi, dînini satıp yime!"}, {"kisim": 3, "madde": 3, "metin": "Bir hadîs-i şerîfde, (Halâle, harâma dikkat ederek çalışıp kazanan kimseyi, Allahü teâlâ çok sever)", "arama": "Halâle, harâma dikkat ederek çalışıp kazanan kimseyi, Allahü"}, {"kisim": 3, "madde": 3, "metin": "Bir hadîs-i şerîfde, (Bir dirhem gümüş kıymetinde harâm alan kimseyi, yirmibeşbin sene Cehennemde bırakacaklardır)", "arama": "Bir dirhem gümüş kıymetinde harâm alan kimseyi, yirmibeşbin "}, {"kisim": 3, "madde": 3, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Bir zemân gelecek ki, insanlar, yalnız malın, paranın gelmesini düşünüp, halâlini, harâmını düşünmiyecekler)", "arama": "Bir zemân gelecek ki, insanlar, yalnız malın, paranın gelmes"}, {"kisim": 3, "madde": 3, "metin": "(Buhârî)deki bir hadîs-i şerîfde buyuruluyor ki, (İnsanın yidiklerinin en hayrlısı, iyisi, bileği ile kazanıp yidiğidir. Allahü teâlânın Peygamberi Dâvüd “aleyhisselâm” elinin emeği ile kazanıp yirdi)", "arama": "İnsanın yidiklerinin en hayrlısı, iyisi, bileği ile kazanıp "}, {"kisim": 3, "madde": 3, "metin": "Bir hadîs-i şerîfde, (Bir müslimân, halâl kazanıp, kimseye muhtâc olmaz ve komşularına, akrabâsına yardım ederse, kıyâmet günü, ayın ondördü gibi parlak, nûrlu olacakdır)", "arama": "Bir müslimân, halâl kazanıp, kimseye muhtâc olmaz ve komşula"}, {"kisim": 3, "madde": 3, "metin": "Bir hadîs-i şerîfde, (Doğru olan tüccâr, kıyâmetde sıddîklarla ve şehîdlerle berâber olacakdır)", "arama": "Doğru olan tüccâr, kıyâmetde sıddîklarla ve şehîdlerle berâb"}, {"kisim": 3, "madde": 3, "metin": "Bir hadîs-i şerîfde, (Allahü teâlâ, san’at sâhibi mü’mini sever)", "arama": "Allahü teâlâ, san’at sâhibi mü’mini sever"}, {"kisim": 3, "madde": 3, "metin": "Bir hadîs-i şerîfde, (En halâl şey, san’at sâhibinin kazandığıdır)", "arama": "En halâl şey, san’at sâhibinin kazandığıdır"}, {"kisim": 3, "madde": 3, "metin": "Bir hadîs-i şerîfde, (Ticâret yapınız! Rızkın onda dokuzu ticâretdedir)", "arama": "Ticâret yapınız! Rızkın onda dokuzu ticâretdedir"}, {"kisim": 3, "madde": 3, "metin": "Bir hadîs-i şerîfde, (Kendini başkasından sadaka istiyecek hâle düşüreni, Allahü teâlâ yetmiş şeye muhtâc eder)", "arama": "Kendini başkasından sadaka istiyecek hâle düşüreni, Allahü t"}, {"kisim": 3, "madde": 3, "metin": "İbrâhîm Edhem “kaddesallahü teâlâ sirrehül’azîz” buyurdu ki, öyle söyleme, hadîs-i şerîfde buyuruldu ki, (Halâl kazanmak için sıkıntı çekenlere Cennet vâcib olur)", "arama": "Halâl kazanmak için sıkıntı çekenlere Cennet vâcib olur"}, {"kisim": 3, "madde": 3, "metin": "Süâl: Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Bana, tüccâr ol, mal topla diye emr olunmadı. Fekat, Rabbini tesbîh et ve ona secde et. Rabbine ölünciye kadar ibâdet et! diye emr olundu)", "arama": "Bana, tüccâr ol, mal topla diye emr olunmadı. Fekat, Rabbini"}, {"kisim": 3, "madde": 3, "metin": "Hadîs-i şerîfde, (Beş vakt nemâzı kıldıkdan sonra, çalışıp halâl kazanmak, her müslimâna farzdır)", "arama": "Beş vakt nemâzı kıldıkdan sonra, çalışıp halâl kazanmak, her"}, {"kisim": 3, "madde": 3, "metin": "Hadîs-i şerîfde, (İnsanların iyisi, insanlara fâidesi olanlardır)", "arama": "İnsanların iyisi, insanlara fâidesi olanlardır"}, {"kisim": 3, "madde": 3, "metin": "105 deki hadîs-i şerîfde, (Eshâbım için fakîrlik se’âdetdir. Âhır zemândaki ümmetim için, zenginlik se’âdetdir)", "arama": "Eshâbım için fakîrlik se’âdetdir. Âhır zemândaki ümmetim içi"}, {"kisim": 3, "madde": 3, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Allahü teâlâ benim rızkımı, süngümün ucuna koymuşdur).", "arama": "(Allahü teâlâ benim rızkımı, süngümün ucuna koymuşdur)."}, {"kisim": 3, "madde": 12, "metin": "Hadîs-i şerîfde, (Iyne satışı yaparsanız ve cihâdı terkedip, zirâ’at ile uğraşırsanız, Allahü teâlâ sizi zelîl eder. Dîninize dönmedikce, bu zilletden kurtulamazsınız!)", "arama": "Iyne satışı yaparsanız ve cihâdı terkedip, zirâ’at ile uğraş"}, {"kisim": 3, "madde": 15, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse gıdâ maddelerini alıp, pahâlı olup da satmak için kırk gün saklarsa, hepsini fakîrlere parasız dağıtsa, günâhını ödiyemez)", "arama": "Bir kimse gıdâ maddelerini alıp, pahâlı olup da satmak için "}, {"kisim": 3, "madde": 15, "metin": "Yine buyurdu ki, (Bir kimse gıdâ maddelerini kırk gün saklarsa, Allahü teâlâ ona darılır. O, Allahü teâlâyı saymamış olur)", "arama": "Bir kimse gıdâ maddelerini kırk gün saklarsa, Allahü teâlâ o"}, {"kisim": 3, "madde": 15, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Bir kimse, hâricden gıdâ maddesi satın alıp, şehre getirir ve piyasaya göre satarsa, sadaka vermiş gibi sevâb kazanır veyâ köle âzâd etmiş gibi sevâb kazanır)", "arama": "Bir kimse, hâricden gıdâ maddesi satın alıp, şehre getirir v"}, {"kisim": 3, "madde": 15, "metin": "Cevâbında buyurdu ki, (Biz, az kâr ile çok sevâb kazanmağı dahâ çok severiz. Fazla kazanmak için, dînimizi fedâ etmemeli idin. Çok büyük cinâyet yapmışsın. Bunu afv etdirmek için sermâyeyi ve kârı hemen sadaka olarak dağıt!)", "arama": "Biz, az kâr ile çok sevâb kazanmağı dahâ çok severiz. Fazla "}, {"kisim": 3, "madde": 15, "metin": "Hadîs-i şerîfde buyuruldu ki, (Alış-verişde vallahi böyledir, vallahi öyle değildir diye yemîn edenlere ve san’at sâhiblerinden, yarın gel, öbür gün gel diye sözünde durmıyanlara yazıklar olsun!)", "arama": "Alış-verişde vallahi böyledir, vallahi öyle değildir diye ye"}, {"kisim": 3, "madde": 15, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Malını yemîn ederek beğendiren kimseye kıyâmet günü merhamet edilmiyecek, acınmıyacakdır)", "arama": "Malını yemîn ederek beğendiren kimseye kıyâmet günü merhamet"}, {"kisim": 3, "madde": 15, "metin": "Buyurdu ki, (Satılan birşeyin kusûrunu gizlemek halâl değildir. O kusûru bilip söylememek de, kimseye halâl değildir.)", "arama": "Satılan birşeyin kusûrunu gizlemek halâl değildir. O kusûru "}, {"kisim": 3, "madde": 15, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Ticârete hıyânet karışınca, bereket gider)", "arama": "Ticârete hıyânet karışınca, bereket gider"}, {"kisim": 3, "madde": 15, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Lâ ilâhe illallah diyenler, dünyâyı dinden üstün tutmadıkca, Allahü teâlânın gadabından, azâbından kurtulurlar. Dîni bırakıp, dünyâya sarılırlarsa, bu kelime-i tevhîdi söyleyince, Allahü teâlâ, onlara, yalan söylüyorsun! buyurur)", "arama": "Lâ ilâhe illallah diyenler, dünyâyı dinden üstün tutmadıkca,"}, {"kisim": 3, "madde": 15, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Ticârete hıyânet karışınca, bereket gider).", "arama": "(Ticârete hıyânet karışınca, bereket gider)."}, {"kisim": 3, "madde": 15, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Lâ ilâhe illallah diyenler, dünyâyı dinden üstün tutmadıkca, Allahü teâlânın gadabından, azâbından kurtulurlar.", "arama": "(Lâ ilâhe illallah diyenler, dünyâyı dinden üstün tutmadıkca"}, {"kisim": 3, "madde": 16, "metin": "] Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Alış-verişde kolaylık gösterenlere, Allahü teâlâ, her işinde kolaylık gösterir)", "arama": "Alış-verişde kolaylık gösterenlere, Allahü teâlâ, her işinde"}, {"kisim": 3, "madde": 16, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Kıyâmetde bir kimseyi hesâba çekerler ki, çok günâh işlemiş, hiç iyilik yapmamış. Sen dünyâda hiç iyilik yapmadın mı? derler. Hayır, yalnız çırağıma derdim ki, (Fakîr olan borcluları sıkışdırma! Ne zemân ellerine geçerse, o zemân vermelerini söyle. İstediklerini yine ver. Boş çevirme!)", "arama": "Kıyâmetde bir kimseyi hesâba çekerler ki, çok günâh işlemiş,"}, {"kisim": 3, "madde": 16, "metin": ") Hadîs-i şerîfde buyuruldu ki: (Bir müslimâna, Allah rızâsı için ödünc veren kimseye, hergün için sadaka sevâbı verilir. Fakîrden, alacağını çabuk istemiyene, hergün için malın hepsini sadaka vermiş gibi sevâb verilir)", "arama": "Bir müslimâna, Allah rızâsı için ödünc veren kimseye, hergün"}, {"kisim": 3, "madde": 16, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Sadaka verilen her dirhem için on sevâb, ödünc verilen her dirhem için ise, onsekiz sevâb vardır. Çünki, borc, ihtiyâcı olana verilir. Sadaka belki, ihtiyâcı olmayanın eline düşebilir)", "arama": "Sadaka verilen her dirhem için on sevâb, ödünc verilen her d"}, {"kisim": 3, "madde": 16, "metin": "Hadîs-i şerîfde buyuruldu ki, (En iyiniz, borcunu iyi ödiyeninizdir)", "arama": "En iyiniz, borcunu iyi ödiyeninizdir"}, {"kisim": 3, "madde": 16, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Ödünc alan bir kimse, iyice ödemeği niyyet ederse, borcunu ödemesi için, melekler ona düâ eder)", "arama": "Ödünc alan bir kimse, iyice ödemeği niyyet ederse, borcunu ö"}, {"kisim": 3, "madde": 16, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Alış-verişde kolaylık gösterenlere, Allahü teâlâ, her işinde kolaylık gösterir).", "arama": "(Alış-verişde kolaylık gösterenlere, Allahü teâlâ, her işind"}, {"kisim": 3, "madde": 16, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Kıyâmetde bir kimseyi hesâba çekerler ki, çok günâh işlemiş, hiç iyilik yapmamış.", "arama": "(Kıyâmetde bir kimseyi hesâba çekerler ki, çok günâh işlemiş"}, {"kisim": 3, "madde": 17, "metin": "Hadîs-i şerîfde buyuruldu ki, (En iyi ticâret, bezzâzlıkdır, kumaş satmakdır. En iyi san’at, terzilikdir)", "arama": "En iyi ticâret, bezzâzlıkdır, kumaş satmakdır. En iyi san’at"}, {"kisim": 3, "madde": 17, "metin": "Halîfe Ömer “radıyallahü anh” buyurdu ki, (Ey tüccârlar! Önce âhıret rızkını kazanın! Sonra dünyâ rızkına çalışın!)", "arama": "Ey tüccârlar! Önce âhıret rızkını kazanın! Sonra dünyâ rızkı"}, {"kisim": 3, "madde": 17, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Melekler insanların amel defterlerini götürdükleri zemân, başında ve sonunda iyi iş yazılı ise, gün ortasında yapılanları ona bağışlarlar)", "arama": "Melekler insanların amel defterlerini götürdükleri zemân, ba"}, {"kisim": 3, "madde": 17, "metin": "Yine buyurdu ki, (Gündüz ve gece melekleri, sabâh ve akşam, gidip gelirken birbirleri ile karşılaşırlar. Hak teâlâ, [giden meleklere], kullarımı nasıl bırakdınız? buyurur. Yâ Rabbî! Nemâzda bulduk ve nemâz kılarken bırakdık, derler. Allahü teâlâ da, şâhid olun, onları afv etdim buyurur)", "arama": "Gündüz ve gece melekleri, sabâh ve akşam, gidip gelirken bir"}, {"kisim": 3, "madde": 17, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Gâfiller arasında Allahü teâlâyı zikr eden kimse, kurumuş ağaçlar arasında bulunan yeşil fidân gibidir ve ölüler arasındaki cânlı gibidir ve harbde kaçanlar arasında, arslan gibi döğüşenler gibidir)", "arama": "Gâfiller arasında Allahü teâlâyı zikr eden kimse, kurumuş ağ"}, {"kisim": 3, "madde": 17, "metin": "Bir kerre buyurdu ki, (Çarşıya giderken, lâ ilâhe illallah, vahde hü lâ şerîke leh, le hül mülkü ve le hül hamdü, yuhyî ve yümît, ve hüve hayyün lâ yemût, bi yedi-hil-hayr, ve hüve alâ külli şey’in kadîr diyen kimseye, iki milyon sevâb yazılır)", "arama": "Çarşıya giderken, lâ ilâhe illallah, vahde hü lâ şerîke leh,"}, {"kisim": 3, "madde": 17, "metin": "] Cüneyd-i Bağdâdî “kuddise sirruh” buyurdu ki, (Pazarda çok kimse vardır ki, sôfîler halkasında oturanlardan dahâ kıymetlidir)", "arama": "Pazarda çok kimse vardır ki, sôfîler halkasında oturanlardan"}, {"kisim": 3, "madde": 17, "metin": "Bir kerre de buyurdu ki: (Öyle kimse tanıyorum ki, pazarda hergün üçyüz rek’at nemâz kılmakda ve otuz bin tesbîh okumakdadır)", "arama": "Öyle kimse tanıyorum ki, pazarda hergün üçyüz rek’at nemâz k"}, {"kisim": 3, "madde": 17, "metin": "Hadîs-i şerîfde buyuruldu ki, (Tüccârın, esnâfın en kötüsü, erken gidip, geç dönenlerdir)", "arama": "Tüccârın, esnâfın en kötüsü, erken gidip, geç dönenlerdir"}, {"kisim": 3, "madde": 17, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir zemân gelir ki, o zemânın müslimânları, bugün sizin yapdığınız ibâdetlerin onda birini yaparsa, âhıretde azâbdan kurtulurlar)", "arama": "Bir zemân gelir ki, o zemânın müslimânları, bugün sizin yapd"}, {"kisim": 3, "madde": 17, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Gâfiller arasında Allahü teâlâyı zikr eden kimse, kurumuş ağaçlar arasında bulunan yeşil fidân gibidir ve ölüler arasındaki cânlı gibidir ve harbde kaçanlar arasında, arslan gibi döğüşenler gibidir).", "arama": "(Gâfiller arasında Allahü teâlâyı zikr eden kimse, kurumuş a"}, {"kisim": 3, "madde": 17, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir zemân gelir ki, o zemânın müslimânları, bugün sizin yapdığınız ibâdetlerin onda birini yaparsa, âhıretde azâbdan kurtulurlar).", "arama": "(Bir zemân gelir ki, o zemânın müslimânları, bugün sizin yap"}, {"kisim": 3, "madde": 19, "metin": "(Mecmâ’ul-enhür)de diyor ki, (Hadîs-i şerîfde, (Dâr-ül-harbde, müslimân ile kâfir arasında fâiz yokdur)", "arama": "Dâr-ül-harbde, müslimân ile kâfir arasında fâiz yokdur"}, {"kisim": 3, "madde": 19, "metin": "Kâdî zâde, (Feth-ul-kadîr) tekmilesinde yukarıdaki hadîs-i şerîfi açıklarken diyor ki: (Hicretden önce Kureyş müşrikleri, ehl-i kitâb olan rumların acem kâfirlerine yenilmelerine sevinmişlerdi. Rum sûresi nâzil olup, acemlerin az zemân sonra yenilecekleri bildirilince, Ebû Bekr-i Sıddîk, Kureyş kâfirleri ile sözleşme yapdı. Acemler yenildi. Ebû Bekr-i Sıddîk da sözleşilen develeri Kureyş kâfirlerinden aldı. Bu sözleşme kumar idi. Mekke şehri de, ", "arama": "Hicretden önce Kureyş müşrikleri, ehl-i kitâb olan rumların "}, {"kisim": 3, "madde": 21, "metin": "Çünki, hadîs-i şerîfde, (Kur’ân-ı kerîm okuyunuz. Fekat, bunu geçim vâsıtası yapmayınız!)", "arama": "Kur’ân-ı kerîm okuyunuz. Fekat, bunu geçim vâsıtası yapmayın"}, {"kisim": 3, "madde": 21, "metin": "Bir hadîs-i şerîfde, (Ezân okuyun. Ezân için ücret almayın!)", "arama": "Ezân okuyun. Ezân için ücret almayın!"}, {"kisim": 3, "madde": 22, "metin": "(Müslim)deki hadîs-i şerîfde, (Serhoş eden her içki şerâb gibi harâmdır)", "arama": "Serhoş eden her içki şerâb gibi harâmdır"}, {"kisim": 3, "madde": 23, "metin": "Hadîs-i şerîfde, (Günâh işliyeni gören, eli ile mâni’ olsun. Buna gücü yetmezse, dili ile mâni’ olsun!)", "arama": "Günâh işliyeni gören, eli ile mâni’ olsun. Buna gücü yetmezs"}, {"kisim": 3, "madde": 23, "metin": "Hadîs-i şerîfde, (Allahü teâlâdan hayâ ediniz!)", "arama": "Allahü teâlâdan hayâ ediniz!"}, {"kisim": 3, "madde": 23, "metin": "Bir hadîs-i şerîfde, (Hayâ, îmândandır. Fuhş söylemek, cefâdandır. Îmân Cennete, cefâ Cehenneme götürür)", "arama": "Hayâ, îmândandır. Fuhş söylemek, cefâdandır. Îmân Cennete, c"}, {"kisim": 3, "madde": 23, "metin": "Bir hadîs-i şerîfde, (Fuhş insanın lekesi, hayâ, zînetidir)", "arama": "Fuhş insanın lekesi, hayâ, zînetidir"}, {"kisim": 3, "madde": 24, "metin": "(Berîka)da, (hıkd) kötü huyu anlatılırken yazılı hadîs-i şerîfde, (Kul haklarını ödeyen, her nemâzdan sonra onbir ihlâs-i şerîf okuyan ve kâtilini afv ederek ölen Cennete girecekdir)", "arama": "Kul haklarını ödeyen, her nemâzdan sonra onbir ihlâs-i şerîf"}, {"kisim": 3, "madde": 24, "metin": "(Buhârî)deki hadîs-i şerîfde, (Ekber-i kebâir, birşeyi Allahü teâlâya ortak etmek, adam öldürmek, anaya, babaya karşı gelmek, yalancı şâhidlik yapmakdır)", "arama": "Ekber-i kebâir, birşeyi Allahü teâlâya ortak etmek, adam öld"}, {"kisim": 3, "madde": 26, "metin": "(Berîka)da, ayak âfetleri başındaki hadîs-i şerîfde, (Ananın, babanın yüzüne merhamet ile bakana, makbûl hac sevâbı verilir)", "arama": "Ananın, babanın yüzüne merhamet ile bakana, makbûl hac sevâb"}, {"kisim": 3, "madde": 27, "metin": "Muhammed Behâeddîn-i Buhârî buyurdu ki, (Mevlânâ Zeyn-üd-dîn-i Taybâdî “kaddesallahü teâlâ sirrehül’azîz” ilm ile Allahü teâlâya vâsıl olmuşdur)", "arama": "Mevlânâ Zeyn-üd-dîn-i Taybâdî “kaddesallahü teâlâ sirrehül’a"}, {"kisim": 3, "madde": 27, "metin": "Çünki, hadîs-i şerîfde, (Onlar görüldüğü vakt, Allah hâtırlanır)", "arama": "Onlar görüldüğü vakt, Allah hâtırlanır"}, {"kisim": 3, "madde": 28, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyuruyor ki, (Bir kimsenin havada uçduğunu ve deniz üzerinde yürüdüğünü yâhud ağzına ateş koyup yutduğunu görseniz, fekat islâmiyyete uymıyan bir iş yapsa, kerâmet sâhibiyim derse de, onu büyücü, yalancı, sapık ve insanları doğru yoldan sapdırıcı biliniz!)", "arama": "Bir kimsenin havada uçduğunu ve deniz üzerinde yürüdüğünü yâ"}, {"kisim": 3, "madde": 29, "metin": "! Bu kelimenin üstünlüklerini dinleyiniz: Resûlullah “sallallahü teâlâ aleyhi ve âlihi ve selleme ve bâreke” buyurdu ki: (Lâ ilâhe illallah diyen kimse Cennete girer)", "arama": "Lâ ilâhe illallah diyen kimse Cennete girer"}, {"kisim": 3, "madde": 31, "metin": "Evet bir hadîs-i şerîfde, (Zemânların en hayrlısı benim zemânımdır)", "arama": "Zemânların en hayrlısı benim zemânımdır"}, {"kisim": 3, "madde": 33, "metin": "Allahü teâlâ, hadîs-i kudsîde, (Yere ve göke sığmam. Fekat, mü’min kulumun kalbine sığarım)", "arama": "Yere ve göke sığmam. Fekat, mü’min kulumun kalbine sığarım"}, {"kisim": 3, "madde": 38, "metin": "Bir hadîs-i şerîfde, (Câhiliyye zemânında iyi olanlarınız, müslimân olup din bilgilerini öğrenince de, en iyiniz olur!)", "arama": "Câhiliyye zemânında iyi olanlarınız, müslimân olup din bilgi"}, {"kisim": 3, "madde": 44, "metin": "Hadîs-i şerîfde, (Allahü teâlâ ile kul arasında, yetmişbin nûrdan perde ve yetmişbin zulmetden perde vardır)", "arama": "Allahü teâlâ ile kul arasında, yetmişbin nûrdan perde ve yet"}, {"kisim": 3, "madde": 44, "metin": ", nümûnelerin üstüne çıkarılmış olunca, bilgilerde hiç şübhe olur mu? Hocam [Muhammed Bâkî] “kuddise sirruh” buyurdu ki, (Hâllerin doğru olmasına alâmet, bunlara tam bir yakîn ve inanmakdır)", "arama": "Hâllerin doğru olmasına alâmet, bunlara tam bir yakîn ve ina"}, {"kisim": 3, "madde": 44, "metin": "Muhammed Behâeddîn-i Buhârî “kuddise sirruh” buyurdu ki, (Her gördüğün, her işitdiğin ve her bildiğin, O değildir. Bunların hepsini, (Lâ)", "arama": "Her gördüğün, her işitdiğin ve her bildiğin, O değildir. Bun"}, {"kisim": 3, "madde": 50, "metin": "e buyuruluyor ki, (Âlimler, Peygamberlerin vârisleridir), (Evliyâ ol kimselerdir ki, Onlar görülünce, Allah hâtırlanır), (Herşeyin hâsıl olduğu yer vardır. Takvânın elde edildiği yer, âriflerin kalbleridir)", "arama": "Herşeyin hâsıl olduğu yer vardır. Takvânın elde edildiği yer"}, {"kisim": 3, "madde": 51, "metin": "Hadîs-i kudsîde, (O olmasaydı, Allahü teâlâ mahlûkları elbette yaratmazdı ve rübûbiyyetini belli etmezdi)", "arama": "O olmasaydı, Allahü teâlâ mahlûkları elbette yaratmazdı ve r"}, {"kisim": 3, "madde": 51, "metin": "Sahîh olan hadîs-i şerîfde buyuruldu ki, (İnsan nemâza başlayınca, Allahü teâlâ ile kul arasında olan perde kalkar)", "arama": "İnsan nemâza başlayınca, Allahü teâlâ ile kul arasında olan "}, {"kisim": 3, "madde": 52, "metin": "Bunun gibi, hadîs-i şerîfde, (Siz dünyâ işlerinizi dahâ iyi bilirsiniz!)", "arama": "Siz dünyâ işlerinizi dahâ iyi bilirsiniz!"}, {"kisim": 3, "madde": 52, "metin": "Büyük üstâd buyurdu ki: (Kulluk ile sâhiblik, âmirlik ve me’mûrluk bir arada olamaz)", "arama": "Kulluk ile sâhiblik, âmirlik ve me’mûrluk bir arada olamaz"}, {"kisim": 3, "madde": 53, "metin": "Resûlullah buyurdu ki, (Âhıretde azâb görmez,\n dünyâ işlerinde, bana tâbi’ olan)", "arama": "Âhıretde azâb görmez,\n dünyâ işlerinde, bana tâbi’ olan"}, {"kisim": 3, "madde": 53, "metin": "Resûlullah buyurdu ki, (Âhıretde azâb görmez,\n dünyâ işlerinde, bana tâbi’ olan).", "arama": "(Âhıretde azâb görmez,\n dünyâ işlerinde, bana tâbi’ olan)."}, {"kisim": 3, "madde": 55, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Lezzetleri yıkan, eğlencelere son veren ölümü çok hâtırlayınız!)", "arama": "Lezzetleri yıkan, eğlencelere son veren ölümü çok hâtırlayın"}, {"kisim": 3, "madde": 55, "metin": "Hadîs-i şerîfde buyuruldu ki, (İnsanlar uykudadır, ölünce uyanırlar)", "arama": "İnsanlar uykudadır, ölünce uyanırlar"}, {"kisim": 3, "madde": 55, "metin": "Hadîs-i şerîfde buyuruldu ki, (Yanında Yasîn-i şerîf okunan hasta, suya doymuş olarak vefât eder ve doymuş olarak kabre girer)", "arama": "Yanında Yasîn-i şerîf okunan hasta, suya doymuş olarak vefât"}, {"kisim": 3, "madde": 55, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Ölüm hastası yanında, bir sûre okununca, her harfi için bir melek gelip, rûhun kolay çıkmasına düâ eder. Yıkanırken yanında bulunurlar. Cenâzesi ile birlikde giderler. Nemâzında bulunurlar. Gömülürken bulunurlar. Hep düâ ederler)", "arama": "Ölüm hastası yanında, bir sûre okununca, her harfi için bir "}, {"kisim": 3, "madde": 55, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Müslimân bir hasta yanında Yasîn-i şerîf okunursa, Rıdvân ismindeki melek Cennet şerbeti getirir. Suya doymuş olarak rûh teslîm eder. Doymuş olarak kabre girer. Suya ihtiyâcı olmaz.)", "arama": "Müslimân bir hasta yanında Yasîn-i şerîf okunursa, Rıdvân is"}, {"kisim": 3, "madde": 55, "metin": "Allahü teâlâ, hadîs-i kudsîde buyuruyor ki, (Kulum, beni nasıl umarsa, onu öyle karşılarım. Öyle ise, benden hep iyilik bekleyiniz!)", "arama": "Kulum, beni nasıl umarsa, onu öyle karşılarım. Öyle ise, ben"}, {"kisim": 3, "madde": 55, "metin": "Server-i âlem “sallallahü aleyhi ve sellem”, vefâtından üç gün önce buyurdu ki, (Allahü teâlâdan iyilik umarak cân veriniz!)", "arama": "Allahü teâlâdan iyilik umarak cân veriniz!"}, {"kisim": 3, "madde": 55, "metin": "Hadîs-i şerîfde buyuruldu ki, (Bir kimse, Allahü teâlâya kavuşmağı severse, Allahü teâlâ da ona kavuşmağı sever)", "arama": "Bir kimse, Allahü teâlâya kavuşmağı severse, Allahü teâlâ da"}, {"kisim": 3, "madde": 55, "metin": "Hadîs-i şerîfde buyuruldu ki, (Hastalığınızı tedâvî ediniz! Çünki, Allahü teâlâ, ölümden başka her hastalık için, devâ, ilâc yaratmışdır)", "arama": "Hastalığınızı tedâvî ediniz! Çünki, Allahü teâlâ, ölümden ba"}, {"kisim": 3, "madde": 55, "metin": "Hadîs-i şerîfde, (Allahü teâlâyı unutarak, gafletle edilen düâ kabûl olmaz)", "arama": "Allahü teâlâyı unutarak, gafletle edilen düâ kabûl olmaz"}, {"kisim": 3, "madde": 55, "metin": "Hadîs-i şerîfde, (Allahü teâlânın bir ni’met vermesini ve bunun devâmlı olmasını isteyen, Lâ havle velâ kuvvete illâ billah çok okusun!)", "arama": "Allahü teâlânın bir ni’met vermesini ve bunun devâmlı olması"}, {"kisim": 3, "madde": 55, "metin": "(Sahîhayn)daki hadîs-i şerîfde, (Bu, Cennet hazînelerinden bir hazînedir!)", "arama": "Bu, Cennet hazînelerinden bir hazînedir!"}, {"kisim": 3, "madde": 55, "metin": "Bir hadîs-i şerîfde de, (Lâ havle velâ kuvvete okumak, doksandokuz derde devâdır. Bunların en hafîfi, hemmdir)", "arama": "Lâ havle velâ kuvvete okumak, doksandokuz derde devâdır. Bun"}, {"kisim": 3, "madde": 55, "metin": "r)da diyor ki: Ömer-ül-Fârûk “radıyallahü teâlâ anh” dedi ki, Resûlullah “sallallahü teâlâ aleyhi ve sellem” buyurdu ki: (Yağmur suyunu toplayıp, üzerine, Fâtiha-i şerîfe, Âyet-el-kürsî, İhlâs-ı şerîf ve Kul-e’ûzü sûreleri yetmişer kerre okunur. Bu sudan aralıksız yedi sabâh içenlerin hastalıkları, ağrıları zâil olur.)", "arama": "Yağmur suyunu toplayıp, üzerine, Fâtiha-i şerîfe, Âyet-el-kü"}, {"kisim": 3, "madde": 55, "metin": "dirdiler ki, Sa’d ibni Mâlik “radıyallahü teâlâ anh” dedi ki, Resûlullah “sallallahü teâlâ aleyhi ve sellem” buyurdu ki: (Yûnüs aleyhisselâm balığın karnında, Enbiyâ sûresinin 87. ci âyetini söyliyerek düâ etdi. [Düâsını kabûl eyledi ve kıyâmete kadar bunu okuyan mü’minlerin düâlarını kabûl edeceğini bildirdi.] Bir müslimân, bu âyet-i kerîmeyi okuyup düâ edince, Allahü teâlâ düâsını muhakkak kabûl eder)", "arama": "Yûnüs aleyhisselâm balığın karnında, Enbiyâ sûresinin 87. ci"}, {"kisim": 3, "madde": 58, "metin": "Hadîs-i şerîfde buyuruldu ki: (Cenâzeyi kırk adım taşıyanın kırk büyük günâhı afv olur.)", "arama": "Cenâzeyi kırk adım taşıyanın kırk büyük günâhı afv olur."}, {"kisim": 3, "madde": 58, "metin": "(Künûz-üd-dekâık)da yazılı ibni Mâcenin bildirdiği hadîs-i şerîfde, (Cenâzeyi yüksek sesle ve ateş, ışık ve başka şeyler taşıyarak götürmeyiniz!)", "arama": "Cenâzeyi yüksek sesle ve ateş, ışık ve başka şeyler taşıyara"}, {"kisim": 3, "madde": 58, "metin": "(Necât-ül-müsallî)de diyor ki, (Hısn-ül-hasîn)de diyor ki, hadîs-i şerîfde, (Bir hasta, lâ ilâhe illâ ente sübhâneke innî küntü minezzâlimîn kırk def’a okursa, şehîd olarak vefât eder. Şifâ bulursa, günâhları afv olur)", "arama": "Bir hasta, lâ ilâhe illâ ente sübhâneke innî küntü minezzâli"}, {"kisim": 3, "madde": 59, "metin": "Hadîs-i şerîfde, (Ana-babasının veyâ ikisinden birinin kabrini her Cum’a günleri ziyâret edenin günâhları afv olur. Haklarını ödemiş olur)", "arama": "Ana-babasının veyâ ikisinden birinin kabrini her Cum’a günle"}, {"kisim": 3, "madde": 59, "metin": "Hadîs-i şerîfde buyuruldu ki, (Bir mü’minin kabrini ziyâret ederken, Allahümme innî es’elüke-bi-hurmet-i Muhammed aleyhisselâm en lâ tü’azzibe hâzelmeyyit derse, o meyyitin azâbı kıyâmete kadar ref’ olur)", "arama": "Bir mü’minin kabrini ziyâret ederken, Allahümme innî es’elük"}, {"kisim": 3, "madde": 59, "metin": "Hadîs-i şerîfde buyuruldu ki, (Bir kimse, tanıdığının kabri yanından geçerken selâm verirse, meyyit bunu tanır ve selâmına cevâb verir)", "arama": "Bir kimse, tanıdığının kabri yanından geçerken selâm verirse"}, {"kisim": 3, "madde": 59, "metin": "Hadîs-i şerîfde buyuruldu ki, (Bir kimse, kabristândan geçerken, onbir kerre İhlâs sûresi okuyup sevâbını meyyitlere hediyye ederse, kendisine ölüler adedince sevâb verilir)", "arama": "Bir kimse, kabristândan geçerken, onbir kerre İhlâs sûresi o"}, {"kisim": 3, "madde": 59, "metin": "(Şir’at-ül-islâm) şerhindeki hadîs-i şerîfde, (Ümmetimin yapdığı ibâdetlerin en kıymetlisi, Kur’ân-ı kerîmi, Mushafa bakarak okumakdır)", "arama": "Ümmetimin yapdığı ibâdetlerin en kıymetlisi, Kur’ân-ı kerîmi"}, {"kisim": 3, "madde": 59, "metin": "[Muhammed Ma’sûm hazretlerinin (Mektûbât)ının üçüncü cildi, doksanüçüncü mektûbunda yazılı hadîs-i şerîfde, (Nemâzda okunan Kur’ân, nemâz dışında okunan Kur’ândan dahâ hayrlıdır)", "arama": "Nemâzda okunan Kur’ân, nemâz dışında okunan Kur’ândan dahâ h"}, {"kisim": 3, "madde": 59, "metin": "] Hazret-i Alî “radıyallahü anh” buyurdu ki, (Nemâzda ayakda iken okunan Kur’ânın her harfi için yüz sevâb verilir. Nemâz dışında abdestli okuyunca, her harfi için yirmibeş sevâb verilir. Abdestsiz okuyunca, on sevâb verilir. Yürürken ve iş yaparken okuyunca, dahâ az sevâb verilir.)", "arama": "Nemâzda ayakda iken okunan Kur’ânın her harfi için yüz sevâb"}, {"kisim": 3, "madde": 59, "metin": "Hadîs-i şerîfde buyuruldu ki, (Kur’ân-ı kerîmi tecvîd bilgisine uyarak okuyunca, her harfine yirmi sevâb verilir. Tecvîde uymazsa, on sevâb verilir)", "arama": "Kur’ân-ı kerîmi tecvîd bilgisine uyarak okuyunca, her harfin"}, {"kisim": 3, "madde": 59, "metin": "Ebû Hüreyre “radıyallahü anh” buyurdu ki, (Kur’ân okunan eve, bereket, iyilik gelir. Melekler oraya toplanır. Şeytânlar oradan kaçar)", "arama": "Kur’ân okunan eve, bereket, iyilik gelir. Melekler oraya top"}, {"kisim": 3, "madde": 59, "metin": "Hadîs-i şerîfde, (İnsanın dinlediği bir âyet, kıyâmetde kendine nûr olur)", "arama": "İnsanın dinlediği bir âyet, kıyâmetde kendine nûr olur"}, {"kisim": 3, "madde": 59, "metin": "Hadîs-i şerîfde, (Kur’ân-ı kerîm okuyunca, Allahü teâlânın rızâsını ve Cenneti isteyiniz! Dünyâlık istemeyiniz! Bir zemân gelir ki, hâfızlar, Kur’ân-ı kerîmi, insanlara yaklaşmak için vâsıta yaparlar)", "arama": "Kur’ân-ı kerîm okuyunca, Allahü teâlânın rızâsını ve Cenneti"}, {"kisim": 3, "madde": 59, "metin": ") (Tenbîh-ül-gâfilîn)deki hadîs-i şerîfde, (Kur’ân-ı kerîm okuyanın ana-babası kâfir olsalar bile, azâbları hafîfler)", "arama": "Kur’ân-ı kerîm okuyanın ana-babası kâfir olsalar bile, azâbl"}, {"kisim": 3, "madde": 59, "metin": "(Künûz-üd-dekâık)da yazılı, Taberânînin ve İbni Hibbânın bildirdikleri hadîs-i şerîfde, (Kur’ân-ı kerîmi hatm edenin düâsı kabûl olunur)", "arama": "Kur’ân-ı kerîmi hatm edenin düâsı kabûl olunur"}, {"kisim": 3, "madde": 59, "metin": "(Hazînet-ül-esrâr)daki hadîs-i şerîflerde, (Kur’ân-ı kerîmi hatm eden kimseye altmışbin melek hayr düâ eder) ve (Hatm düâsı yapılan yerde bulunan, ganîmet dağılırken bulunan kimse gibidir. Hatme başlanan yerde bulunan, cihâd eden kimse gibidir. İkisinde de bulunan, iki sevâba da kavuşur ve şeytânı rezîl eder)", "arama": "Hatm düâsı yapılan yerde bulunan, ganîmet dağılırken bulunan"}, {"kisim": 3, "madde": 59, "metin": "Sa’d ibni Ebî Vakkâs buyurdu ki, (Bir kimse, gündüz hatm okursa, melekler ona akşama kadar düâ eder. Gece okunursa, sabâha kadar düâ ederler)", "arama": "Bir kimse, gündüz hatm okursa, melekler ona akşama kadar düâ"}, {"kisim": 3, "madde": 59, "metin": "(Künûz-üd-dekâık)da yazılı, Deylemînin bildirdiği hadîs-i şerîfde, (Kur’ân-ı kerîmi tecvîde uygun okuyana şehîd sevâbı verilir)", "arama": "Kur’ân-ı kerîmi tecvîde uygun okuyana şehîd sevâbı verilir"}, {"kisim": 3, "madde": 59, "metin": "İmâm-ı Gazâlî diyor ki, hadîs-i şerîfde, (Üç mescidden başka mescidlere ziyâret için gidilmez)", "arama": "Üç mescidden başka mescidlere ziyâret için gidilmez"}, {"kisim": 3, "madde": 60, "metin": "[1316] da İstanbulda basılan bu tercemenin onsekizinci hadîs-i şerîfinde, (Bir işinizde şaşırırsanız ölmüşlerden yardım isteyiniz!)", "arama": "Bir işinizde şaşırırsanız ölmüşlerden yardım isteyiniz!"}, {"kisim": 3, "madde": 60, "metin": "Celâleddîn-i Rûmî “kuddise sirruh”, son hastalığında buyurdu ki, (Ben ölünce üzülmeyiniz! Her yerde benimle olunuz, beni düşününüz! İmdâdınıza yetişir, size yardım ederim. Rûhumun, bu dünyâda iki dürlü bağlılığı vardır: Biri, bedenime olan bağlılığı, ikincisi, sizlere olan bağlılığı. Allahü teâlânın inâyeti ile, ferd ve mücerred olunca, ya’nî rûhum bedenden ayrılınca, bedene olan bağlılığı da, size olur.)", "arama": "Ben ölünce üzülmeyiniz! Her yerde benimle olunuz, beni düşün"}, {"kisim": 3, "madde": 62, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki: (Ölünün mezârdaki hâli, imdâd diye bağıran, denize düşmüş kimseye benzer. Boğulmak üzere olan kimse, kendisini kurtaracak birini beklediği gibi, meyyit de, babasından, anasından, kardeşinden, arkadaşından gelecek bir düâyı gözler. Kendisine bir düâ gelince, dünyânın hepsi kendine verilmiş gibi sevinmekden dahâ çok sevinir. Allahü teâlâ, yaşıyanların düâları sebebi ile, ölülere dağlar gibi çok r", "arama": "Ölünün mezârdaki hâli, imdâd diye bağıran, denize düşmüş kim"}, {"kisim": 3, "madde": 62, "metin": "(Makâmât-ı Mazheriyye)de diyor ki: (Hadîs-i şerîfde, (Bir kimse, kendisi için veyâ başkası için yetmişbin aded Kelime-i tevhîd okursa, günâhları afv olur)", "arama": "Bir kimse, kendisi için veyâ başkası için yetmişbin aded Kel"}, {"kisim": 3, "madde": 63, "metin": "Hadîs-i şerîfde, (Bir kimse, başkası yerine oruc tutamaz ve nemâz kılamaz. Fekat, onun orucu ve nemâzı için fakîri doyurur)", "arama": "Bir kimse, başkası yerine oruc tutamaz ve nemâz kılamaz. Fek"}, {"kisim": 3, "madde": 67, "metin": "a “aleyhimürrıdvân” böyle yapılınca, bizler gibi günâhı çok olanlar, hesâba dâhil olur mu? Hadîs-i şerîfde buyuruldu ki, (Tâ’ûn, eski ümmetlere, azâb olarak gönderildi. Bu ümmet için şehîd olmağa sebebdir)", "arama": "Tâ’ûn, eski ümmetlere, azâb olarak gönderildi. Bu ümmet için"}, {"kisim": 3, "madde": 69, "metin": "[(Miftâh-un-necât) da yazılı hadîs-i şerîfde, (Bir kimse, mü’minler için, hergün yirmibeş kerre, istigfâr okursa, Allahü teâlâ, bu kimsenin kalbinden gıl ve hasedi çıkarır. İsmi, Ebdâl ismleri arasına yazılır. Ona, bütün mü’minler adedince, sevâb yazılır. Kıyâmet günü, bütün mü’minler: Yâ Rabbî, bu kulun bizim için, istigfâr okurdu. Sen de onu afv eyle! derler)", "arama": "Bir kimse, mü’minler için, hergün yirmibeş kerre, istigfâr o"}, {"kisim": 3, "madde": 70, "metin": "Bir hadîs-i şerîfde de, (Beşikden mezâra kadar ilm öğreniniz, çalışınız!)", "arama": "Beşikden mezâra kadar ilm öğreniniz, çalışınız!"}, {"kisim": 3, "madde": 70, "metin": "Bir hadîs-i şerîfde, (Bilerek yapılan az bir ibâdet, bilmiyerek yapılan çok ibâdetden dahâ iyidir!)", "arama": "Bilerek yapılan az bir ibâdet, bilmiyerek yapılan çok ibâdet"}, {"kisim": 3, "madde": 70, "metin": "Adâlete bakınız! Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (İyi huyları temâmlamak, iyi ahlâkı dünyâya yaymak için gönderildim)", "arama": "İyi huyları temâmlamak, iyi ahlâkı dünyâya yaymak için gönde"}, {"kisim": 3, "madde": 70, "metin": "Bir hadîs-i şerîfde, (Îmânı yüksek olanınız, ahlâkı güzel olanınızdır!)", "arama": "Îmânı yüksek olanınız, ahlâkı güzel olanınızdır!"}, {"kisim": 3, "madde": 70, "metin": "Alî Râmîtenî “kaddesallahü teâlâ sirrehül’azîz” hazretleri buyurdu ki, (Allah adamlarının kalbleri, Hakkın nazargâhıdır. O kalblere girmiş olanlara da, o nazardan nasîb erişir.)", "arama": "Allah adamlarının kalbleri, Hakkın nazargâhıdır. O kalblere "}, {"kisim": 3, "madde": 70, "metin": "Bir hadîs-i şerîfde, (Allahü teâlânın, kalbime akıtdığı, doldurduğu feyzlerin, nûrların hepsini Ebû Bekrin kalbine akıtdım!)", "arama": "Allahü teâlânın, kalbime akıtdığı, doldurduğu feyzlerin, nûr"}, {"kisim": 3, "madde": 70, "metin": "ci mektûbundaki hadîs-i şerîfde, (Vera’ sâhibi ile birlikde oturmak ibâdetdir)", "arama": "Vera’ sâhibi ile birlikde oturmak ibâdetdir"}, {"kisim": 3, "madde": 70, "metin": "i şerîflerden öğreneceğim) diyenler, hadîs-i şerîfleri yanlış anlıyarak, nefsin ve şeytânın tuzaklarına düşdükleri gibi, (Ben kalb bilgilerini doğruca Resûlullahın kalbinden alacağım)", "arama": "Ben kalb bilgilerini doğruca Resûlullahın kalbinden alacağım"}, {"kisim": 3, "madde": 70, "metin": "İşte bunun için, hadîs-i şerîfde, (Kur’ân-ı kerîmi kendi anladığına göre tefsîr eden kâfir olur)", "arama": "Kur’ân-ı kerîmi kendi anladığına göre tefsîr eden kâfir olur"}, {"kisim": 3, "madde": 70, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (İyi huyları temâmlamak, iyi ahlâkı dünyâya yaymak için gönderildim).", "arama": "(İyi huyları temâmlamak, iyi ahlâkı dünyâya yaymak için gönd"}]};
